-- Schema for Domain: invoice | Business: Agriculture | Version: v1_ecm
-- Generated on: 2026-05-01 16:23:38

-- ========= DATABASE =========
CREATE DATABASE IF NOT EXISTS `agriculture_ecm`.`invoice` COMMENT 'Single source of truth for all billing, invoicing, payments, and revenue recognition. Manages accounts receivable (AR), payment terms, credit management, financial settlements, and invoice lifecycle from generation to payment. Integrates with GL for revenue accounting per GAAP/IFRS standards. Supports agricultural-specific billing scenarios including commodity-based pricing, weight-ticket reconciliation, and seasonal payment terms.';

-- ========= TABLES =========
CREATE OR REPLACE TABLE `agriculture_ecm`.`invoice`.`invoice` (
    `invoice_id` BIGINT COMMENT 'Primary key for invoice',
    `bill_of_lading_id` BIGINT COMMENT 'Foreign key linking to supply.bill_of_lading. Business justification: In ag commodity trading, the BOL is the primary document triggering customer invoicing (title transfer proof). Direct FK from invoice to bill_of_lading supports BOL-based invoice generation, AP/AR thr',
    `billing_account_id` BIGINT COMMENT 'Reference to the billing account representing the customer financial relationship. Links to the billing_account product for credit terms, payment history, and AR aging.',
    `commodity_hedge_id` BIGINT COMMENT 'Foreign key linking to finance.commodity_hedge. Business justification: In agriculture, invoices for hedged commodity sales are linked to hedge instruments for ASC 815 hedge effectiveness testing and hedge accounting. Linking the invoice (hedged item) to the commodity_hed',
    `company_code_id` BIGINT COMMENT 'Foreign key linking to finance.company_code. Business justification: AR invoices are issued by a specific legal entity (company code). In multi-entity agriculture operations (cooperatives, grain elevators, subsidiaries), statutory financial reporting, intercompany elim',
    `journal_entry_id` BIGINT COMMENT 'Foreign key linking to finance.journal_entry. Business justification: AR invoice posting creates a journal entry (debit AR, credit revenue). In agriculture ERP systems, linking the invoice to its GL posting journal entry is required for AR-GL reconciliation, period clos',
    `payment_term_id` BIGINT COMMENT 'Foreign key linking to invoice.payment_term. Business justification: invoice.payment_terms_code is a denormalized string reference to the payment_term reference table. The invoice header must FK to the authoritative payment_term record to enforce due date calculation, ',
    `order_id` BIGINT COMMENT 'Reference to the originating sales order that triggered this invoice. Enables traceability from billing document back to the sales order in SAP SD or Oracle NetSuite.',
    `shipment_id` BIGINT COMMENT 'Foreign key linking to supply.shipment. Business justification: In ag commodity billing, AR invoices are generated upon shipment completion (BOL-triggered billing). Linking invoice to shipment supports shipment-based invoice generation, three-way matching (PO/ship',
    `billing_address` STRING COMMENT 'Full billing address of the customer as printed on the invoice document. Includes street, city, state, postal code, and country. Denormalized for invoice archival and legal document integrity.',
    `billing_period_end` DATE COMMENT 'End date of the service or delivery period covered by this invoice. Used with billing_period_start to define the performance obligation period for revenue recognition under GAAP ASC 606 / IFRS 15.',
    `billing_period_start` DATE COMMENT 'Start date of the service or delivery period covered by this invoice. Relevant for contract settlement invoices, advance billing, and service-based billing where revenue is recognized over a period per GAAP ASC 606.',
    `bol_number` STRING COMMENT 'Bill of Lading number associated with the shipment covered by this invoice. Required for freight billing reconciliation, export documentation, and FSMA supply chain traceability. Supports FOB and CIF shipping term invoicing.',
    `created_timestamp` TIMESTAMP COMMENT 'Timestamp when the invoice record was first created in the system. Used for audit trail, data lineage, and SOX financial reporting controls. Populated automatically at record insertion.',
    `currency_code` STRING COMMENT 'ISO 4217 three-letter currency code for the invoice transaction currency (e.g., USD, EUR, CAD). Supports multi-currency billing for international agricultural commodity sales and export transactions.. Valid values are `^[A-Z]{3}$`',
    `customer_name` STRING COMMENT 'Legal name of the customer (food manufacturer, distributor, cooperative, or agricultural buyer) as it appears on the invoice. Denormalized from the billing account for invoice document rendering and archival purposes.',
    `discount_amount` DECIMAL(18,2) COMMENT 'Total monetary discount applied to the invoice including trade discounts, volume rebates, early payment discounts, and cooperative patronage deductions. Reduces gross amount to arrive at net taxable amount.',
    `dispute_reason` STRING COMMENT 'Reason code for a customer-raised invoice dispute. Applicable when invoice_status is disputed. Agricultural-specific reasons include weight disputes (scale ticket discrepancies), quality claims (grade/moisture rejections), and price discrepancies against commodity contracts. [ENUM-REF-CANDIDATE: price_discrepancy|quantity_discrepancy|quality_claim|weight_dispute|duplicate_invoice|unauthorized_deduction|other — 7 candidates stripped; promote to reference product]',
    `due_date` DATE COMMENT 'Date by which full payment must be received per the agreed payment terms. Drives AR aging buckets (current, 30, 60, 90+ days), dunning processes, and late payment penalty calculations.',
    `dunning_date` DATE COMMENT 'Date on which the most recent dunning notice was sent to the customer for this overdue invoice. Used to schedule the next dunning run and track collections activity.',
    `dunning_level` STRING COMMENT 'Current dunning (collections escalation) level for overdue invoices. Ranges from 0 (not dunned) to 4 (final notice / collections). Drives automated payment reminder and collections workflows in SAP FI-AR.',
    `exchange_rate` DECIMAL(18,2) COMMENT 'Exchange rate applied to convert the transaction currency to the companys functional currency (USD) at the invoice date. Required for multi-currency consolidation and IFRS IAS 21 / GAAP ASC 830 foreign currency translation.',
    `gl_posting_date` DATE COMMENT 'Date on which the invoice was posted to the general ledger in the financial accounting system. Determines the accounting period for financial reporting. May differ from invoice_date for period-end accruals.',
    `gross_amount` DECIMAL(18,2) COMMENT 'Total pre-tax, pre-discount invoice amount in the transaction currency. Represents the sum of all line item extended prices before adjustments. Used as the base for tax calculation and discount application.',
    `intercompany_flag` BOOLEAN COMMENT 'Indicates whether this invoice represents a transaction between related legal entities (e.g., farm to elevator, elevator to processing plant, processing plant to distribution subsidiary). Intercompany invoices require elimination in consolidated financial statements per GAAP ASC 810 / IFRS 10.',
    `invoice_date` DATE COMMENT 'The principal business event date on which the invoice was formally issued to the customer. Used as the billing date for revenue recognition, aging calculations, and customer remittance matching. Corresponds to SAP FI posting date.',
    `invoice_number` STRING COMMENT 'Externally-visible, human-readable invoice number assigned at issuance. Used on printed billing documents, customer remittances, and payment references. Sourced from SAP FI-AR document number or Oracle NetSuite invoice number.. Valid values are `^[A-Z]{2,4}-[0-9]{6,12}$`',
    `invoice_status` STRING COMMENT 'Current lifecycle state of the invoice. Drives AR aging, cash application, and revenue recognition workflows. draft = not yet issued; issued = sent to customer; partially_paid = cash partially applied; paid = fully settled; void = cancelled; disputed = customer has raised a formal dispute.. Valid values are `draft|issued|partially_paid|paid|void|disputed`',
    `invoice_type` STRING COMMENT 'Classification of the billing document by business scenario. Determines pricing logic, tax treatment, and revenue recognition rules. [ENUM-REF-CANDIDATE: commodity_sale|service|weight_ticket_settlement|contract_settlement|advance_billing|intercompany_transfer|cooperative_patronage — promote to reference product]',
    `net_amount` DECIMAL(18,2) COMMENT 'Final total amount due from the customer after applying all discounts and adding taxes. Equals gross_amount minus discount_amount plus tax_amount. This is the amount the customer is obligated to pay.',
    `notes` STRING COMMENT 'Free-text field for additional billing instructions, special handling notes, commodity-specific remarks (e.g., grade, moisture content basis), or customer-specific billing requirements printed on the invoice document.',
    `paid_amount` DECIMAL(18,2) COMMENT 'Cumulative amount of cash payments applied to this invoice through payment_allocation records. Used to calculate the outstanding balance and determine if the invoice is partially or fully paid.',
    `po_number` STRING COMMENT 'Customer-provided purchase order number referenced on this invoice. Required for three-way matching (PO-GRN-Invoice) in the customers procurement system and for payment processing by food manufacturers and distributors.',
    `revenue_recognition_date` DATE COMMENT 'Date on which revenue from this invoice is recognized in the general ledger per GAAP ASC 606 / IFRS 15 five-step model. May differ from invoice_date for advance billing, contract settlements, or FOB destination shipments.',
    `shipping_terms` STRING COMMENT 'International commercial terms (Incoterms) defining the point of title transfer and risk allocation for the shipment. Determines revenue recognition timing under GAAP ASC 606 and affects freight cost allocation on the invoice.. Valid values are `FOB_ORIGIN|FOB_DESTINATION|CIF|EXW|DAP|FCA`',
    `source_system` STRING COMMENT 'Operational system of record from which this invoice record originated. Supports data lineage, reconciliation, and audit trail requirements across the multi-system agricultural enterprise landscape.. Valid values are `SAP_S4HANA|ORACLE_NETSUITE|GRANULAR|MANUAL`',
    `tax_amount` DECIMAL(18,2) COMMENT 'Total tax assessed on the invoice including sales tax, VAT, GST, and any applicable agricultural commodity taxes. Calculated per jurisdiction tax rules and reported for tax compliance.',
    `tax_exempt_certificate` STRING COMMENT 'Certificate number issued by the relevant tax authority confirming the customers tax-exempt status. Required for audit documentation when tax_exempt_flag is True. Supports IRS and state tax compliance.',
    `tax_exempt_flag` BOOLEAN COMMENT 'Indicates whether the customer or transaction is exempt from sales tax or VAT. Agricultural cooperatives, government entities, and certain commodity transactions may qualify for tax exemption. Drives tax calculation logic.',
    `updated_timestamp` TIMESTAMP COMMENT 'Timestamp of the most recent modification to the invoice record. Supports change data capture (CDC), audit trails, and SOX financial reporting controls.',
    `weight_ticket_number` STRING COMMENT 'Reference number of the certified scale weight ticket used to determine commodity quantity for billing. Critical for grain elevator, livestock, and bulk commodity invoicing where payment is based on certified weight. Supports USDA grain inspection compliance.',
    CONSTRAINT pk_invoice PRIMARY KEY(`invoice_id`)
) COMMENT 'Core accounts receivable invoice header representing the primary billing document issued to food manufacturers, distributors, cooperatives, and agricultural buyers. Captures invoice number, billing date, due date, total amount, tax, currency, payment terms, invoice status (draft/issued/partially_paid/paid/void/disputed), invoice type (commodity sale, service, weight-ticket settlement, contract settlement, advance billing, intercompany transfer, cooperative patronage), and source transaction references (sales order, delivery, contract). Serves as the SSOT for all outbound billing documents including intercompany transactions between farms, elevators, processing plants, and distribution subsidiaries. Links to invoice_line for item detail, payment_allocation for cash application, and billing_account for customer financial relationship.';

CREATE OR REPLACE TABLE `agriculture_ecm`.`invoice`.`line` (
    `line_id` BIGINT COMMENT 'Unique surrogate identifier for each invoice line item record in the Databricks Silver Layer. Primary key for the invoice_line data product.',
    `certificate_of_analysis_id` BIGINT COMMENT 'Foreign key linking to quality.certificate_of_analysis. Business justification: Grain commodity invoice lines are settled against a specific COA confirming grade, moisture, and MRL compliance. invoice_line.coa_reference is a denormalized text field; replacing it with a proper FK ',
    `commodity_id` BIGINT COMMENT 'Foreign key linking to product.commodity. Business justification: Invoice lines in ag operations must reference the exact commodity (corn, soybeans, wheat) for grade-based pricing, MRL compliance verification, and commodity-level revenue reporting. Agriculture domai',
    `price_basis_id` BIGINT COMMENT 'Foreign key linking to invoice.price_basis. Business justification: invoice_line.pricing_basis is a denormalized string reference to the price_basis reference table. Agricultural commodity invoice lines are priced using specific pricing bases (futures + basis, flat pr',
    `cost_center_id` BIGINT COMMENT 'Foreign key linking to finance.cost_center. Business justification: invoice.invoice_line carries a cost_center_code text field that is a denormalized reference to finance.cost_center. AR invoice lines must be allocated to cost centers for revenue accounting and P&L re',
    `field_id` BIGINT COMMENT 'Foreign key linking to land.field. Business justification: FSMA traceability, organic certification, and GMO segregation require field-of-origin on commodity invoice lines. Direct field_id on invoice_line supports field-level revenue reporting and regulatory ',
    `gl_account_id` BIGINT COMMENT 'Foreign key linking to finance.gl_account. Business justification: Invoice lines post to specific GL accounts (commodity revenue, storage income, handling fees). In agriculture, different commodity types and service lines post to different revenue GL accounts. gl_acc',
    `grading_standard_id` BIGINT COMMENT 'Foreign key linking to product.grading_standard. Business justification: Invoice lines in ag reference the USDA or other grading standard under which the commodity was priced and accepted. Linking to grading_standard_id supports grade-based price settlement audits, regulat',
    `invoice_id` BIGINT COMMENT 'Reference to the parent AR invoice header to which this line item belongs. Establishes the header-detail relationship per TRANSACTION_LINE role.',
    `irrigation_schedule_id` BIGINT COMMENT 'Foreign key linking to weather.irrigation_schedule. Business justification: Irrigation scheduling drives irrigation service invoicing — executed irrigation events are the direct basis for billing water volume, labor, and equipment on invoice lines. Linking irrigation_schedule',
    `material_master_id` BIGINT COMMENT 'Reference to the material master record representing the crop product, livestock, or service item billed on this line. Serves as the RESOURCE_REFERENCE per TRANSACTION_LINE role.',
    `variety_id` BIGINT COMMENT 'Foreign key linking to research.variety. Business justification: Seed and grain invoice lines reference the specific variety sold/purchased for variety-based pricing, IP royalty billing, and GMO/organic premium calculation. A seed company invoicing farmers must lin',
    `spray_window_id` BIGINT COMMENT 'Foreign key linking to weather.spray_window. Business justification: Custom application service providers bill per completed spray window — the spray_window record documents the weather-compliant conditions under which pesticide/fertilizer application occurred. Linking',
    `sustainability_certification_id` BIGINT COMMENT 'Foreign key linking to sustainability.sustainability_certification. Business justification: Invoice lines for certified organic/sustainable commodities must reference the governing certification to justify premium pricing, support FSMA traceability audits, and satisfy buyer verification requ',
    `basis_amount` DECIMAL(18,2) COMMENT 'The local cash price differential (basis) relative to the futures contract reference price, expressed in the invoice currency per UOM. Positive basis indicates premium over futures; negative indicates discount. Critical for agricultural commodity pricing reconciliation.',
    `bol_number` STRING COMMENT 'Bill of Lading number associated with the shipment of the commodity billed on this line. Provides logistics traceability and supports freight reconciliation and COOL (Country of Origin Labeling) compliance.',
    `contract_number` STRING COMMENT 'Reference to the underlying sales or forward contract (grain marketing contract, livestock purchase agreement, or service agreement) that governs the pricing and terms for this invoice line.',
    `created_timestamp` TIMESTAMP COMMENT 'Timestamp when this invoice line record was first created in the system, in ISO 8601 format (yyyy-MM-ddTHH:mm:ss.SSSXXX). Supports audit trail, SOX compliance, and data lineage tracking.',
    `currency_code` STRING COMMENT 'ISO 4217 three-letter currency code for all monetary amounts on this line (e.g., USD, EUR, CAD, BRL). Completes the MONETARY_TRIPLET currency dimension. Typically USD for domestic US agricultural transactions.. Valid values are `^[A-Z]{3}$`',
    `delivery_date` DATE COMMENT 'Date on which the commodity, livestock, or service was delivered or performed, establishing the revenue recognition trigger date per GAAP ASC 606 / IFRS 15 performance obligation satisfaction.',
    `discount_amount` DECIMAL(18,2) COMMENT 'Total discount or price reduction applied to this line item, expressed in the invoice currency. Includes trade discounts, volume rebates, quality deductions, and dockage adjustments for commodity grading deficiencies.',
    `dockage_pct` DECIMAL(18,2) COMMENT 'Percentage deduction applied to the billed quantity for foreign material, moisture excess, or quality deficiencies per USDA grain inspection standards. Drives quantity and price adjustments on the invoice line.',
    `futures_contract_ref` STRING COMMENT 'CME/CBOT futures contract month and symbol used as the pricing reference for this line when pricing_basis is futures or formula (e.g., ZC-DEC24 for December 2024 Corn futures). Null when pricing_basis is spot or contract.',
    `gross_amount` DECIMAL(18,2) COMMENT 'Gross billed amount for this line before discounts and adjustments, calculated as quantity × unit_price. Expressed in the invoice currency. Part of the MONETARY_TRIPLET for revenue recognition.',
    `is_gmo` BOOLEAN COMMENT 'Indicates whether the commodity billed on this line contains or is derived from genetically modified organisms (GMO). Required for labeling compliance under USDA National Bioengineered Food Disclosure Standard and export documentation.',
    `is_organic_certified` BOOLEAN COMMENT 'Indicates whether the commodity billed on this line is certified organic under the USDA National Organic Program (NOP). Affects pricing premiums, labeling requirements, and COA documentation.',
    `is_taxable` BOOLEAN COMMENT 'Indicates whether this invoice line item is subject to sales tax, VAT, or other applicable taxes. Drives tax calculation logic in SAP S/4HANA FI and Oracle NetSuite Tax modules.',
    `line_description` STRING COMMENT 'Human-readable description of the commodity, crop product, livestock, or service being billed on this line (e.g., Yellow Corn No. 2 - Harvest 2024, Feeder Cattle - 500-600 lb, Custom Application Service).',
    `line_number` STRING COMMENT 'Sequential position of this line item within the parent invoice. Used for ordering, display, and reconciliation of multi-line invoices. Satisfies LINE_SEQUENCE category.',
    `line_status` STRING COMMENT 'Current processing status of this invoice line item within the AR lifecycle. Drives workflow routing, dispute management, and revenue recognition timing. [ENUM-REF-CANDIDATE: open|billed|disputed|cancelled|credited|settled — promote to reference product if additional statuses are needed]. Valid values are `open|billed|disputed|cancelled|credited|settled`',
    `line_type` STRING COMMENT 'Classification of the invoice line item indicating whether it represents a commodity sale, livestock transaction, service charge, freight, storage, handling fee, penalty, or credit memo. Drives revenue recognition category assignment. [ENUM-REF-CANDIDATE: commodity|livestock|service|freight|storage|handling|penalty|credit_memo — promote to reference product]',
    `lot_number` STRING COMMENT 'Batch or lot number identifying the specific production lot of the commodity or product billed. Enables traceability from invoice line back to field harvest, processing batch, or animal group per FSMA and GLOBALG.A.P. requirements.',
    `moisture_pct` DECIMAL(18,2) COMMENT 'Moisture content percentage of the grain or commodity at time of delivery/billing. Used to calculate moisture dockage adjustments and shrinkage deductions applied to the billed quantity and price.',
    `net_amount` DECIMAL(18,2) COMMENT 'Net billed amount for this line after discounts and before tax, calculated as gross_amount minus discount_amount. Represents the taxable base for this line. Satisfies LINE_VALUE_OR_RESULT and MONETARY_TRIPLET categories.',
    `origin_country_code` STRING COMMENT 'ISO 3166-1 alpha-3 country code indicating the country of origin of the commodity billed, required for COOL (Country of Origin Labeling) compliance under USDA Agricultural Marketing Act.. Valid values are `^[A-Z]{3}$`',
    `purchase_order_number` STRING COMMENT 'Customers purchase order number referencing this invoice line. Required for three-way match (PO-GRN-Invoice) reconciliation in SAP S/4HANA MM and Oracle NetSuite procurement workflows.',
    `quantity` DECIMAL(18,2) COMMENT 'Quantity of the commodity, livestock, or service units billed on this line. Expressed in the unit of measure specified in uom. Satisfies LINE_QUANTITY category. For grain: bushels (BU); for livestock: head; for bulk commodities: metric tons (MT) or hundredweight (CWT).',
    `revenue_category` STRING COMMENT 'Revenue recognition category assigned to this line for GL posting and financial reporting under GAAP ASC 606 / IFRS 15. Drives the revenue account mapping in SAP S/4HANA CO module and Oracle NetSuite GL.. Valid values are `crop_sales|livestock_sales|service_revenue|storage_revenue|freight_revenue|other_revenue`',
    `tax_amount` DECIMAL(18,2) COMMENT 'Tax amount assessed on this line item (sales tax, VAT, excise tax, or agricultural levy), expressed in the invoice currency. Part of the MONETARY_TRIPLET adjustment component.',
    `test_weight` DECIMAL(18,2) COMMENT 'Test weight of the grain commodity in pounds per bushel (lb/BU) as measured at delivery. A key quality parameter affecting grade assignment and price adjustments for corn, soybeans, wheat, and other grains.',
    `unit_price` DECIMAL(18,2) COMMENT 'Price per unit of measure for this line item. Expressed in the invoice currency. May reflect spot market price, futures-based contract price, or negotiated contract price depending on pricing_basis.',
    `uom` STRING COMMENT 'Unit of measure for the billed quantity. Agricultural-standard units include BU (Bushel), CWT (Hundredweight), MT (Metric Ton), LB (Pound), KG (Kilogram), HEAD (livestock count), TON (short ton), GAL (gallon), L (liter), ACRE, EA (each for services). [ENUM-REF-CANDIDATE: BU|CWT|MT|LB|KG|HEAD|TON|GAL|L|ACRE|EA — 11 candidates stripped; promote to reference product]',
    `updated_timestamp` TIMESTAMP COMMENT 'Timestamp of the most recent modification to this invoice line record, in ISO 8601 format (yyyy-MM-ddTHH:mm:ss.SSSXXX). Supports change tracking, dispute resolution, and SOX audit requirements.',
    `weight_ticket_ref` STRING COMMENT 'Reference number of the scale/weight ticket used to verify the quantity of grain or bulk commodity billed on this line. Critical for weight-ticket reconciliation in agricultural commodity billing. Links to the physical scale ticket from the elevator or processing facility.',
    CONSTRAINT pk_line PRIMARY KEY(`line_id`)
) COMMENT 'Line-item detail for each AR invoice, representing individual commodity lots, crop products, livestock, or service charges billed. Captures line number, commodity code, crop/livestock description, quantity (BU, CWT, MT, head), unit of measure, unit price, pricing basis (spot, futures, contract), gross amount, discount, net amount, tax amount, GLN/lot reference, weight-ticket reference, and revenue recognition category. Supports commodity-based pricing and weight-ticket reconciliation per agricultural billing standards.';

CREATE OR REPLACE TABLE `agriculture_ecm`.`invoice`.`payment` (
    `payment_id` BIGINT COMMENT 'Unique system-generated surrogate identifier for each payment transaction record in the accounts receivable (AR) ledger.',
    `account_id` BIGINT COMMENT 'Reference to the paying customer (food manufacturer, cooperative, distributor, or agricultural buyer) who submitted this payment.',
    `bank_account_id` BIGINT COMMENT 'Foreign key linking to finance.bank_account. Business justification: Customer payments (grain settlement, cooperative payments) are deposited into specific company bank accounts. Cash management, bank reconciliation, and daily cash position reporting in agriculture req',
    `billing_account_id` BIGINT COMMENT 'Foreign key linking to invoice.billing_account. Business justification: Payments received from agricultural customers must be linked to the billing_account AR master for AR balance updates, last_payment_date/amount tracking, and avg_days_to_pay calculation. payment alread',
    `company_code_id` BIGINT COMMENT 'Foreign key linking to finance.company_code. Business justification: Payments are received by a specific legal entity. In multi-entity agriculture operations (multiple grain elevators, cooperative subsidiaries), cash receipts must be attributed to the correct legal ent',
    `contract_id` BIGINT COMMENT 'Reference to the underlying sales or commodity purchase contract linked to this payment, particularly relevant for advance payments, crop pre-purchase agreements, and seasonal payment programs.',
    `journal_entry_id` BIGINT COMMENT 'Foreign key linking to finance.journal_entry. Business justification: Cash receipt payments generate GL postings (debit bank/cash, credit AR). In agriculture AR operations, linking payment to its GL journal entry supports cash application reconciliation, period close AR',
    `invoice_id` BIGINT COMMENT 'Reference to the primary invoice against which this payment is applied. Supports invoice-to-payment reconciliation in accounts receivable (AR).',
    `payment_term_id` BIGINT COMMENT 'Foreign key linking to invoice.payment_term. Business justification: payment.payment_terms_code is a denormalized string reference to the payment_term reference table. Payments must reference the authoritative payment term to validate early payment discount eligibility',
    `advance_purpose` STRING COMMENT 'Specific business purpose for advance or prepayment transactions. Applicable only when payment_type is advance or deposit. Supports agricultural-specific advance payment programs including crop pre-purchase financing, seed and input supply advances, and grain storage deposits.. Valid values are `crop_prepurchase|seed_advance|input_supply_advance|storage_deposit|other`',
    `amount` DECIMAL(18,2) COMMENT 'Gross amount of the payment as submitted by the payer in the transaction currency. Represents the total funds received before any deductions, discounts, or adjustments are applied.',
    `applied_amount` DECIMAL(18,2) COMMENT 'Portion of the payment amount that has been successfully applied against one or more AR invoices. The difference between payment_amount and applied_amount yields the unapplied balance.',
    `bank_reference_number` STRING COMMENT 'Unique reference number assigned by the bank for the payment transaction (e.g., ACH trace number, wire confirmation number, check clearing reference). Used for bank reconciliation and payment tracing.',
    `channel` STRING COMMENT 'Interface or channel through which the payment was submitted. portal = customer self-service web portal; edi = EDI 820 electronic remittance; manual = manually entered by AR staff; bank_direct = bank-initiated lockbox or direct debit; mobile = mobile payment application.. Valid values are `portal|edi|manual|bank_direct|mobile`',
    `check_number` STRING COMMENT 'Paper check number when payment_method is check. Required for check reconciliation, stop-payment processing, and audit trail in agricultural cooperative and distributor payments.',
    `clearing_date` DATE COMMENT 'Date on which the payment was cleared against the AR invoice in the accounting system. Marks the completion of the cash application process and AR balance reduction.',
    `commodity_lot_reference` STRING COMMENT 'Lot number (LOT) or batch identifier of the agricultural commodity (grain, produce, livestock) associated with this payment. Enables traceability from payment back to specific commodity lot for FSMA compliance and quality reconciliation.',
    `cost_center_code` STRING COMMENT 'SAP cost center code associated with the payment for internal management accounting and profitability analysis by business unit or agricultural division.',
    `created_timestamp` TIMESTAMP COMMENT 'Timestamp when the payment record was first created in the system. Supports audit trail, data lineage, and SOX financial reporting controls.',
    `currency_code` STRING COMMENT 'ISO 4217 three-letter currency code for the payment transaction (e.g., USD, EUR, CAD). Supports multi-currency agricultural commodity sales and international trade settlements.. Valid values are `^[A-Z]{3}$`',
    `discount_taken_amount` DECIMAL(18,2) COMMENT 'Early payment discount amount deducted by the payer per agreed payment terms (e.g., 2/10 net 30). Recorded separately for cash discount accounting and terms compliance tracking.',
    `due_date` DATE COMMENT 'Date by which the payment was contractually due per the invoice payment terms. Used for early/late payment analysis, discount eligibility determination, and AR aging reporting.',
    `exchange_rate` DECIMAL(18,2) COMMENT 'Foreign currency exchange rate applied to convert the payment amount to the companys functional currency (USD) at the time of payment. Required for multi-currency AR reconciliation and IFRS 21 translation.',
    `functional_currency_amount` DECIMAL(18,2) COMMENT 'Payment amount converted to the companys functional currency (USD) using the exchange_rate at the time of payment. Used for consolidated financial reporting and GL posting.',
    `gl_account_code` STRING COMMENT 'General Ledger (GL) account code to which this payment is posted in the financial accounting system. Supports revenue recognition, AR clearing, and advance payment liability accounting per GAAP/IFRS.',
    `is_intercompany` BOOLEAN COMMENT 'Indicates whether this payment is an intercompany transaction between related legal entities within the agricultural enterprise group. Required for intercompany elimination in consolidated financial statements per GAAP/IFRS.',
    `is_partial_payment` BOOLEAN COMMENT 'Indicates whether this payment covers only a portion of the total invoice amount. True when applied_amount is less than the full invoice balance. Supports installment and partial payment tracking for agricultural seasonal payment programs.',
    `notes` STRING COMMENT 'Free-text notes or comments entered by AR staff regarding the payment, such as dispute context, special handling instructions, customer communication details, or reconciliation remarks.',
    `payer_bank_account` STRING COMMENT 'Masked or tokenized bank account identifier of the payer used for ACH, EFT, or wire payments. Stored in masked format for PCI compliance. Used for payment routing validation and fraud detection.',
    `payer_bank_routing_number` STRING COMMENT 'ABA routing transit number (9 digits) of the payers bank for ACH and wire payment processing. Used for payment routing validation and bank reconciliation.. Valid values are `^[0-9]{9}$`',
    `payment_date` DATE COMMENT 'The business event date on which the payment was received or initiated by the payer. Used for aging analysis, cash application, and revenue recognition timing per GAAP/IFRS.',
    `payment_method` STRING COMMENT 'Financial instrument or mechanism used to submit the payment. ACH = Automated Clearing House electronic transfer; wire = bank wire transfer; check = paper check; EFT = Electronic Funds Transfer; commodity_offset = payment settled via commodity credit or offset against grain/livestock delivery — common in agricultural cooperative and elevator transactions.. Valid values are `ACH|wire|check|EFT|commodity_offset`',
    `payment_number` STRING COMMENT 'Externally-known business identifier for the payment transaction, typically matching the payment document number in SAP S/4HANA FI or Oracle NetSuite. Used for cross-system reconciliation and customer remittance matching.',
    `payment_status` STRING COMMENT 'Current lifecycle state of the payment transaction. pending = received but not yet bank-confirmed; cleared = bank-confirmed and applied to AR; returned = rejected by bank (e.g., NSF check, ACH return); voided = cancelled before clearing; on_hold = suspended pending investigation or dispute resolution.. Valid values are `pending|cleared|returned|voided|on_hold`',
    `payment_type` STRING COMMENT 'Classification of the payment by its business purpose and timing relative to the invoice. standard = payment against an existing invoice; advance = prepayment before invoice issuance (crop pre-purchase, seed advance, input supply advance); deposit = security or storage deposit; installment = partial payment under a deferred or seasonal payment plan.. Valid values are `standard|advance|deposit|installment`',
    `profit_center_code` STRING COMMENT 'SAP profit center code for allocating payment revenue to the appropriate agricultural business segment (e.g., crop sales, livestock, inputs distribution) for segment reporting per IFRS 8.',
    `remittance_advice_number` STRING COMMENT 'Reference number from the payers remittance advice document accompanying the payment. Used to match payment to specific invoices and deductions in the cash application process.',
    `return_reason_code` STRING COMMENT 'Standardized bank return reason code when payment_status is returned (e.g., NACHA ACH return codes R01=Insufficient Funds, R02=Account Closed, R03=No Account). Required for returned payment processing and customer follow-up.',
    `sales_order_reference` STRING COMMENT 'Sales Order (SO) number from SAP S/4HANA SD or Oracle NetSuite linked to this payment. Enables end-to-end order-to-cash reconciliation for agricultural product sales.',
    `unapplied_amount` DECIMAL(18,2) COMMENT 'Remaining payment balance not yet applied to any invoice. Represents funds held in suspense or advance payment accounts pending invoice matching. Common in agricultural commodity sales with prepayment programs.',
    `updated_timestamp` TIMESTAMP COMMENT 'Timestamp of the most recent modification to the payment record. Supports change tracking, audit trail, and data lineage for SOX compliance and financial controls.',
    `value_date` DATE COMMENT 'The bank value date on which funds are credited to the companys account. May differ from payment_date for wire transfers and ACH batches. Critical for accurate cash position reporting and bank reconciliation.',
    `weight_ticket_reference` STRING COMMENT 'Reference to the grain or commodity weight ticket number used to reconcile payment amounts against actual delivered commodity weight. Specific to agricultural commodity billing where payment is based on scale-verified weight at elevator or processing facility.',
    CONSTRAINT pk_payment PRIMARY KEY(`payment_id`)
) COMMENT 'Records all inbound payment transactions applied against AR invoices from agricultural customers including food manufacturers, cooperatives, and distributors. Captures payment date, payment method (ACH, wire, check, EFT, commodity offset), payment amount, currency, bank reference, remittance advice number, payer account, applied invoice references, unapplied balance, payment type (standard, advance/prepayment, deposit, installment), payment purpose for advances (crop pre-purchase, seed advance, input supply advance, storage deposit), linked contract reference for advance payments, and payment status (pending/cleared/returned/voided). Supports seasonal payment terms, deferred payment arrangements, and advance payment programs common in agricultural commodity sales.';

CREATE OR REPLACE TABLE `agriculture_ecm`.`invoice`.`payment_allocation` (
    `payment_allocation_id` BIGINT COMMENT 'Unique system-generated identifier for each payment allocation record linking a payment to a specific invoice or invoice line. Serves as the primary key for this association entity.',
    `advance_payment_id` BIGINT COMMENT 'Foreign key linking to invoice.advance_payment. Business justification: payment_allocation is the association entity linking payments to invoices. When an advance payment is being applied against an invoice, the payment_allocation record should reference the originating a',
    `journal_entry_id` BIGINT COMMENT 'Foreign key linking to finance.journal_entry. Business justification: Payment allocations (clearing open AR items) generate GL clearing journal entries. In agriculture AR operations, matching payments to invoices triggers GL clearing postings. clearing_document_number i',
    `invoice_id` BIGINT COMMENT 'Reference to the invoice header being settled by this allocation. Supports multi-invoice settlement scenarios common in commodity contract billing and cooperative patronage distribution.',
    `line_id` BIGINT COMMENT 'Reference to a specific invoice line item being settled. Enables partial payment tracking at the line level, critical for weight-ticket reconciliation and commodity-based billing where individual line items may be settled independently.',
    `patronage_distribution_id` BIGINT COMMENT 'Reference to the cooperative patronage distribution record being applied through this allocation. Supports cooperative patronage dividend application against member invoices, a common agricultural billing workflow for grain cooperatives and farm supply cooperatives.',
    `payment_id` BIGINT COMMENT 'Reference to the payment record being allocated. Links the allocation to the source payment transaction in the accounts receivable (AR) ledger.',
    `allocated_amount` DECIMAL(18,2) COMMENT 'The gross monetary amount of the payment applied to this invoice or invoice line in the transaction currency. Core financial field for AR settlement, revenue recognition, and cash application reporting per GAAP/IFRS standards.',
    `allocation_date` DATE COMMENT 'The business date on which the payment was applied to the invoice. Used for aging analysis, cash application reporting, and Days Sales Outstanding (DSO) calculation. May differ from the payment receipt date in seasonal agricultural billing cycles.',
    `allocation_number` STRING COMMENT 'Externally visible business identifier for this payment allocation record, used in AR clearing documents, remittance advice matching, and audit trails. Corresponds to the SAP FI clearing document number or Oracle NetSuite application number.. Valid values are `^ALLOC-[0-9]{10}$`',
    `allocation_status` STRING COMMENT 'Current lifecycle state of the payment allocation: pending (awaiting posting), posted (applied to AR ledger), reversed (allocation reversed/cancelled), reconciled (matched and confirmed in bank reconciliation), disputed (under investigation for discrepancy). Drives AR aging and cash application workflows.. Valid values are `pending|posted|reversed|reconciled|disputed`',
    `allocation_type` STRING COMMENT 'Categorizes the nature of the payment application: full (complete invoice settlement), partial (portion of invoice settled), advance (prepayment applied against future invoice), credit_offset (credit memo applied), netting (offsetting payable against receivable), write_off (uncollectable balance cleared). [ENUM-REF-CANDIDATE: full|partial|advance|credit_offset|netting|write_off — promote to reference product]. Valid values are `full|partial|advance|credit_offset|netting|write_off`',
    `approved_by_user` STRING COMMENT 'The user ID or username of the finance manager or controller who approved this payment allocation, particularly for write-offs, large variance clearances, or deduction approvals. Supports segregation of duties and SOX internal control requirements.',
    `base_currency_amount` DECIMAL(18,2) COMMENT 'Allocated amount converted to the companys functional (base) currency for general ledger (GL) posting and financial reporting. Required for multi-currency operations in international agricultural commodity trading per IFRS 21.',
    `commodity_contract_number` STRING COMMENT 'Reference to the agricultural commodity purchase or sales contract against which this payment is being applied. Supports commodity contract payment matching for grain, livestock, and produce contracts. Links to forward contracts, basis contracts, and hedge-to-arrive (HTA) arrangements.',
    `cost_center_code` STRING COMMENT 'SAP Controlling (CO) cost center code associated with this payment allocation for internal management accounting and profitability analysis. Enables revenue attribution by farm unit, crop division, or livestock operation.',
    `created_by_user` STRING COMMENT 'The user ID or username of the AR specialist or system process that created this payment allocation record. Required for SOX internal controls, audit trail, and segregation of duties compliance in financial operations.',
    `created_timestamp` TIMESTAMP COMMENT 'The date and time when this payment allocation record was first created in the system. Used for audit trail, data lineage, and compliance reporting per SOX financial controls.',
    `currency_code` STRING COMMENT 'ISO 4217 three-letter currency code for the allocated amount (e.g., USD, EUR, CAD). Required for multi-currency agricultural commodity trading and international supply chain billing.. Valid values are `^[A-Z]{3}$`',
    `deduction_amount` DECIMAL(18,2) COMMENT 'Monetary value of deductions taken by the payer against the invoice, such as quality dockage, moisture penalties, freight charges, or promotional allowances. Distinct from discount_taken_amount as deductions are typically disputed or contractually defined adjustments in commodity billing.',
    `deduction_code` STRING COMMENT 'Code identifying the reason for any deduction taken by the payer against the invoice amount (e.g., quality deduction, moisture dockage, freight deduction, promotional allowance). Common in agricultural commodity billing where buyers deduct for grade, moisture, or foreign material.',
    `discount_due_date` DATE COMMENT 'The last date by which payment must be received to qualify for the early payment discount. Used to validate whether the early_payment_discount_amount was legitimately earned. Derived from invoice date and payment terms.',
    `discount_taken_amount` DECIMAL(18,2) COMMENT 'Monetary value of the trade or cash discount applied at the time of payment allocation. Represents the discount actually utilized by the payer, which may differ from the discount offered. Used in AR reconciliation and discount expense reporting.',
    `early_payment_discount_amount` DECIMAL(18,2) COMMENT 'Monetary value of the early payment discount earned by the payer for settling the invoice before the discount due date. Distinct from standard trade discounts; tied to payment terms such as 2/10 Net 30 common in agricultural supply chain billing.',
    `exchange_rate` DECIMAL(18,2) COMMENT 'Foreign currency exchange rate applied to convert the transaction currency amount to the base/functional currency at the time of allocation. Sourced from the ERP systems daily exchange rate table. Required for IFRS 21 and GAAP ASC 830 compliance.',
    `gl_account_code` STRING COMMENT 'The general ledger (GL) account code to which this payment allocation is posted for revenue recognition and AR clearing. Ensures proper accounting treatment per GAAP/IFRS chart of accounts. Sourced from SAP FI GL account determination or Oracle NetSuite account mapping.',
    `is_intercompany` BOOLEAN COMMENT 'Indicates whether this payment allocation is between entities within the same corporate group (intercompany transaction). Required for intercompany elimination in consolidated financial statements per GAAP ASC 810 and IFRS 10.',
    `last_updated_timestamp` TIMESTAMP COMMENT 'The date and time when this payment allocation record was most recently modified. Tracks changes to allocation status, amounts, or reconciliation state. Required for data lineage and SOX audit trail.',
    `netting_reference_number` STRING COMMENT 'Reference identifier for the intercompany or counterparty netting arrangement when allocation_type is netting. Used in agricultural supply chain scenarios where a company is both buyer and seller to the same counterparty (e.g., grain merchandiser netting payables against receivables).',
    `notes` STRING COMMENT 'Free-text notes or comments entered by the AR specialist regarding this payment allocation. May include details about partial payment agreements, dispute resolutions, weight-ticket discrepancies, or special handling instructions for seasonal payment arrangements.',
    `posting_date` DATE COMMENT 'The accounting period posting date for this allocation in the general ledger (GL). May differ from the allocation date when period-end adjustments are made. Determines the fiscal period for revenue recognition and AR aging per GAAP/IFRS.',
    `profit_center_code` STRING COMMENT 'SAP Controlling (CO) profit center code for segment reporting and profitability analysis by business unit (e.g., crop division, livestock division, agri-supply). Supports EBITDA reporting by agricultural business segment.',
    `reconciliation_status` STRING COMMENT 'Status of the bank reconciliation matching for this allocation: unreconciled (not yet matched to bank statement), matched (confirmed against bank statement), partially_matched (partial bank confirmation), exception (discrepancy requiring investigation), cleared (fully reconciled and closed). Essential for month-end close and cash management in agricultural operations.. Valid values are `unreconciled|matched|partially_matched|exception|cleared`',
    `reversal_date` DATE COMMENT 'The date on which this payment allocation was reversed. Populated only when allocation_status is reversed. Used for AR aging recalculation and audit trail documentation.',
    `reversal_reason` STRING COMMENT 'Business reason for reversing this payment allocation (e.g., returned check, bank rejection, incorrect application, duplicate payment). Populated only when allocation_status is reversed. Required for audit trail and AR dispute management.',
    `value_date` DATE COMMENT 'The bank value date on which funds were credited or debited, used for cash flow reporting and bank reconciliation. May differ from the posting date in agricultural cooperative payment cycles and commodity settlement workflows.',
    `variance_amount` DECIMAL(18,2) COMMENT 'Difference between the invoice amount and the payment allocated, representing unresolved discrepancies such as pricing disputes, weight-ticket measurement differences, or deduction claims. Positive value indicates underpayment; negative indicates overpayment. Critical for weight-ticket settlement reconciliation in grain and commodity billing.',
    `weight_ticket_number` STRING COMMENT 'Reference to the grain elevator or commodity scale weight ticket associated with this payment allocation. Critical for weight-ticket settlement reconciliation in grain, oilseed, and commodity billing workflows where payment is based on net weight delivered.',
    `write_off_amount` DECIMAL(18,2) COMMENT 'Monetary amount of the invoice balance written off as uncollectable or as an approved variance adjustment. Used in bad debt management, small balance write-offs, and weight-ticket variance clearance in commodity billing workflows.',
    CONSTRAINT pk_payment_allocation PRIMARY KEY(`payment_allocation_id`)
) COMMENT 'Association entity linking payments to specific invoices and invoice lines, enabling partial payment tracking, multi-invoice settlement, and split-payment reconciliation. Captures allocation date, allocated amount, discount taken, early payment discount, write-off amount, allocation type (full/partial/advance/credit_offset/netting), reconciliation status, and variance amount. Critical for weight-ticket settlement reconciliation, commodity contract payment matching, and cooperative patronage distribution application in agricultural billing workflows.';

CREATE OR REPLACE TABLE `agriculture_ecm`.`invoice`.`credit_memo` (
    `credit_memo_id` BIGINT COMMENT 'Unique system-generated identifier for the credit memo record. Primary key for the credit_memo data product in the invoice domain.',
    `account_id` BIGINT COMMENT 'Identifier of the agricultural customer (buyer, distributor, food manufacturer, or retailer) to whom the credit memo is issued. Links to the customer master for AR management.',
    `billing_account_id` BIGINT COMMENT 'Foreign key linking to invoice.billing_account. Business justification: Credit memos reduce AR balances for agricultural customers and must be linked to the billing_account AR master for proper AR aging updates, credit limit recalculation, and account-level credit memo tr',
    `certificate_of_analysis_id` BIGINT COMMENT 'Foreign key linking to quality.certificate_of_analysis. Business justification: Credit memos in grain/produce trading are issued when COA results confirm quality shortfall (moisture variance, grade downgrade, pesticide residue). credit_memo.coa_reference is a denormalized text fi',
    `commodity_lot_id` BIGINT COMMENT 'Reference to the specific commodity lot (LOT) associated with the credit memo. Enables traceability for quality-based credits such as MRL non-compliance deductions, grading disputes, or post-harvest quality adjustments back to the originating harvest batch.',
    `company_code_id` BIGINT COMMENT 'Foreign key linking to finance.company_code. Business justification: Credit memos are issued by a specific legal entity. In multi-entity agriculture operations, credit memo reporting by legal entity is required for statutory financial statements, intercompany eliminati',
    `frost_alert_id` BIGINT COMMENT 'Foreign key linking to weather.frost_alert. Business justification: Frost events causing crop loss trigger credit memos for undelivered or damaged commodity under forward contracts. Ag billing teams issue credit memos citing the specific frost alert as the triggering ',
    `journal_entry_id` BIGINT COMMENT 'Foreign key linking to finance.journal_entry. Business justification: Credit memos for quality deductions, moisture dockage, and grade adjustments in agriculture generate GL reversals/adjustments. Linking credit_memo to its journal entry supports audit trail, period clo',
    `inventory_goods_receipt_id` BIGINT COMMENT 'Foreign key linking to inventory.goods_receipt. Business justification: Quality rejection credit processing: credit memos in grain agriculture are issued for short deliveries, quality rejections, or contamination identified at goods receipt. Direct FK enables traceability',
    `invoice_id` BIGINT COMMENT 'Reference to the original invoice against which this credit memo is issued. Enables traceability from credit memo back to the source billing document for AR reconciliation.',
    `lot_trace_id` BIGINT COMMENT 'Foreign key linking to supply.lot_trace. Business justification: Ag credit memos for quality rejections, MRL exceedances, or grade disputes must reference the specific lot for FSMA-compliant credit processing and recall management. Linking credit_memo to lot_trace ',
    `nonconformance_id` BIGINT COMMENT 'Foreign key linking to quality.nonconformance. Business justification: Credit memos in agriculture are issued when nonconformances result in rejected shipments, MRL exceedances, or disposition decisions (destroy/return). A FK from credit_memo to nonconformance_id enables',
    `payment_term_id` BIGINT COMMENT 'Foreign key linking to invoice.payment_term. Business justification: credit_memo.payment_terms_code is a denormalized string reference to the payment_term reference table. Credit memos may have specific application terms (e.g., must be applied within X days). Normalizi',
    `precipitation_event_id` BIGINT COMMENT 'Foreign key linking to weather.precipitation_event. Business justification: Hail and storm events causing crop damage trigger credit memos for quality downgrades or delivery shortfalls under commodity contracts. Linking precipitation_event to credit_memo provides the weather-',
    `recall_event_id` BIGINT COMMENT 'Foreign key linking to compliance.recall_event. Business justification: Recall-driven credit issuance: in agriculture, credit memos are the primary financial instrument issued when a recall event requires customer reimbursement for recalled/destroyed product. Regulators a',
    `shipment_id` BIGINT COMMENT 'Foreign key linking to supply.shipment. Business justification: Credit memos in ag are issued for short shipments, rejected loads, or damaged deliveries — all tied to a specific shipment. Linking credit_memo to shipment supports shipment-level credit reconciliatio',
    `sustainability_certification_id` BIGINT COMMENT 'Foreign key linking to sustainability.sustainability_certification. Business justification: Credit memos issued for certification non-compliance (e.g., organic decertification, failed audit) must reference the certification that triggered the regulatory deduction. Required for is_regulatory_',
    `weight_ticket_id` BIGINT COMMENT 'Foreign key linking to invoice.weight_ticket. Business justification: credit_memo.weight_ticket_number is a denormalized string reference to the weight_ticket record. Credit memos in agricultural billing are frequently issued due to weight discrepancies or quality dispu',
    `application_date` DATE COMMENT 'The date on which the credit memo was applied against an open invoice, future order, or issued as a cash refund. Distinct from issue_date; used for AR aging, cash flow forecasting, and period-end close reconciliation.',
    `application_method` STRING COMMENT 'The method by which the credit memo is applied: invoice_offset (applied against a specific open invoice), future_order (applied as a discount on a future purchase order), cash_refund (refunded to the customer), account_credit (held as a standing credit on the customer account).. Valid values are `invoice_offset|future_order|cash_refund|account_credit`',
    `applied_amount` DECIMAL(18,2) COMMENT 'The portion of the net credit amount that has already been applied against open invoices or future orders. Enables tracking of partial credit utilization, particularly relevant for large agricultural commodity contracts with multiple delivery invoices.',
    `approval_date` DATE COMMENT 'The date on which the credit memo was formally approved by the authorized approver. Used for SOX compliance audit trails and to measure the credit memo processing cycle time from request to approval.',
    `approval_status` STRING COMMENT 'The internal approval workflow status of the credit memo. Credit memos above defined thresholds require multi-level authorization per SOX internal controls. States: pending (awaiting review), approved (authorized for issuance), rejected (denied), escalated (referred to senior management).. Valid values are `pending|approved|rejected|escalated`',
    `approved_by` STRING COMMENT 'Name or employee identifier of the person who authorized the credit memo issuance. Required for SOX audit trail and internal control documentation. Captures the approving manager or financial controller.',
    `commodity_grade` STRING COMMENT 'The USDA or industry-standard commodity grade assigned to the produce or grain at the time of the credit dispute (e.g., US No. 1, US No. 2, Choice, Select). Used to document grading disputes and price adjustment credits based on grade downgrade.',
    `cost_center_code` STRING COMMENT 'SAP cost center code associated with the credit memo for internal cost allocation and profitability analysis. Enables attribution of credit losses to specific farming operations, business units, or product lines for EBITDA and COGS reporting.',
    `created_timestamp` TIMESTAMP COMMENT 'The timestamp when the credit memo record was first created in the system. Provides the audit trail creation point for SOX compliance, data lineage, and financial period-end reconciliation in the Databricks Silver Layer.',
    `credit_amount` DECIMAL(18,2) COMMENT 'The gross credit amount before tax adjustments, representing the total value being reversed or reduced from the original invoice. Expressed in the transaction currency. Used for AR balance reduction and revenue recognition reversal.',
    `credit_memo_number` STRING COMMENT 'Externally-visible, human-readable business identifier for the credit memo document. Used in customer communications, AR aging reports, and audit trails. Follows the format CM-YYYY-NNNNNN.. Valid values are `^CM-[0-9]{4}-[0-9]{6}$`',
    `credit_reason_code` STRING COMMENT 'Standardized code identifying the business reason for issuing the credit memo. Agricultural-specific reasons include: PRICE_ADJ (price adjustment post-harvest), QUALITY_REJECT (quality rejection at delivery), WEIGHT_DISC (weight ticket discrepancy), PRODUCE_RETURN (return of produce), MRL_DEDUCTION (Maximum Residue Limit non-compliance deduction), GRADE_DISPUTE (commodity grading dispute). [ENUM-REF-CANDIDATE: PRICE_ADJ|QUALITY_REJECT|WEIGHT_DISC|PRODUCE_RETURN|MRL_DEDUCTION|GRADE_DISPUTE — promote to reference product]. Valid values are `PRICE_ADJ|QUALITY_REJECT|WEIGHT_DISC|PRODUCE_RETURN|MRL_DEDUCTION|GRADE_DISPUTE`',
    `credit_reason_description` STRING COMMENT 'Free-text narrative providing detailed explanation of the credit reason beyond the standardized code. Captures specifics such as lot numbers affected, field of origin, inspector findings, or commodity grade dispute details for audit and dispute resolution purposes.',
    `currency_code` STRING COMMENT 'ISO 4217 three-letter currency code for the credit memo transaction (e.g., USD, EUR, CAD). Supports multi-currency agricultural commodity trading and international supply chain settlements.. Valid values are `^[A-Z]{3}$`',
    `expiry_date` DATE COMMENT 'The date after which the credit memo can no longer be applied against open invoices or future orders. Supports seasonal agricultural payment terms where credits must be utilized within a crop cycle or fiscal period.',
    `fsma_traceable` BOOLEAN COMMENT 'Indicates whether the credit memo is associated with a FSMA-traceable commodity lot requiring full supply chain traceability documentation under the FSMA Food Traceability Rule (21 CFR Part 1, Subpart S). Triggers enhanced documentation requirements for food safety audits.',
    `gl_account_code` STRING COMMENT 'The General Ledger (GL) account code to which the credit memo reversal is posted. Ensures correct revenue recognition reversal and AR balance adjustment per GAAP/IFRS chart of accounts. Sourced from SAP S/4HANA FI-CO module.',
    `is_regulatory_deduction` BOOLEAN COMMENT 'Indicates whether the credit memo was triggered by a regulatory compliance deduction (True) such as MRL non-compliance, FSMA violation penalty, or EPA/USDA-mandated recall credit, versus a commercial dispute or voluntary adjustment (False). Supports regulatory reporting and compliance tracking.',
    `issue_date` DATE COMMENT 'The calendar date on which the credit memo was formally issued to the customer. This is the principal business event date used for revenue recognition reversal, AR aging, and period-end financial reporting under GAAP/IFRS.',
    `memo_status` STRING COMMENT 'Current lifecycle state of the credit memo. Tracks progression from draft creation through issuance, application against open invoices or future orders, and final closure or voiding. [ENUM-REF-CANDIDATE: draft|issued|applied|partially_applied|voided|expired — promote to reference product if additional states are needed]. Valid values are `draft|issued|applied|partially_applied|voided|expired`',
    `net_credit_amount` DECIMAL(18,2) COMMENT 'The total net credit amount inclusive of tax credit (credit_amount + tax_credit_amount). Represents the final value applied to the customers AR balance or refunded. Used for financial settlement and GL posting.',
    `notes` STRING COMMENT 'Free-text field for additional operational notes, internal comments, or customer communication details related to the credit memo. May capture dispute resolution outcomes, customer acknowledgment references, or special handling instructions for seasonal agricultural settlements.',
    `originating_invoice_number` STRING COMMENT 'The human-readable invoice number of the original billing document that this credit memo reverses or adjusts. Retained as a denormalized reference for audit trails, customer communications, and dispute resolution without requiring a join.',
    `price_adjustment_reason` STRING COMMENT 'Specific narrative for price-adjustment credits, capturing the market condition, contract clause, or WASDE-driven price revision that triggered the credit. Relevant for commodity-based pricing where spot market fluctuations or futures contract settlements require post-invoice price corrections.',
    `quantity_credited` DECIMAL(18,2) COMMENT 'The quantity of agricultural commodity or product being credited, expressed in the unit of measure applicable to the transaction (e.g., bushels, metric tons, hundredweight, cases). Supports weight-ticket reconciliation and partial return credits.',
    `remaining_credit_amount` DECIMAL(18,2) COMMENT 'The unapplied balance of the credit memo (net_credit_amount minus applied_amount). Represents the credit still available for application against future invoices or for cash refund. Critical for AR aging and customer statement accuracy.',
    `source_system` STRING COMMENT 'Identifies the operational system of record from which the credit memo originated: SAP_S4HANA (primary ERP), ORACLE_NETSUITE (secondary ERP), GRANULAR (Granular Farm Management for farm-level billing), MANUAL (manually entered credit). Supports data lineage and reconciliation in the Silver Layer.. Valid values are `SAP_S4HANA|ORACLE_NETSUITE|GRANULAR|MANUAL`',
    `tax_credit_amount` DECIMAL(18,2) COMMENT 'The tax component of the credit memo, representing the reversal of taxes originally charged on the invoiced amount. Includes applicable sales tax, VAT, or agricultural commodity tax credits as required by jurisdiction.',
    `unit_of_measure` STRING COMMENT 'The unit of measure for the quantity_credited field. Agricultural-specific units include BU (Bushel), MT (Metric Ton), CWT (Hundredweight), LB (Pound), KG (Kilogram), CS (Case), EA (Each), TON (Short Ton). Aligns with USDA commodity measurement standards. [ENUM-REF-CANDIDATE: BU|MT|CWT|LB|KG|CS|EA|TON — 8 candidates stripped; promote to reference product]',
    `unit_price_credited` DECIMAL(18,2) COMMENT 'The per-unit price used to calculate the credit amount (credit_amount = quantity_credited × unit_price_credited). Captures the price differential in price adjustment credits or the original invoice unit price for return and quality rejection credits.',
    `updated_timestamp` TIMESTAMP COMMENT 'The timestamp of the most recent modification to the credit memo record. Supports incremental data loading in the Databricks Silver Layer, change data capture (CDC), and audit trail maintenance for SOX compliance.',
    CONSTRAINT pk_credit_memo PRIMARY KEY(`credit_memo_id`)
) COMMENT 'Credit memo documents issued to agricultural customers to reverse or reduce previously billed amounts. Captures credit memo number, originating invoice reference, credit reason (price adjustment, quality rejection, weight discrepancy, return of produce, MRL non-compliance deduction, grading dispute), credit amount, tax credit, issue date, expiry date, and application status. Supports agricultural-specific credit scenarios including post-harvest quality adjustments and commodity grade disputes.';

CREATE OR REPLACE TABLE `agriculture_ecm`.`invoice`.`debit_memo` (
    `debit_memo_id` BIGINT COMMENT 'Unique system-generated surrogate key identifying each debit memo record in the invoice domain. Primary key for the debit_memo data product.',
    `account_id` BIGINT COMMENT 'Reference to the agricultural customer (grain elevator, food manufacturer, distributor, or retailer) to whom the debit memo is issued. Links to the customer master for AR management.',
    `billing_account_id` BIGINT COMMENT 'Foreign key linking to invoice.billing_account. Business justification: Debit memos increase AR balances for agricultural customers and must be linked to the billing_account AR master for proper AR aging updates and account-level debit memo tracking. debit_memo already ha',
    `commodity_id` BIGINT COMMENT 'Foreign key linking to product.commodity. Business justification: Debit memos in ag arise from quality disputes, grade adjustments, and pricing corrections — all commodity-specific. A commodity_id FK normalizes the denormalized commodity_code, supporting commodity-l',
    `commodity_lot_id` BIGINT COMMENT 'Foreign key linking to inventory.commodity_lot. Business justification: Storage and quality debit traceability: debit memos in grain elevators are issued for storage charges, shrinkage, or quality adjustments tied to specific commodity lots. Direct FK replaces denormalize',
    `company_code_id` BIGINT COMMENT 'Foreign key linking to finance.company_code. Business justification: Debit memos are issued by a specific legal entity. The sales_org_id(unlinked) is a sales org concept, not a company code. Multi-entity agriculture operations require debit memo attribution to legal en',
    `journal_entry_id` BIGINT COMMENT 'Foreign key linking to finance.journal_entry. Business justification: Debit memos for storage charges, drying fees, and handling deductions in agriculture generate GL postings. Linking debit_memo to its journal entry supports audit trail, period close reconciliation, an',
    `invoice_id` BIGINT COMMENT 'Reference to the original invoice against which this debit memo is raised to recover an underbilling or apply a post-settlement adjustment. Supports AR reconciliation and audit trail.',
    `payment_term_id` BIGINT COMMENT 'Foreign key linking to invoice.payment_term. Business justification: debit_memo.payment_terms_code is a denormalized string reference to the payment_term reference table. Debit memos issued to agricultural customers for additional charges must reference the authoritati',
    `sales_organization_id` BIGINT COMMENT 'Reference to the sales organization responsible for issuing the debit memo. Determines the legal entity, currency, and revenue recognition rules applicable to the adjustment.',
    `weight_ticket_id` BIGINT COMMENT 'Foreign key linking to invoice.weight_ticket. Business justification: debit_memo.weight_ticket_number is a denormalized string reference to the weight_ticket record. Debit memos in agricultural billing are frequently issued for additional charges tied to specific commod',
    `approval_date` DATE COMMENT 'Date on which the debit memo was formally approved by the authorized approver. Supports SOX audit trail and internal controls documentation.',
    `approved_by` STRING COMMENT 'Name or employee identifier of the finance or commercial manager who authorized the issuance of the debit memo. Required for SOX internal controls and segregation of duties compliance.',
    `bill_of_lading_number` STRING COMMENT 'Bill of lading document number associated with the shipment for which freight or logistics charges are being recovered via this debit memo. Supports FOB (Free On Board) and CIF (Cost Insurance and Freight) freight adjustment billing.',
    `cancellation_date` DATE COMMENT 'Date on which the debit memo was cancelled or reversed, if applicable. Populated only when memo_status is CANCELLED. Supports AR reversal processing and period-end close in SAP S/4HANA.',
    `cancellation_reason` STRING COMMENT 'Free-text explanation for the cancellation or reversal of the debit memo. Populated when memo_status is CANCELLED. Required for audit trail and SOX compliance.',
    `contract_number` STRING COMMENT 'Reference to the underlying sales or purchase contract number governing the original transaction. Supports contract-based price escalation clauses and post-settlement adjustment terms common in grain and commodity trading.',
    `cost_center_code` STRING COMMENT 'SAP cost center code associated with the business unit or operational division responsible for the debit memo. Supports internal cost allocation and EBITDA (Earnings Before Interest Taxes Depreciation and Amortization) reporting.',
    `created_timestamp` TIMESTAMP COMMENT 'System timestamp recording when the debit memo record was first created in the data platform. Supports audit trail, data lineage, and SOX financial reporting controls.',
    `currency_code` STRING COMMENT 'ISO 4217 three-letter currency code for the transaction currency of the debit memo (e.g., USD for US Dollar). Required for multi-currency operations and IFRS/GAAP foreign currency translation.. Valid values are `^[A-Z]{3}$`',
    `debit_amount` DECIMAL(18,2) COMMENT 'Gross base amount of the debit memo before tax, representing the underbilling recovery or post-settlement adjustment. Expressed in the transaction currency. Core monetary component for AR and revenue recognition.',
    `debit_memo_number` STRING COMMENT 'Externally visible, human-readable document number assigned to the debit memo at issuance. Used in customer correspondence, remittance advice, and accounts receivable (AR) reconciliation. Sourced from SAP S/4HANA FI document numbering.. Valid values are `^DM-[0-9]{4}-[0-9]{6}$`',
    `debit_reason_code` STRING COMMENT 'Standardized code classifying the business reason for issuing the debit memo. Supported reasons include: PRICE_ESC (price escalation), FREIGHT_ADJ (additional freight charges), STORAGE_FEE (storage fees), FUMIGATION (fumigation charges), QUALITY_PREM (quality premium adjustment), WT_TICKET_CORR (weight-ticket correction). Drives GL account determination and reporting in SAP S/4HANA.. Valid values are `PRICE_ESC|FREIGHT_ADJ|STORAGE_FEE|FUMIGATION|QUALITY_PREM|WT_TICKET_CORR`',
    `debit_reason_description` STRING COMMENT 'Free-text narrative explaining the specific business justification for the debit memo, supplementing the structured debit_reason_code. For example, details of a weight-ticket discrepancy or the basis for a quality premium adjustment per COA (Certificate of Analysis).',
    `dispute_reference` STRING COMMENT 'Reference number for any customer dispute or deduction claim raised against this debit memo. Populated when memo_status transitions to DISPUTED. Supports AR collections and dispute resolution workflow.',
    `due_date` DATE COMMENT 'Date by which the customer is required to remit payment for the debit memo amount, calculated from issue_date per the applicable payment terms. Used in AR aging and collections management.',
    `exchange_rate` DECIMAL(18,2) COMMENT 'Foreign currency exchange rate applied at the time of debit memo posting to convert the transaction currency to the company code currency. Relevant for international agricultural commodity trading operations.',
    `gl_account_code` STRING COMMENT 'General ledger account code to which the debit memo revenue or receivable adjustment is posted in SAP S/4HANA CO/FI. Determines the financial statement line for GAAP/IFRS revenue recognition and SOX audit trail.',
    `issue_date` DATE COMMENT 'Calendar date on which the debit memo was formally issued to the customer. Represents the principal business event date for revenue recognition and AR aging calculations.',
    `memo_status` STRING COMMENT 'Current lifecycle status of the debit memo document. DRAFT: created but not yet issued; ISSUED: sent to customer and open in AR; DISPUTED: customer has raised a dispute; PARTIALLY_PAID: partial payment received; PAID: fully settled; CANCELLED: voided prior to payment.. Valid values are `DRAFT|ISSUED|DISPUTED|PARTIALLY_PAID|PAID|CANCELLED`',
    `payment_method` STRING COMMENT 'Designated payment method for settlement of the debit memo. OFFSET indicates netting against a credit memo or open payable, common in grain elevator contra-account settlements.. Valid values are `ACH|WIRE|CHECK|EFT|OFFSET`',
    `posting_date` DATE COMMENT 'Date on which the debit memo is posted to the general ledger (GL) in SAP S/4HANA. May differ from issue_date when period-end adjustments are processed. Governs the fiscal period for revenue recognition.',
    `profit_center_code` STRING COMMENT 'SAP profit center code for segment-level profitability reporting. Enables attribution of debit memo revenue adjustments to specific agricultural business segments (e.g., grain trading, livestock, crop inputs).',
    `purchase_order_number` STRING COMMENT 'Customer purchase order number referenced on the debit memo for cross-referencing with the customers procurement system. Facilitates customer payment matching and dispute resolution.',
    `quantity` DECIMAL(18,2) COMMENT 'Physical quantity of commodity or product subject to the debit memo adjustment (e.g., bushels, metric tons, hundredweight). Used in conjunction with unit_of_measure for weight-ticket corrections and commodity-based pricing recalculations.',
    `source_system_code` STRING COMMENT 'Identifier of the operational system of record from which the debit memo originated. SAP_S4: SAP S/4HANA FI/SD; NETSUITE: Oracle NetSuite AR; GRANULAR: Granular Farm Management; MANUAL: manually entered adjustment. Supports data lineage and reconciliation in the Databricks Silver Layer.. Valid values are `SAP_S4|NETSUITE|GRANULAR|MANUAL`',
    `tax_amount` DECIMAL(18,2) COMMENT 'Tax component applied to the debit memo, calculated per applicable tax codes (e.g., sales tax, VAT). May be zero for exempt agricultural commodity transactions under USDA or state-level exemptions.',
    `tax_code` STRING COMMENT 'SAP tax condition code determining the applicable tax rate and jurisdiction for the debit memo. Governs whether agricultural commodity exemptions apply under state or federal tax regulations.',
    `total_amount` DECIMAL(18,2) COMMENT 'Net total amount of the debit memo inclusive of tax (debit_amount + tax_amount). Represents the total receivable to be collected from the customer. Used for AR balance updates and financial reporting.',
    `unit_of_measure` STRING COMMENT 'Unit of measure for the quantity field. BU (Bushel), MT (Metric Ton), CWT (Hundredweight), LB (Pound), KG (Kilogram), TON (Short Ton). Standard agricultural commodity measurement units per USDA and industry conventions.. Valid values are `BU|MT|CWT|LB|KG|TON`',
    `unit_price` DECIMAL(18,2) COMMENT 'Price per unit of measure applied in the debit memo calculation (e.g., price per bushel or per metric ton). Used for price escalation adjustments and commodity-based pricing reconciliation.',
    `updated_timestamp` TIMESTAMP COMMENT 'System timestamp recording the most recent modification to the debit memo record. Supports change data capture (CDC), audit trail, and SOX compliance for financial document integrity.',
    CONSTRAINT pk_debit_memo PRIMARY KEY(`debit_memo_id`)
) COMMENT 'Debit memo documents issued to agricultural customers to increase previously billed amounts or recover underbillings. Captures debit memo number, originating invoice reference, debit reason (price escalation, additional freight charges, storage fees, fumigation charges, quality premium adjustment, weight-ticket correction), debit amount, tax, issue date, and status. Supports post-settlement adjustments common in grain elevator and commodity trading billing.';

CREATE OR REPLACE TABLE `agriculture_ecm`.`invoice`.`weight_ticket` (
    `weight_ticket_id` BIGINT COMMENT 'Unique system-generated surrogate identifier for the weight ticket record in the Databricks Silver Layer. Primary key for this entity.',
    `asset_id` BIGINT COMMENT 'License plate number or fleet identifier of the truck or vehicle delivering the commodity. Used for tare weight lookup, driver verification, and logistics traceability per FSMA Traceability Rule.',
    `commodity_id` BIGINT COMMENT 'Foreign key linking to product.commodity. Business justification: Weight tickets at grain elevators are always commodity-specific — the commodity determines grading standards, moisture adjustment tables, and settlement price basis. A normalized commodity_id replaces',
    `commodity_lot_id` BIGINT COMMENT 'Foreign key linking to inventory.commodity_lot. Business justification: FSMA traceability and grain settlement: weight tickets are the source document for commodity lot creation at grain elevators. Direct FK enables lot-level settlement reporting, quality-to-payment trace',
    `employee_id` BIGINT COMMENT 'Certified scale operator license or employee ID of the individual who performed the weighing. Required for legal defensibility of certified weights under state weights-and-measures law and USDA FGIS standards.',
    `equipment_field_operation_id` BIGINT COMMENT 'Foreign key linking to equipment.field_operation. Business justification: Harvest field operations produce grain loads weighed at the elevator. Linking weight tickets to the originating harvest field operation enables farm-to-elevator traceability, yield reconciliation (GPS',
    `facility_id` BIGINT COMMENT 'Reference to the receiving facility, grain elevator, or livestock scale facility where the commodity was weighed. Links to the facility master for location, license, and operator certification details.',
    `farm_unit_id` BIGINT COMMENT 'Foreign key linking to land.farm_unit. Business justification: Weight tickets record grain deliveries from specific farm operations. Linking weight_ticket to farm_unit enables producer-level delivery aggregation for settlement statements, FSA reporting, crop insu',
    `field_id` BIGINT COMMENT 'Reference to the originating field or farm unit from which the commodity was harvested. Enables field-level yield reconciliation, COOL (Country of Origin Labeling) compliance, and precision agriculture analytics linking weight tickets to yield records.',
    `grading_standard_id` BIGINT COMMENT 'Foreign key linking to product.grading_standard. Business justification: Weight tickets record the USDA grade assigned at commodity intake — this grade directly determines price adjustments and settlement amounts. A grading_standard_id FK normalizes the denormalized usda_g',
    `inspection_id` BIGINT COMMENT 'Foreign key linking to quality.inspection. Business justification: Weight tickets in grain receiving are paired with USDA or third-party quality inspections. weight_ticket.inspection_certificate_number is a denormalized text field; a FK to inspection_id enables prope',
    `inspection_record_id` BIGINT COMMENT 'Foreign key linking to compliance.inspection_record. Business justification: Commodity receipt inspection and settlement: grain/commodity weight tickets in agriculture are issued alongside official inspection records that verify grade, moisture, and quality parameters used for',
    `inventory_goods_receipt_id` BIGINT COMMENT 'Foreign key linking to inventory.goods_receipt. Business justification: Grain settlement reconciliation: weight tickets are the scale document for commodity delivery; linking to goods_receipt enables FSMA lot traceability, GRN-to-ticket matching for AP settlement, and inv',
    `lot_trace_id` BIGINT COMMENT 'Foreign key linking to supply.lot_trace. Business justification: FSMA requires lot-level traceability from field to scale to invoice. Linking weight_ticket to lot_trace connects the physical weighing event to the traceable lot record, enabling lot-level settlement ',
    `variety_id` BIGINT COMMENT 'Foreign key linking to research.variety. Business justification: Identity-preserved grain receiving requires variety tracking on weight tickets — non-GMO, organic, or IP-protected varieties must be segregated and documented at point of delivery. Weight ticket → var',
    `shipment_id` BIGINT COMMENT 'Foreign key linking to supply.shipment. Business justification: In ag grain operations, weight tickets are generated for inbound truck deliveries that correspond to shipment records. Linking weight_ticket to shipment supports shipment-to-settlement reconciliation,',
    `trailer_asset_id` BIGINT COMMENT 'License plate number or fleet identifier of the trailer carrying the commodity. Separate from truck ID as trailers may be interchanged. Used for tare weight lookup and load traceability.. Valid values are `^[A-Z0-9-]{2,20}$`',
    `trial_id` BIGINT COMMENT 'Foreign key linking to research.trial. Business justification: Research trial harvests generate commercial weight tickets when foundation seed or trial grain is sold or transferred. Linking weight_ticket to trial enables research harvest settlement, trial cost ac',
    `broken_kernels_pct` DECIMAL(18,2) COMMENT 'Percentage of broken corn kernels and foreign material (BCFM) in a corn sample, as defined by USDA FGIS grading standards. A key grade factor for corn that drives price discounts and grade assignment.',
    `commodity_type` STRING COMMENT 'Broad classification of the commodity category. Drives applicable grading standards, inspection protocols, and settlement calculation rules (e.g., grain uses bushel-based pricing; livestock uses CWT-based pricing).. Valid values are `grain|oilseed|cotton|livestock|other`',
    `created_timestamp` TIMESTAMP COMMENT 'Timestamp when the weight ticket record was first created in the source system (SAP S/4HANA MM or Granular Farm Management). Used for audit trail and data lineage. Format: yyyy-MM-ddTHH:mm:ss.SSSXXX.',
    `currency_code` STRING COMMENT 'Three-letter ISO 4217 currency code for the settlement amount (e.g., USD for US Dollar). Required for multi-currency operations and IFRS financial reporting.. Valid values are `^[A-Z]{3}$`',
    `damage_pct` DECIMAL(18,2) COMMENT 'Percentage of grain kernels that are heat-damaged, mold-damaged, sprouted, or otherwise damaged as determined by USDA FGIS inspection. A primary grade factor affecting commodity grade assignment and price discounts.',
    `dockage_pct` DECIMAL(18,2) COMMENT 'Percentage of the gross sample weight consisting of material other than the grain (weed seeds, chaff, straw, sand) that passes through a prescribed sieve. Deducted from net weight before pricing per USDA FGIS grading standards.',
    `driver_name` STRING COMMENT 'Full name of the truck driver delivering the commodity. Required for chain-of-custody documentation, FSMA traceability, and facility access records.',
    `foreign_material_pct` DECIMAL(18,2) COMMENT 'Percentage of the grain sample consisting of foreign material (non-grain matter that does not pass through the dockage sieve). A grade-determining factor per USDA FGIS standards that affects commodity grade and price discounts.',
    `gross_weight_kg` DECIMAL(18,2) COMMENT 'Total certified scale weight of the loaded vehicle (truck/trailer plus commodity) in kilograms as recorded on the certified scale. Foundational quantity for net weight calculation per state weights-and-measures law.',
    `is_gmo` BOOLEAN COMMENT 'Indicates whether the commodity delivered on this weight ticket is derived from genetically modified organisms (GMO). Required for identity preservation programs, non-GMO certification, and international trade compliance (EU GMO labeling regulations).',
    `is_organic` BOOLEAN COMMENT 'Indicates whether the commodity is certified organic under the USDA National Organic Program (NOP). Drives premium pricing, segregated storage requirements, and organic certificate documentation requirements.',
    `is_split_load` BOOLEAN COMMENT 'Indicates whether this weight ticket represents a split-load delivery where a single truck carries commodity from multiple fields, farms, or ownership lots. When True, multiple weight tickets may share the same truck/trailer ID and require proportional allocation.',
    `moisture_pct` DECIMAL(18,2) COMMENT 'Moisture content of the grain or oilseed sample expressed as a percentage of total weight, measured at time of delivery. Used to calculate moisture dockage/shrink adjustments to net weight and price per USDA FGIS grading standards. Null for livestock.',
    `net_weight_bu` DECIMAL(18,2) COMMENT 'Net commodity weight converted to bushels (BU) using USDA standard test weight per bushel for the specific commodity (e.g., 56 lbs/bu for corn, 60 lbs/bu for wheat). Used for grain pricing, settlement, and WASDE reporting. Null for livestock and cotton.',
    `net_weight_kg` DECIMAL(18,2) COMMENT 'Certified net commodity weight in kilograms, calculated as gross weight minus tare weight. This is the authoritative quantity used for invoice line reconciliation, settlement calculations, and USDA FGIS reporting. Stored as a certified value from the scale system.',
    `notes` STRING COMMENT 'Free-text field for scale operator or receiving clerk notes regarding special conditions, quality observations, load discrepancies, or dispute details associated with this weight ticket. Supports exception handling and dispute resolution.',
    `price_per_unit` DECIMAL(18,2) COMMENT 'Contracted or market price per unit of measure (per bushel for grain, per CWT for livestock, per pound for cotton) applied to this weight ticket for settlement calculation. Sourced from the applicable sales order or commodity contract.',
    `price_unit_of_measure` STRING COMMENT 'Unit of measure to which the price per unit applies. BU = Bushel (grain); CWT = Hundredweight (livestock); MT = Metric Ton; LB = Pound (cotton); KG = Kilogram. Drives settlement amount calculation.. Valid values are `BU|CWT|MT|LB|KG|TON`',
    `purchase_order_number` STRING COMMENT 'Purchase Order (PO) number from SAP S/4HANA MM or Oracle NetSuite against which this commodity delivery is being received. Enables three-way match (PO/GRN/Invoice) for AP processing and GAAP accrual accounting.. Valid values are `^[A-Z0-9-]{4,20}$`',
    `scale_datetime` TIMESTAMP COMMENT 'The certified date and time the commodity was weighed on the certified scale. This is the principal business event timestamp and the authoritative quantity determination moment per state weights-and-measures law. Format: yyyy-MM-ddTHH:mm:ss.SSSXXX.',
    `settlement_amount` DECIMAL(18,2) COMMENT 'Gross settlement amount payable to the vendor/grower for this weight ticket, calculated as adjusted net weight multiplied by price per unit before deductions. Represents the principal monetary value of this transaction for AR/AP reconciliation.',
    `tare_weight_kg` DECIMAL(18,2) COMMENT 'Certified scale weight of the empty vehicle (truck/trailer without commodity) in kilograms. Subtracted from gross weight to determine net commodity weight. May be captured on inbound or outbound weigh.',
    `test_weight_lbs_per_bu` DECIMAL(18,2) COMMENT 'Measured weight per bushel of the grain sample in pounds per bushel (lbs/bu), indicating grain density and quality. Used as a grade factor per USDA FGIS standards (e.g., minimum 56 lbs/bu for No. 2 Yellow Corn). Null for non-grain commodities.',
    `ticket_number` STRING COMMENT 'Externally-known, human-readable certified scale ticket number assigned by the elevator or receiving facility. Used for reconciliation against invoice lines, grain settlement documents, and USDA FGIS inspection records. Unique within a facility.. Valid values are `^[A-Z0-9-]{4,20}$`',
    `ticket_status` STRING COMMENT 'Current lifecycle state of the weight ticket. draft = captured but not yet certified; open = certified and awaiting settlement; settled = reconciled to an invoice line and payment; voided = cancelled/corrected; disputed = under quality or quantity dispute.. Valid values are `draft|open|settled|voided|disputed`',
    `updated_timestamp` TIMESTAMP COMMENT 'Timestamp of the most recent modification to the weight ticket record. Tracks corrections, grade adjustments, or settlement status changes. Format: yyyy-MM-ddTHH:mm:ss.SSSXXX.',
    CONSTRAINT pk_weight_ticket PRIMARY KEY(`weight_ticket_id`)
) COMMENT 'Certified scale weight records for commodity deliveries (grain, oilseed, cotton, livestock) serving as the authoritative quantity source for invoice line reconciliation. Captures ticket number, scale date/time, commodity type, gross weight, tare weight, net weight, moisture content, test weight, dockage percentage, grade factor adjustments (broken kernels, foreign material, damage), scale operator certification, facility/elevator location, truck/trailer ID, driver, and settlement status. Must reconcile to invoice lines per USDA FGIS grain inspection standards and state weights-and-measures regulations. Supports split-load tickets and multi-commodity loads.';

CREATE OR REPLACE TABLE `agriculture_ecm`.`invoice`.`billing_account` (
    `billing_account_id` BIGINT COMMENT 'Primary key for billing_account',
    `account_id` BIGINT COMMENT 'Reference to the master customer entity in the CRM or ERP customer master. Links the AR billing account to the corresponding buyer record in Salesforce CRM or SAP SD customer master.',
    `billing_customer_account_id` BIGINT COMMENT 'FK to customer.account',
    `company_code_id` BIGINT COMMENT 'Foreign key linking to finance.company_code. Business justification: Billing accounts (AR accounts) are maintained by a specific legal entity. In multi-entity agriculture operations, AR aging reports by legal entity, credit limit management by entity, and statutory AR ',
    `employee_id` BIGINT COMMENT 'Reference to the internal employee or sales representative responsible for managing this AR billing account relationship. Used for collections escalation routing and customer relationship management in Salesforce CRM.',
    `payment_term_id` BIGINT COMMENT 'Foreign key linking to invoice.payment_term. Business justification: billing_account.payment_terms_code is a denormalized string reference to the payment_term reference table. The billing account master should FK to the authoritative payment_term record to enforce cons',
    `account_close_date` DATE COMMENT 'Date on which the AR billing account was closed or deactivated. Null for active accounts. Used for account lifecycle reporting and historical AR analysis.',
    `account_open_date` DATE COMMENT 'Date on which the AR billing account was formally opened and activated in the AR subledger. Represents the effective start of the financial relationship between the agricultural enterprise and the buyer.',
    `account_status` STRING COMMENT 'Current lifecycle status of the AR billing account. active indicates normal billing operations; on_hold indicates credit hold applied; pending_review indicates credit review in progress; closed indicates account terminated.. Valid values are `active|inactive|on_hold|closed|pending_review`',
    `account_type` STRING COMMENT 'Classification of the billing account by customer category relevant to agricultural commerce. Drives applicable payment terms, tax treatment, and regulatory reporting (e.g., COOL, USDA export documentation).. Valid values are `domestic|export|intercompany|cooperative|government`',
    `aging_1_30_amount` DECIMAL(18,2) COMMENT 'Outstanding AR balance for invoices 1 to 30 days past due, expressed in the account currency. Used in AR aging reports for collections prioritization and expected credit loss provisioning.',
    `aging_31_60_amount` DECIMAL(18,2) COMMENT 'Outstanding AR balance for invoices 31 to 60 days past due, expressed in the account currency. Elevated aging in this bucket may trigger credit review or collection escalation for agricultural buyers.',
    `aging_61_90_amount` DECIMAL(18,2) COMMENT 'Outstanding AR balance for invoices 61 to 90 days past due, expressed in the account currency. Accounts in this bucket are typically escalated to senior credit management and may trigger collateral enforcement actions.',
    `aging_91_120_amount` DECIMAL(18,2) COMMENT 'Outstanding AR balance for invoices 91 to 120 days past due, expressed in the account currency. Balances in this bucket are typically subject to formal demand letters and potential write-off evaluation.',
    `aging_current_amount` DECIMAL(18,2) COMMENT 'Outstanding AR balance for invoices not yet past due (within current payment terms), expressed in the account currency. Part of the standard AR aging bucket analysis used for cash flow forecasting and credit management.',
    `aging_over_120_amount` DECIMAL(18,2) COMMENT 'Outstanding AR balance for invoices more than 120 days past due, expressed in the account currency. Represents the highest-risk aging bucket; balances here are evaluated for bad debt write-off per GAAP ASC 310 and IFRS 9 ECL provisioning.',
    `ar_account_number` STRING COMMENT 'Externally-known alphanumeric AR account number assigned to the billing customer in the SAP FI-AR subledger or Oracle NetSuite AR module. Used on invoices, statements, and remittance advice for buyer identification.. Valid values are `^AR-[A-Z0-9]{6,12}$`',
    `avg_days_to_pay` DECIMAL(18,2) COMMENT 'Rolling average number of days from invoice date to payment receipt for this AR account, calculated over the trailing 12-month period. Key KPI for credit risk assessment and payment behavior benchmarking in agricultural commodity sales.',
    `bank_account_ref` STRING COMMENT 'Masked or tokenized reference to the customers bank account used for ACH or wire transfer payments. Full account details are stored in the payment vault; this field holds only the last 4 digits or a token for reconciliation purposes.',
    `billing_address_line1` STRING COMMENT 'Primary street address line for the billing customers invoicing address. Used on invoice documents, statements, and regulatory filings including USDA and FDA traceability records.',
    `billing_city` STRING COMMENT 'City of the billing customers invoicing address. Required for invoice generation, tax jurisdiction determination, and COOL (Country of Origin Labeling) compliance reporting.',
    `billing_country_code` STRING COMMENT 'ISO 3166-1 alpha-3 country code for the billing customers invoicing address (e.g., USA, CAN, BRA). Drives export documentation requirements, COOL labeling, and applicable tax/VAT treatment for international agricultural trade.. Valid values are `^[A-Z]{3}$`',
    `billing_postal_code` STRING COMMENT 'Postal or ZIP code of the billing customers invoicing address. Used for tax rate determination, geographic sales analysis, and invoice document generation.',
    `billing_state_province` STRING COMMENT 'State or province of the billing customers invoicing address. Used for tax jurisdiction determination, state-level agricultural regulatory reporting, and USDA program eligibility.',
    `collateral_type` STRING COMMENT 'Type of collateral securing the AR account credit exposure. Agricultural-specific collateral types include crop liens (UCC Article 9 security interest in standing or harvested crops) and equipment liens. Drives credit limit and risk classification decisions.. Valid values are `crop_lien|equipment_lien|letter_of_credit|surety_bond|none`',
    `collateral_value` DECIMAL(18,2) COMMENT 'Appraised or estimated monetary value of the collateral securing the AR account, expressed in the account currency. Used in credit exposure calculations and expected credit loss (ECL) modeling per IFRS 9.',
    `created_timestamp` TIMESTAMP COMMENT 'Timestamp when this AR billing account record was first created in the data platform (Silver Layer). Supports audit trail, data lineage, and SOX internal control requirements.',
    `credit_hold_flag` BOOLEAN COMMENT 'Indicates whether this AR account is currently under a credit hold, blocking new sales orders from being processed. When True, SAP SD order creation is blocked pending credit resolution.',
    `credit_hold_reason` STRING COMMENT 'Reason code explaining why the AR account is placed on credit hold. Supports credit management workflow and audit trail for SOX compliance. collateral_expired is specific to agricultural crop lien or letter of credit expiry.. Valid values are `overdue_balance|credit_limit_exceeded|disputed_invoices|collateral_expired|financial_review|manual_hold`',
    `credit_limit_amount` DECIMAL(18,2) COMMENT 'Maximum outstanding AR balance authorized for this billing account, expressed in the account currency. Enforced during sales order creation in SAP SD credit management. Reviewed periodically based on crop cycle seasonality and buyer financial health.',
    `credit_review_date` DATE COMMENT 'Scheduled or last-completed date for periodic credit review of this AR account. Agricultural accounts are typically reviewed annually or after significant crop season events, commodity price swings, or weather-related losses.',
    `credit_risk_category` STRING COMMENT 'Internal credit risk classification assigned to the billing account based on financial analysis, payment history, and market conditions. watch indicates accounts under heightened monitoring due to commodity price volatility or crop failure risk.. Valid values are `low|medium|high|watch`',
    `credit_score` STRING COMMENT 'Numeric credit score assigned to the billing account based on payment history, financial statements, and agricultural market exposure. Used to determine credit limit and payment terms. Typically sourced from internal scoring model or third-party credit bureau.',
    `currency_code` STRING COMMENT 'ISO 4217 three-letter currency code for the AR account (e.g., USD, EUR, BRL). All monetary amounts on this account are denominated in this currency. Supports multi-currency agricultural export transactions.. Valid values are `^[A-Z]{3}$`',
    `current_balance` DECIMAL(18,2) COMMENT 'Total outstanding accounts receivable balance for this billing account as of the last subledger posting date, expressed in the account currency. Represents the sum of all open invoice amounts net of payments and credit memos.',
    `dispute_balance` DECIMAL(18,2) COMMENT 'Total outstanding AR balance currently under formal dispute by the customer, expressed in the account currency. Disputed amounts are excluded from collections activity and tracked separately per GAAP revenue recognition guidance. Common in agricultural weight-ticket reconciliation disputes.',
    `gl_reconciliation_account` STRING COMMENT 'SAP GL reconciliation account number to which this AR subledger account posts. Ensures the AR subledger balance reconciles to the GL trade receivables account per GAAP ASC 310 and SOX internal controls.. Valid values are `^[0-9]{6,10}$`',
    `last_payment_amount` DECIMAL(18,2) COMMENT 'Monetary amount of the most recent payment received and posted against this AR account, in the account currency. Supports cash application reconciliation and payment pattern analysis.',
    `last_payment_date` DATE COMMENT 'Date of the most recent payment received and posted against this AR account. Used in collections analysis, average days to pay calculation, and credit risk monitoring.',
    `payment_method` STRING COMMENT 'Preferred or contracted payment method for this AR account. commodity_offset is an agricultural-specific method where payment is settled via commodity delivery or grain bank offset rather than cash.. Valid values are `ach|wire_transfer|check|credit_card|commodity_offset`',
    `seasonal_terms_flag` BOOLEAN COMMENT 'Indicates whether this AR account is subject to seasonal payment terms aligned to agricultural harvest cycles (e.g., deferred payment until post-harvest). When True, standard payment terms are overridden by the seasonal schedule defined in the payment terms code.',
    `tax_id_number` STRING COMMENT 'Federal or state tax identification number (EIN, TIN, or VAT number) for the billing customer entity. Required for 1099 reporting, USDA program payments, and international trade documentation.',
    `updated_timestamp` TIMESTAMP COMMENT 'Timestamp when this AR billing account record was last modified in the data platform. Used for incremental data pipeline processing, change data capture, and audit trail maintenance.',
    CONSTRAINT pk_billing_account PRIMARY KEY(`billing_account_id`)
) COMMENT 'Accounts receivable account master for each billing customer entity, representing the financial relationship between the agricultural enterprise and its buyers. Captures AR account number, customer reference, credit limit amount, credit risk category (low/medium/high/watch), credit scoring basis, collateral type (crop lien, equipment lien, letter of credit, surety bond), collateral value, credit review date, credit hold status, credit hold reason, current balance, aging buckets (current/30/60/90/120+ days), payment terms code, currency, last payment date, average days to pay, dispute balance, and account manager. Integrates with SAP FI-AR subledger and Oracle NetSuite AR module.';

CREATE OR REPLACE TABLE `agriculture_ecm`.`invoice`.`payment_term` (
    `payment_term_id` BIGINT COMMENT 'Unique surrogate identifier for each payment term configuration record in the agricultural billing reference master.',
    `applicable_commodity_types` STRING COMMENT 'Comma-separated list of commodity categories to which this payment term is applicable (e.g., grain,oilseed, livestock, produce, all). Supports commodity-specific settlement schedules such as deferred grain payment programs and livestock settlement windows. Null indicates applicability to all commodity types.',
    `applicable_company_code` STRING COMMENT 'SAP S/4HANA company code(s) for which this payment term is valid. Comma-separated if applicable to multiple company codes. Null indicates applicability across all company codes. Supports multi-entity agricultural enterprise structures.',
    `applicable_customer_segment` STRING COMMENT 'Customer segment classification for which this payment term is designed. Allows differentiated term offerings for growers, cooperatives, distributors, and processors within the agricultural supply chain. [ENUM-REF-CANDIDATE: all|grower|cooperative|distributor|processor|retailer|export — promote to reference product]',
    `applicable_sales_org` STRING COMMENT 'SAP S/4HANA sales organization code(s) for which this payment term is valid. Comma-separated if applicable to multiple sales organizations. Null indicates global applicability across all sales organizations.',
    `approved_by` STRING COMMENT 'Name or employee identifier of the finance or credit manager who approved this payment term configuration for use. Supports SOX internal controls over financial reporting and segregation of duties requirements.',
    `approved_date` DATE COMMENT 'Date on which this payment term configuration was formally approved by the authorized finance or credit manager. Supports SOX audit trail and change management documentation.',
    `baseline_date_type` STRING COMMENT 'Defines the reference date from which net due days and discount days are calculated. Agricultural-specific options include weight_ticket_date (grain elevator settlements) and harvest_completion_date (post-harvest deferred programs). Maps to SAP S/4HANA payment term baseline date configuration.. Valid values are `invoice_date|posting_date|delivery_date|goods_receipt_date|weight_ticket_date|harvest_completion_date`',
    `created_timestamp` TIMESTAMP COMMENT 'Timestamp when this payment term configuration record was first created in the system, in ISO 8601 format with timezone offset (yyyy-MM-ddTHH:mm:ss.SSSXXX). Supports audit trail and data lineage requirements.',
    `credit_limit_required` DECIMAL(18,2) COMMENT 'Minimum approved credit limit (in functional currency) that a customer must hold to be eligible for this payment term. Supports credit risk management for extended or deferred agricultural payment programs. Null if no minimum credit limit is required.',
    `currency_code` STRING COMMENT 'ISO 4217 three-letter currency code in which this payment terms monetary thresholds and discount calculations are denominated (e.g., USD, EUR, CAD). Supports multi-currency agricultural export transactions.. Valid values are `^[A-Z]{3}$`',
    `deferral_max_days` STRING COMMENT 'Maximum number of calendar days that payment may be deferred from the invoice date under a seasonal deferral program, regardless of when the trigger event occurs. Caps the deferral window to manage credit exposure. Null when is_seasonal_deferral is false.',
    `deferral_trigger_event` STRING COMMENT 'The business event that triggers the start of the payment window for seasonally deferred terms. For example, harvest_completion starts the net due days clock after crop harvest is recorded. Null when is_seasonal_deferral is false.. Valid values are `harvest_completion|crop_sale|livestock_sale|weight_ticket_settlement|fixed_calendar_date|growing_season_end`',
    `discount_days_1` STRING COMMENT 'Number of days from the baseline date within which payment must be received to qualify for the first-tier early payment discount percentage. Corresponds to SAP S/4HANA ZBD1T field. Null if no early payment discount applies.',
    `discount_days_2` STRING COMMENT 'Number of days from the baseline date within which payment must be received to qualify for the second-tier early payment discount. Corresponds to SAP S/4HANA ZBD2T field. Null if no second discount tier applies.',
    `discount_percent_1` DECIMAL(18,2) COMMENT 'Percentage discount applied to the invoice amount if payment is received within discount_days_1. Expressed as a decimal (e.g., 0.0200 = 2%). Corresponds to SAP S/4HANA ZBD1P field. Null if no early payment discount applies.',
    `discount_percent_2` DECIMAL(18,2) COMMENT 'Percentage discount applied to the invoice amount if payment is received within discount_days_2 but after discount_days_1. Corresponds to SAP S/4HANA ZBD2P field. Null if no second discount tier applies.',
    `dunning_procedure_code` STRING COMMENT 'SAP S/4HANA dunning procedure code assigned to this payment term, controlling the escalation schedule for overdue AR notices. Seasonal agricultural terms may use specialized dunning procedures that account for harvest timing before escalating collection actions.. Valid values are `^[A-Z0-9]{1,10}$`',
    `effective_date` DATE COMMENT 'Date from which this payment term configuration becomes valid and may be applied to new invoices, sales orders, or purchase orders. Supports seasonal term activation aligned with crop or livestock cycles.',
    `erp_term_key` STRING COMMENT 'Native payment term key as stored in the source ERP system (SAP S/4HANA ZTERM field, Oracle NetSuite term ID). Enables traceability and reconciliation between the lakehouse silver layer and the operational system of record.. Valid values are `^[A-Z0-9]{1,4}$`',
    `expiration_date` DATE COMMENT 'Date after which this payment term configuration is no longer valid for assignment to new transactions. Null indicates an open-ended term with no planned expiration. Supports seasonal program sunset dates.',
    `fsma_compliant` BOOLEAN COMMENT 'Indicates whether this payment term configuration has been reviewed and confirmed compliant with FSMA supplier payment provisions, particularly for produce safety rule supplier agreements and preventive controls.',
    `gl_account_code` STRING COMMENT 'Default General Ledger account code associated with revenue or AR postings under this payment term. Used for automated GL determination in SAP S/4HANA FI/CO integration. Supports revenue recognition per GAAP/IFRS.. Valid values are `^[A-Z0-9]{4,10}$`',
    `installment_count` STRING COMMENT 'Total number of installment payments required under this term when is_installment is true. For example, 3 for a three-payment seasonal schedule. Null when is_installment is false.',
    `installment_schedule_type` STRING COMMENT 'Defines how installment amounts are distributed across the payment schedule. harvest_triggered supports agricultural deferred programs where installment timing is tied to crop harvest completion events. Null when is_installment is false.. Valid values are `equal|percentage_split|milestone_based|harvest_triggered`',
    `is_installment` BOOLEAN COMMENT 'Indicates whether this payment term requires payment in multiple installments rather than a single lump sum. When true, installment_count and installment_schedule_type define the installment structure. Common for large agricultural equipment purchases and seasonal input financing.',
    `is_seasonal_deferral` BOOLEAN COMMENT 'Indicates whether this payment term includes a seasonal deferral provision, allowing payment to be deferred to a post-harvest or post-season window. Characteristic of agricultural deferred grain payment programs and spring input financing.',
    `late_payment_grace_days` STRING COMMENT 'Number of calendar days beyond the due date before late payment penalties begin to accrue. Provides a grace window before penalty charges are triggered. Null if no grace period applies.',
    `late_payment_penalty_percent` DECIMAL(18,2) COMMENT 'Annual percentage rate applied to overdue invoice balances as a late payment penalty or interest charge. Expressed as a decimal (e.g., 0.0150 = 1.5% per annum). Null if no late payment penalty applies under this term.',
    `net_due_days` STRING COMMENT 'Number of calendar days from the invoice date (or baseline date) by which full payment is due. For example, 30 for Net 30 terms. Core field in SAP S/4HANA payment term configuration (ZBD3T). Drives AR due date calculation.',
    `netsuite_term_code` STRING COMMENT 'Payment term identifier as defined in Oracle NetSuite GL/AR module. Populated when the term originates from or is synchronized with NetSuite. Supports dual-ERP environments where SAP S/4HANA and Oracle NetSuite coexist.',
    `payment_method_restriction` STRING COMMENT 'Restricts the allowable payment methods under this term. For example, large grain settlement programs may require ACH or wire transfer only. none indicates no restriction. Maps to SAP S/4HANA payment method configuration.. Valid values are `none|ach_only|check_only|wire_only|ach_or_wire|ach_or_check`',
    `price_fixation_required` BOOLEAN COMMENT 'Indicates whether the commodity price must be fixed (priced) before the payment due date clock starts. Relevant for deferred pricing grain contracts (basis contracts, hedge-to-arrive) where the final invoice amount is not determined at delivery.',
    `term_code` STRING COMMENT 'Externally-known alphanumeric code uniquely identifying the payment term configuration, as defined in SAP S/4HANA FI/SD module (e.g., NET30, DEFGRAIN90, LSTK45). Used on invoices, sales orders, and purchase orders for term lookup.. Valid values are `^[A-Z0-9_-]{2,20}$`',
    `term_description` STRING COMMENT 'Detailed narrative description of the payment term, including applicable conditions, seasonal rules, commodity restrictions, and any special settlement provisions relevant to agricultural billing scenarios.',
    `term_name` STRING COMMENT 'Human-readable name of the payment term configuration (e.g., Net 30 Days, Deferred Grain Payment 90 Days Post-Harvest, Livestock Settlement 14 Days). Displayed on customer-facing documents and AR aging reports.',
    `term_status` STRING COMMENT 'Current lifecycle status of the payment term configuration. Inactive or deprecated terms are retained for historical invoice reference but cannot be assigned to new transactions.. Valid values are `active|inactive|draft|deprecated`',
    `term_type` STRING COMMENT 'Classification of the payment term by its structural type. Supports agricultural-specific types including deferred seasonal programs (post-harvest grain payment windows), commodity-price-based settlement, and livestock consignment settlement. [ENUM-REF-CANDIDATE: standard_net|early_payment_discount|deferred_seasonal|installment|consignment_settlement|commodity_price_based|prepayment — promote to reference product]',
    `updated_timestamp` TIMESTAMP COMMENT 'Timestamp of the most recent modification to this payment term configuration record, in ISO 8601 format with timezone offset (yyyy-MM-ddTHH:mm:ss.SSSXXX). Supports change tracking and audit compliance.',
    `weight_ticket_reconciliation_required` BOOLEAN COMMENT 'Indicates whether payment under this term requires reconciliation against a weight ticket (scale ticket) before the invoice due date is triggered. Critical for grain elevator and commodity settlement billing scenarios where final payment amount depends on certified weight.',
    CONSTRAINT pk_payment_term PRIMARY KEY(`payment_term_id`)
) COMMENT 'Reference master defining payment term configurations applicable to agricultural billing including standard net terms, seasonal deferred payment programs, and commodity-specific settlement schedules. Captures term code, term description, net days, discount days, early payment discount percentage, seasonal deferral rules (e.g., post-harvest payment windows), installment schedule flag, installment count, and applicable commodity types. Supports agricultural-specific terms such as deferred grain payment programs and livestock settlement windows.';

CREATE OR REPLACE TABLE `agriculture_ecm`.`invoice`.`dispute` (
    `dispute_id` BIGINT COMMENT 'Primary key for dispute',
    `account_id` BIGINT COMMENT 'Reference to the agricultural customer (buyer, distributor, food manufacturer, or retailer) who raised the dispute against the invoice.',
    `billing_account_id` BIGINT COMMENT 'Foreign key linking to invoice.billing_account. Business justification: Disputes are raised against invoices by agricultural customers and must be linked to the billing_account AR master for dispute balance tracking (billing_account.dispute_balance field). dispute already',
    `certificate_of_analysis_id` BIGINT COMMENT 'Foreign key linking to quality.certificate_of_analysis. Business justification: Invoice disputes in commodity agriculture are frequently triggered by COA discrepancies (grade claimed vs invoiced, MRL exceedance). dispute.coa_reference is a denormalized text field; a FK to coa_id ',
    `commodity_id` BIGINT COMMENT 'Foreign key linking to product.commodity. Business justification: Disputes in ag operations frequently involve commodity-specific issues (MRL exceedances, grade disputes, quality rejections). A commodity_id FK enables commodity-level dispute analytics, supports FSMA',
    `commodity_lot_id` BIGINT COMMENT 'Foreign key linking to inventory.commodity_lot. Business justification: Quality and MRL dispute resolution: grain disputes (grade, moisture, MRL exceedance) are tied to specific commodity lots. Direct FK replaces denormalized commodity_lot_reference, enabling structured d',
    `company_code_id` BIGINT COMMENT 'Foreign key linking to finance.company_code. Business justification: Disputes are managed by a specific legal entity. In multi-entity agriculture operations, dispute reporting by legal entity supports credit risk management, collections performance reporting, and finan',
    `contract_id` BIGINT COMMENT 'Reference to the underlying sales or commodity purchase contract governing the disputed transaction, used for contract terms verification during dispute resolution.',
    `credit_memo_id` BIGINT COMMENT 'Foreign key linking to invoice.credit_memo. Business justification: dispute.credit_memo_number is a denormalized string reference to the credit_memo record. Disputes in agricultural billing are frequently resolved by issuing a credit memo. Normalizing to credit_memo_i',
    `employee_id` BIGINT COMMENT 'Reference to the internal employee or team responsible for investigating and resolving the dispute. Typically an AR specialist, commodity quality analyst, or compliance officer depending on dispute type.',
    `frost_alert_id` BIGINT COMMENT 'Foreign key linking to weather.frost_alert. Business justification: Invoice disputes in agriculture frequently arise from frost-related quality claims — buyers dispute grade or quantity citing frost damage. Linking frost_alert to dispute enables weather-event traceabi',
    `grading_standard_id` BIGINT COMMENT 'Foreign key linking to product.grading_standard. Business justification: Ag disputes frequently center on which grading standard was applied and whether grade_claimed vs grade_invoiced differ. A grading_standard_id FK provides the formal standard reference for dispute reso',
    `inspection_finding_id` BIGINT COMMENT 'Foreign key linking to quality.inspection_finding. Business justification: Invoice disputes in commodity agriculture are directly triggered by specific inspection findings (MRL exceedance, grade failure, foreign material). A FK from dispute to inspection_finding_id enables f',
    `inspection_record_id` BIGINT COMMENT 'Foreign key linking to compliance.inspection_record. Business justification: Quality inspection-driven invoice dispute resolution: agriculture invoice disputes for grade, moisture, or quality discrepancies are formally resolved by referencing the official inspection record. di',
    `inventory_goods_receipt_id` BIGINT COMMENT 'Foreign key linking to inventory.goods_receipt. Business justification: Dispute origination traceability: quality disputes in grain agriculture originate from quality determinations made at goods receipt. Direct FK enables dispute resolution teams to access original recei',
    `invoice_id` BIGINT COMMENT 'Reference to the parent invoice against which this dispute has been raised. Links to the invoice header record in the accounts receivable (AR) ledger.',
    `lot_trace_id` BIGINT COMMENT 'Foreign key linking to supply.lot_trace. Business justification: Ag invoice disputes most commonly arise from lot-level quality issues: grade disputes, moisture discrepancies, MRL exceedances, or organic certification failures. Linking dispute to lot_trace enables ',
    `nonconformance_id` BIGINT COMMENT 'Foreign key linking to quality.nonconformance. Business justification: Invoice disputes in export commodity markets are directly triggered by nonconformances (MRL exceedance, pesticide residue). dispute.mrl_exceedance_detail is a denormalized text field; a FK to nonconfo',
    `precipitation_event_id` BIGINT COMMENT 'Foreign key linking to weather.precipitation_event. Business justification: Hail and storm events causing commodity damage are a primary source of invoice disputes in agriculture. Buyers dispute invoice amounts citing weather-caused quality degradation. This link enables the ',
    `regulatory_finding_id` BIGINT COMMENT 'Foreign key linking to compliance.regulatory_finding. Business justification: Regulatory-finding-driven invoice dispute: dispute has is_regulatory_dispute flag and mrl_exceedance_detail, indicating disputes triggered by regulatory findings (MRL violations, pesticide residue fin',
    `variety_id` BIGINT COMMENT 'Foreign key linking to research.variety. Business justification: Variety performance disputes are a named business process in seed sales: customers dispute invoices when a variety fails to meet published yield, disease resistance, or trait performance benchmarks. L',
    `sustainability_certification_id` BIGINT COMMENT 'Foreign key linking to sustainability.sustainability_certification. Business justification: Invoice disputes involving certification-based pricing (e.g., buyer claims commodity was not certified as invoiced) require direct reference to the sustainability certification record. Dispute resolut',
    `cost_center_code` STRING COMMENT 'SAP S/4HANA CO cost center code associated with the business unit responsible for the disputed transaction. Used for internal cost allocation of dispute settlements and write-offs.',
    `created_timestamp` TIMESTAMP COMMENT 'The timestamp when the dispute record was first created in the system, in ISO 8601 format (yyyy-MM-ddTHH:mm:ss.SSSXXX). Serves as the audit trail creation marker for SOX compliance and data lineage.',
    `currency_code` STRING COMMENT 'ISO 4217 three-letter currency code for all monetary amounts on this dispute record (e.g., USD for US Dollar, EUR for Euro). Supports multi-currency agricultural commodity trading.. Valid values are `^[A-Z]{3}$`',
    `customer_claim_amount` DECIMAL(18,2) COMMENT 'The specific monetary amount the customer is claiming as a credit, refund, or price adjustment. May differ from the disputed_amount if the customer is requesting a specific settlement figure based on their own calculations (e.g., weight-ticket reconciliation or commodity grade re-pricing).',
    `days_to_resolve` STRING COMMENT 'Number of calendar days elapsed between dispute_date and resolution_date. Populated upon resolution. Used for KPI reporting on dispute resolution cycle time and SLA compliance tracking.',
    `dispute_date` DATE COMMENT 'The calendar date on which the customer formally raised the dispute. This is the principal business event date used for aging calculations, SLA tracking, and regulatory reporting timelines.',
    `dispute_description` STRING COMMENT 'Detailed free-text narrative provided by the customer or AR team describing the nature of the dispute, including specific claims, supporting evidence references, and any relevant field or delivery observations.',
    `dispute_number` STRING COMMENT 'Externally visible, human-readable unique identifier for the dispute, used in customer communications, USDA grain grading arbitration filings, and audit trails. Format: DSP-YYYY-NNNNNN.. Valid values are `^DSP-[0-9]{4}-[0-9]{6}$`',
    `dispute_status` STRING COMMENT 'Current lifecycle state of the dispute. open = newly filed; under_review = assigned and being investigated; resolved = final determination reached; escalated = elevated to senior arbitration or regulatory body; withdrawn = customer retracted the claim.. Valid values are `open|under_review|resolved|escalated|withdrawn`',
    `dispute_type` STRING COMMENT 'Classification of the reason for the dispute. Common agricultural billing dispute types include: price_discrepancy, weight_variance, quality_rejection, grade_dispute, mrl_exceedance_deduction, duplicate_billing, contract_terms_disagreement, short_shipment, packaging_defect. [ENUM-REF-CANDIDATE: price_discrepancy|weight_variance|quality_rejection|grade_dispute|mrl_exceedance_deduction|duplicate_billing|contract_terms_disagreement|short_shipment|packaging_defect — promote to reference product]',
    `disputed_amount` DECIMAL(18,2) COMMENT 'The portion of the invoice amount that the customer is formally contesting. May equal the full invoice amount (full dispute) or a subset (partial dispute) such as a weight variance deduction or MRL exceedance penalty.',
    `escalation_date` DATE COMMENT 'The date on which the most recent escalation action was taken. Null if the dispute has never been escalated. Used for escalation aging and regulatory timeline compliance.',
    `escalation_level` STRING COMMENT 'Numeric indicator of how many times the dispute has been escalated to a higher authority. Level 0 = not escalated; Level 1 = escalated to senior AR manager; Level 2 = escalated to legal/compliance; Level 3 = escalated to external arbitration (e.g., USDA GIPSA commodity arbitration).',
    `escalation_reason` STRING COMMENT 'Free-text description of the reason the dispute was escalated, such as failure to reach agreement within SLA, regulatory involvement required, or high-value commodity arbitration triggered.',
    `gl_account_code` STRING COMMENT 'The General Ledger (GL) account code to which the dispute settlement (credit memo or price adjustment) is posted in SAP S/4HANA FI. Ensures correct revenue recognition reversal or deduction accounting per GAAP/IFRS.',
    `invoice_amount` DECIMAL(18,2) COMMENT 'The total billed amount on the original invoice as issued to the customer, captured at the time of dispute initiation for reference and variance calculation.',
    `is_partial_dispute` BOOLEAN COMMENT 'Indicates whether the dispute covers only a portion of the invoice amount (True) or the full invoice amount (False). Drives AR aging treatment and partial payment clearing logic in SAP S/4HANA FI-AR.',
    `is_regulatory_dispute` BOOLEAN COMMENT 'Indicates whether the dispute involves a regulatory compliance dimension (e.g., FSMA traceability violation, EPA MRL exceedance, USDA grade certification challenge, COOL labeling dispute). Regulatory disputes trigger mandatory escalation and compliance reporting workflows.',
    `mrl_exceedance_detail` STRING COMMENT 'Description of the Maximum Residue Limit (MRL) exceedance that triggered a deduction or dispute, including the active ingredient (AI), detected level, and applicable MRL threshold per EPA or Codex Alimentarius standards. Populated only for mrl_exceedance_deduction dispute types.',
    `priority_level` STRING COMMENT 'Business priority assigned to the dispute, influencing reviewer assignment and resolution SLA targets. critical is typically reserved for disputes involving regulatory violations (e.g., MRL exceedance, FSMA non-compliance) or high-value commodity contracts.. Valid values are `low|medium|high|critical`',
    `resolution_date` DATE COMMENT 'The calendar date on which the dispute was formally closed and a resolution determination was recorded. Null if the dispute is still open or under review. Used for SLA compliance measurement and AR aging reports.',
    `resolution_notes` STRING COMMENT 'Free-text notes recorded by the assigned reviewer documenting the investigation findings, evidence reviewed (weight tickets, COA, grade certificates), and the rationale for the resolution determination.',
    `resolution_type` STRING COMMENT 'The method by which the dispute was resolved. credit_issued = credit memo applied to AR; price_adjusted = invoice repriced per commodity grade or weight; claim_denied = dispute rejected after review; partial_settlement = negotiated partial credit; replacement_shipment = goods replaced; contract_amended = contract terms updated.. Valid values are `credit_issued|price_adjusted|claim_denied|partial_settlement|replacement_shipment|contract_amended`',
    `sales_order_reference` STRING COMMENT 'The Sales Order (SO) number from SAP S/4HANA SD module that originated the disputed invoice. Enables cross-referencing between the dispute, the original order, and the delivery to verify contract pricing and quantity terms.',
    `settlement_amount` DECIMAL(18,2) COMMENT 'The final agreed monetary settlement amount upon resolution of the dispute. Populated only when dispute_status = resolved. May reflect a full credit, partial credit, price adjustment, or zero (claim denied).',
    `sla_due_date` DATE COMMENT 'The target date by which the dispute must be resolved per internal Service Level Agreement (SLA) or contractual dispute resolution terms. Calculated from dispute_date plus the applicable SLA window based on dispute_type and priority_level.',
    `source_system` STRING COMMENT 'Identifies the operational system of record from which this dispute record originated. Supports data lineage tracking in the Databricks Silver Layer lakehouse.. Valid values are `SAP_S4HANA|ORACLE_NETSUITE|GRANULAR|MANUAL`',
    `updated_timestamp` TIMESTAMP COMMENT 'The timestamp of the most recent modification to the dispute record, in ISO 8601 format (yyyy-MM-ddTHH:mm:ss.SSSXXX). Used for incremental data pipeline processing and audit trail maintenance in the Silver Layer.',
    `weight_ticket_reference` STRING COMMENT 'Reference number of the weight ticket (scale ticket) associated with the disputed commodity delivery. Critical for weight variance disputes in grain, oilseed, and livestock commodity billing reconciliation per USDA GIPSA standards.',
    CONSTRAINT pk_dispute PRIMARY KEY(`dispute_id`)
) COMMENT 'Tracks formal disputes raised by agricultural customers against issued invoices, managing the dispute lifecycle from initiation through resolution. Captures dispute number, disputed invoice reference, dispute date, dispute type (price discrepancy, weight variance, quality rejection, grade dispute, MRL exceedance deduction, duplicate billing, contract terms disagreement), disputed amount, customer claim amount, dispute status (open/under_review/resolved/escalated/withdrawn), resolution date, resolution type (credit issued, price adjusted, claim denied, partial settlement), adjusted settlement amount, assigned reviewer, and escalation history. Supports USDA grain grading dispute workflows and commodity quality arbitration processes.';

CREATE OR REPLACE TABLE `agriculture_ecm`.`invoice`.`revenue_recognition` (
    `revenue_recognition_id` BIGINT COMMENT 'Primary key for revenue_recognition',
    `account_id` BIGINT COMMENT 'Reference to the customer (buyer/counterparty) associated with this revenue recognition event. Used for customer-level revenue reporting and analytics.',
    `invoice_id` BIGINT COMMENT 'Reference to the parent accounts receivable invoice that triggered this revenue recognition event. Links the recognition event to the billing document in the invoice domain.',
    `billing_schedule_id` BIGINT COMMENT 'Foreign key linking to invoice.billing_schedule. Business justification: Revenue recognition events are triggered by billing schedule milestones for long-term agricultural contracts. Adding billing_schedule_id to revenue_recognition links the recognition event to the sched',
    `carbon_credit_id` BIGINT COMMENT 'Foreign key linking to sustainability.carbon_credit. Business justification: ASC 606 / IFRS 15 revenue recognition for carbon credit sales requires tracing each recognition event to the specific carbon credit instrument being recognized. revenue_recognition has commodity_lot_r',
    `commodity_id` BIGINT COMMENT 'Foreign key linking to product.commodity. Business justification: ASC 606 revenue recognition in ag requires commodity-level performance obligation tracking — delivery terms, variable consideration, and recognition triggers differ by commodity. A commodity_id FK ena',
    `commodity_lot_id` BIGINT COMMENT 'Foreign key linking to inventory.commodity_lot. Business justification: ASC 606 revenue recognition audit: commodity revenue is recognized upon transfer of control of specific lots (delivery, title transfer). Direct FK replaces denormalized commodity_lot_reference, enabli',
    `company_code_id` BIGINT COMMENT 'Foreign key linking to finance.company_code. Business justification: Revenue recognition is performed at the legal entity level. In multi-entity agriculture operations, ASC 606 revenue recognition reporting by legal entity, consolidation, and statutory financial statem',
    `contract_id` BIGINT COMMENT 'Reference to the underlying customer contract or sales agreement governing the performance obligations for this revenue recognition event. Critical for multi-element agricultural commodity contracts.',
    `cost_center_id` BIGINT COMMENT 'Foreign key linking to finance.cost_center. Business justification: invoice.revenue_recognition carries a cost_center_code text field that is a denormalized reference to finance.cost_center. Revenue recognition events must be tied to specific cost centers for accurate',
    `journal_entry_id` BIGINT COMMENT 'Foreign key linking to finance.journal_entry. Business justification: Revenue recognition events generate GL postings (debit deferred revenue, credit revenue) under ASC 606. In agriculture, grain contract revenue recognition requires specific GL entries. gl_posting_refe',
    `line_id` BIGINT COMMENT 'Foreign key linking to invoice.invoice_line. Business justification: Revenue recognition under ASC 606/IFRS 15 is performed at the performance obligation level, which in agricultural billing maps to individual commodity lots on invoice lines. revenue_recognition alread',
    `lot_trace_id` BIGINT COMMENT 'Foreign key linking to supply.lot_trace. Business justification: Ag revenue recognition at lot level is required for organic premium tracking, grade-based pricing, and FSMA lot-level financial reporting. Linking revenue_recognition to lot_trace enables lot-level re',
    `original_event_revenue_recognition_id` BIGINT COMMENT 'For reversal or adjustment events, references the original revenue_recognition_event_id that is being reversed or corrected. Enables audit trail linkage between original recognition and its reversal/correction entries.',
    `obligation_id` BIGINT COMMENT 'Reference to the specific performance obligation within the contract that this recognition event satisfies. Under ASC 606/IFRS 15, revenue is recognized when or as each performance obligation is satisfied.',
    `shipment_id` BIGINT COMMENT 'Foreign key linking to supply.shipment. Business justification: Under ASC 606, ag revenue is recognized at shipment (FOB origin) or delivery (FOB destination) based on shipping terms. Linking revenue_recognition to shipment provides the shipment timestamp and term',
    `bol_number` STRING COMMENT 'The Bill of Lading (BOL) number associated with the shipment that triggered this revenue recognition event. For FOB (Free On Board) shipping point contracts, the BOL date establishes the title transfer date and thus the revenue recognition date.',
    `created_timestamp` TIMESTAMP COMMENT 'The timestamp when this revenue recognition event record was first created in the system. Audit trail field required for SOX compliance and data lineage in the Databricks Silver Layer.',
    `currency_code` STRING COMMENT 'ISO 4217 three-letter currency code for the transaction currency in which recognized_amount, deferred_amount, and transaction_price are expressed (e.g., USD, EUR, BRL for Brazilian agricultural exports).. Valid values are `^[A-Z]{3}$`',
    `deferred_amount` DECIMAL(18,2) COMMENT 'The portion of the transaction price that has been invoiced or received but not yet recognized as revenue, pending future performance obligation satisfaction. Recorded as a contract liability on the balance sheet. Common in multi-season crop contracts and prepaid input supply agreements.',
    `event_number` STRING COMMENT 'Externally visible, human-readable business identifier for this recognition event (e.g., RRE-2024-000123). Used for audit trails, GL reconciliation, and cross-system referencing in SAP S/4HANA FI.',
    `exchange_rate` DECIMAL(18,2) COMMENT 'The foreign currency exchange rate applied to convert the transaction currency amount to the functional currency amount at the recognition event date. Expressed as units of functional currency per one unit of transaction currency.',
    `fiscal_period` STRING COMMENT 'The fiscal year and period (YYYY-MM) to which this revenue recognition event is attributed for financial reporting. Determines the accounting period in which recognized revenue appears on the income statement. Aligned with SAP S/4HANA FI fiscal year variant.. Valid values are `^[0-9]{4}-(0[1-9]|1[0-2])$`',
    `functional_currency_amount` DECIMAL(18,2) COMMENT 'The recognized revenue amount translated into the entitys functional currency (typically USD for US-based agricultural operations) using the exchange rate at the recognition event date. Required for consolidated financial reporting under IFRS IAS 21 and GAAP ASC 830.',
    `gl_account_code` STRING COMMENT 'The General Ledger account code to which the recognized revenue amount is posted in SAP S/4HANA FI. Determines the revenue line in the income statement (e.g., crop commodity revenue, livestock revenue, agri-service revenue). Critical for financial close and SOX compliance.',
    `gl_posting_date` DATE COMMENT 'The accounting date on which the recognized revenue amount was posted to the General Ledger. May differ from recognition_event_date due to period-end close timing or late adjustments. Governs which fiscal period the revenue falls into.',
    `gl_posting_reference` STRING COMMENT 'The document number or journal entry reference generated in the General Ledger system (SAP S/4HANA) when the revenue recognition amount was posted. Enables direct drill-through from the recognition event to the GL journal entry for audit and reconciliation purposes.',
    `is_contract_modification` BOOLEAN COMMENT 'Indicates whether this revenue recognition event was triggered by or resulted from a contract modification (change order, price renegotiation, scope change). Contract modifications require reassessment of performance obligations and transaction price allocation under ASC 606/IFRS 15.',
    `is_variable_consideration_constrained` BOOLEAN COMMENT 'Indicates whether the variable consideration estimate included in this recognition event has been constrained (i.e., limited to the amount highly probable of not resulting in a significant revenue reversal). Required disclosure under ASC 606 constraint guidance for agricultural price-variable contracts.',
    `notes` STRING COMMENT 'Free-text field for additional context, auditor comments, or explanatory notes related to this revenue recognition event. Used to document non-standard recognition scenarios, regulatory exceptions, or manual override justifications.',
    `performance_obligation_satisfied_pct` DECIMAL(18,2) COMMENT 'For over-time revenue recognition, the cumulative percentage of the performance obligation satisfied as of this recognition event date. Expressed as a percentage (0.00 to 100.00). Used to calculate the recognized amount for long-term contract farming, agronomy services, and multi-season supply agreements.',
    `profit_center_code` STRING COMMENT 'SAP CO profit center code to which this revenue recognition event is attributed. Enables profitability analysis by business unit, crop type, or geographic region within the agricultural enterprise.',
    `recognition_event_date` DATE COMMENT 'The business date on which the revenue recognition event occurred — i.e., the date the performance obligation was satisfied and revenue became recognizable. For commodity sales, this is typically the title transfer date per the Bill of Lading (BOL) or weight ticket.',
    `recognition_status` STRING COMMENT 'Current lifecycle status of the revenue recognition event. Pending indicates awaiting trigger conditions; recognized indicates revenue has been posted to GL; deferred indicates revenue is held pending future obligation satisfaction; reversed indicates a prior recognition has been corrected; cancelled indicates the event was voided.. Valid values are `pending|recognized|deferred|reversed|cancelled`',
    `recognition_trigger` STRING COMMENT 'The specific business event or condition that triggered this revenue recognition event. Identifies whether recognition was triggered by physical delivery confirmation, legal title transfer (commodity), contract milestone completion, period-end proportional allocation, consignment sale by the buyer, or customer invoice acceptance. [ENUM-REF-CANDIDATE: delivery_confirmed|title_transfer|contract_milestone|period_end_allocation|consignment_sale|invoice_acceptance — promote to reference product]. Valid values are `delivery_confirmed|title_transfer|contract_milestone|period_end_allocation|consignment_sale|invoice_acceptance`',
    `recognition_type` STRING COMMENT 'Classification of the revenue recognition method applied to this event. Point_in_time applies to standard crop commodity deliveries; over_time applies to long-term service or contract farming arrangements; bill_and_hold applies where goods are invoiced but not yet shipped; consignment_release applies when consigned agricultural goods are sold by the consignee; commodity_title_transfer applies to grain elevator and commodity exchange transactions where title transfer timing governs recognition.. Valid values are `point_in_time|over_time|bill_and_hold|consignment_release|commodity_title_transfer`',
    `recognized_amount` DECIMAL(18,2) COMMENT 'The gross monetary amount of revenue recognized in this event, expressed in the transaction currency. For agricultural commodity sales, this reflects the agreed contract price multiplied by the delivered quantity (weight-ticket reconciled). Core financial metric for revenue reporting under ASC 606/IFRS 15.',
    `revenue_category` STRING COMMENT 'High-level classification of the revenue type being recognized. Enables disaggregated revenue reporting required under ASC 606 and IFRS 15 disclosure requirements. Categories reflect the primary agricultural revenue streams: crop commodity sales, livestock sales, agricultural services (custom farming, agronomy), input supply (seed, fertilizer, chemicals), and land lease/rental income.. Valid values are `crop_commodity|livestock|agri_services|input_supply|lease_rental`',
    `reversal_reason` STRING COMMENT 'Descriptive reason code or narrative explaining why a previously recognized revenue event was reversed. Applicable when recognition_status is reversed. Common reasons in agriculture include: contract cancellation, commodity rejection at delivery, quality dispute, weight-ticket discrepancy, or price renegotiation.',
    `sales_order_reference` STRING COMMENT 'The Sales Order (SO) number from SAP S/4HANA SD module that originated the revenue stream for this recognition event. Provides traceability from the customer order through invoicing to revenue recognition.',
    `shipping_terms` STRING COMMENT 'The shipping/delivery terms (Incoterms) governing when title and risk of loss transfer from seller to buyer. Directly determines the point-in-time at which revenue recognition criteria are met. FOB (Free On Board) shipping point means recognition at shipment; FOB destination means recognition at delivery. Critical for agricultural commodity export transactions.. Valid values are `FOB_shipping|FOB_destination|CIF|FAS|EXW`',
    `source_system` STRING COMMENT 'Identifies the operational system of record that originated this revenue recognition event. Supports data lineage tracking in the Databricks Silver Layer. SAP S/4HANA Revenue Accounting and Reporting (RAR) is the primary source for enterprise agricultural operations.. Valid values are `SAP_S4HANA|Oracle_NetSuite|Granular|manual`',
    `transaction_price` DECIMAL(18,2) COMMENT 'The total transaction price allocated to this performance obligation as determined under ASC 606 Step 3 (Determine Transaction Price). Includes fixed consideration and any variable consideration estimates. For commodity contracts, reflects the agreed price per unit multiplied by contracted quantity.',
    `updated_timestamp` TIMESTAMP COMMENT 'The timestamp when this revenue recognition event record was last modified. Tracks adjustments, status changes, and corrections to the recognition event for audit trail and SOX compliance purposes.',
    `variable_consideration_estimate` DECIMAL(18,2) COMMENT 'The estimated amount of variable consideration included in the transaction price for this recognition event. Variable consideration in agriculture includes price adjustments for commodity grade/quality premiums or discounts, volume rebates, weather-contingent pricing, and harvest yield-based true-ups. Constrained to the amount that is highly probable of not reversing per ASC 606 constraint guidance.',
    `weight_ticket_reference` STRING COMMENT 'Reference to the weight ticket number used to reconcile the delivered quantity of agricultural commodities (grain, produce, livestock) against the invoiced quantity. Weight-ticket reconciliation is a critical agricultural-specific step in confirming the quantity basis for revenue recognition.',
    CONSTRAINT pk_revenue_recognition PRIMARY KEY(`revenue_recognition_id`)
) COMMENT 'Records revenue recognition events triggered by invoice milestones per GAAP ASC 606 and IFRS 15 standards, capturing when and how agricultural revenue is recognized. Captures recognition event date, recognition type (point-in-time delivery, over-time contract, bill-and-hold, consignment release, commodity transfer of title), recognized amount, deferred amount, performance obligation reference, contract modification flag, variable consideration estimate, and GL posting reference. Critical for crop commodity sales where title transfer and revenue recognition timing may differ.';

CREATE OR REPLACE TABLE `agriculture_ecm`.`invoice`.`billing_schedule` (
    `billing_schedule_id` BIGINT COMMENT 'Unique system-generated identifier for the billing schedule record. Primary key for the billing_schedule data product.',
    `account_id` BIGINT COMMENT 'Reference to the customer or counterparty to whom recurring or milestone-based invoices will be issued under this billing schedule.',
    `commodity_id` BIGINT COMMENT 'Reference to the agricultural commodity (e.g., grain, livestock, crop inputs) associated with this billing schedule, enabling commodity-based pricing and weight-ticket reconciliation.',
    `company_code_id` BIGINT COMMENT 'Foreign key linking to finance.company_code. Business justification: Billing schedules for recurring storage, handling, or service contracts in agriculture are configured for a specific legal entity. Company code linkage supports entity-specific billing configuration, ',
    `conservation_enrollment_id` BIGINT COMMENT 'Foreign key linking to sustainability.conservation_enrollment. Business justification: USDA conservation program payments (CRP, EQIP, CSP) follow a defined annual or milestone-based billing schedule tied to enrollment contract terms. Linking billing_schedule to conservation_enrollment e',
    `contract_id` BIGINT COMMENT 'Reference to the long-term agricultural contract (grain storage agreement, crop input supply contract, livestock management service agreement) that this billing schedule governs.',
    `gl_account_id` BIGINT COMMENT 'Foreign key linking to finance.gl_account. Business justification: invoice.billing_schedule carries a gl_account_code text field that is a denormalized reference to finance.gl_account. Billing schedules drive revenue recognition postings to specific GL accounts; a pr',
    `ip_record_id` BIGINT COMMENT 'Foreign key linking to research.ip_record. Business justification: IP royalty billing schedules are directly tied to specific patents or PVP certificates: each IP record defines the royalty rate, basis, and term that drives the billing schedule. Linking billing_sched',
    `payment_term_id` BIGINT COMMENT 'Foreign key linking to invoice.payment_term. Business justification: billing_schedule.payment_terms_code is a denormalized string reference to the payment_term reference table. Billing schedules for long-term agricultural contracts must reference the authoritative paym',
    `variety_id` BIGINT COMMENT 'Foreign key linking to research.variety. Business justification: Seed technology royalty billing schedules are variety-specific: each licensed variety has its own per-unit royalty rate and billing cadence. Linking billing_schedule to variety enables automated royal',
    `approval_date` DATE COMMENT 'Date on which this billing schedule was formally approved and authorized for use. Supports audit trail and financial controls compliance.',
    `approval_required_flag` BOOLEAN COMMENT 'Indicates whether each billing run under this schedule requires explicit management approval before the invoice is released to the customer. Supports internal controls and SOX compliance for material agricultural contracts.',
    `approved_by` STRING COMMENT 'Name or identifier of the person who authorized this billing schedule for activation. Required for audit trail and SOX financial reporting controls.',
    `auto_invoice_flag` BOOLEAN COMMENT 'Indicates whether invoices are automatically generated and posted when the billing date or milestone is reached (True), or whether manual review and approval is required before invoice creation (False).',
    `billing_amount` DECIMAL(18,2) COMMENT 'Fixed monetary amount to be invoiced per billing cycle. Used when the billing amount is predetermined (e.g., fixed storage fee per month). Null when billing_formula is used instead for variable or commodity-based pricing.',
    `billing_day_of_month` STRING COMMENT 'Day of the month (1–31) on which recurring invoices are generated for monthly or quarterly schedules. For example, a value of 1 means invoices are generated on the first of each billing period month.',
    `billing_formula` STRING COMMENT 'Expression or formula used to calculate the invoice amount dynamically, supporting commodity-based pricing (e.g., quantity_mt * market_price_per_mt, weight_cwt * rate_per_cwt). Used when billing_amount is not fixed. Supports NPK input pricing, weight-ticket reconciliation, and variable rate billing.',
    `billing_frequency` STRING COMMENT 'Frequency at which invoices are generated under this schedule. Supports agricultural-specific cycles including seasonal (aligned with crop harvest or livestock production calendars) and milestone-based (triggered by specific agricultural events). [ENUM-REF-CANDIDATE: weekly|monthly|quarterly|semi_annual|annual|seasonal|milestone — promote to reference product]',
    `billing_month_of_year` STRING COMMENT 'Month of the year (1–12) on which annual or seasonal invoices are generated. Supports crop harvest calendar alignment (e.g., month 10 for fall harvest billing) and livestock production cycle billing.',
    `billing_tolerance_days` STRING COMMENT 'Number of days before or after the scheduled billing date within which invoice generation is still considered on-schedule. Accommodates agricultural operational variability such as harvest delays or weather-related disruptions.',
    `completed_occurrences` STRING COMMENT 'Count of billing events that have been successfully executed (invoices generated and posted) under this schedule to date. Used to track schedule progress and remaining billing obligations.',
    `cost_center_code` STRING COMMENT 'SAP cost center code associated with the billing schedule for internal cost allocation and profitability analysis across agricultural business units (e.g., crop division, livestock division).',
    `created_timestamp` TIMESTAMP COMMENT 'Timestamp when this billing schedule record was first created in the system. Supports audit trail, data lineage, and SOX financial reporting controls.',
    `currency_code` STRING COMMENT 'ISO 4217 three-letter currency code for the billing amount (e.g., USD, EUR, CAD). Supports multi-currency agricultural trade and international commodity contracts.. Valid values are `^[A-Z]{3}$`',
    `discount_percent` DECIMAL(18,2) COMMENT 'Percentage discount applied to the billing amount for each invoice generated under this schedule. Supports volume-based, seasonal, or contractual discount arrangements common in agricultural supply chain agreements.',
    `end_date` DATE COMMENT 'The date on which this billing schedule expires and no further invoices will be generated. Nullable for open-ended schedules. Aligns with contract expiry or crop season end.',
    `last_billed_date` DATE COMMENT 'The date on which the most recent invoice was generated under this billing schedule. Used to track billing history and validate schedule adherence.',
    `milestone_completion_date` DATE COMMENT 'The date on which the triggering milestone was confirmed as completed, authorizing invoice generation for milestone-based billing schedules.',
    `milestone_description` STRING COMMENT 'Description of the agricultural business event or milestone that triggers invoice generation for milestone-type schedules (e.g., Harvest completion, Grain delivery to elevator, Livestock weaning, Crop input delivery confirmed).',
    `next_billing_date` DATE COMMENT 'The date on which the next invoice will be automatically generated or triggered under this schedule. Updated after each successful billing run.',
    `notes` STRING COMMENT 'Free-text field for additional context, special instructions, or exceptions related to this billing schedule (e.g., Billing deferred pending USDA crop report, Weight-ticket reconciliation required before invoicing).',
    `profit_center_code` STRING COMMENT 'SAP profit center code for revenue attribution, enabling EBITDA and profitability reporting by agricultural segment (e.g., grain storage, crop inputs, livestock services).',
    `revenue_recognition_method` STRING COMMENT 'Method used to recognize revenue from invoices generated by this schedule per IFRS 15 / ASC 606 standards. point_in_time for delivery-based recognition; over_time for service contracts; milestone_based for performance obligation completion; proportional for percentage-of-completion.. Valid values are `point_in_time|over_time|milestone_based|proportional`',
    `schedule_code` STRING COMMENT 'Externally-known alphanumeric code uniquely identifying this billing schedule, used for cross-system reference and communication with customers and partners (e.g., BSCHED-2024-001).. Valid values are `^[A-Z0-9_-]{3,30}$`',
    `schedule_name` STRING COMMENT 'Human-readable descriptive name for the billing schedule (e.g., Annual Grain Storage Q1 Billing, Seasonal Crop Input Monthly Installment).',
    `schedule_status` STRING COMMENT 'Current lifecycle state of the billing schedule. active indicates invoices are being generated; suspended indicates temporarily paused; completed indicates all billing milestones fulfilled; cancelled indicates terminated before completion; draft indicates not yet activated.. Valid values are `active|suspended|completed|cancelled|draft`',
    `schedule_type` STRING COMMENT 'Classification of the billing schedule by its triggering mechanism. recurring for time-based periodic billing; milestone for event-triggered billing (e.g., harvest completion); one_time for single-occurrence billing; seasonal for crop or livestock production calendar-aligned billing.. Valid values are `recurring|milestone|one_time|seasonal`',
    `source_system` STRING COMMENT 'Operational system of record from which this billing schedule originated (e.g., SAP S/4HANA FI, Oracle NetSuite, Granular Farm Management). Supports data lineage and reconciliation in the Databricks Silver Layer.. Valid values are `SAP_S4HANA|ORACLE_NETSUITE|GRANULAR|SALESFORCE|MANUAL`',
    `start_date` DATE COMMENT 'The date on which this billing schedule becomes effective and the first billing cycle begins. Aligns with contract commencement or crop season start.',
    `tax_code` STRING COMMENT 'Tax classification code applied to invoices generated by this schedule, determining applicable tax rates and exemptions (e.g., agricultural tax exemptions, state sales tax codes). Integrates with SAP S/4HANA tax determination.',
    `total_billing_occurrences` STRING COMMENT 'Total number of billing events planned for this schedule over its full lifecycle. For example, a 12-month monthly schedule has 12 occurrences. Null for open-ended or milestone-only schedules.',
    `updated_timestamp` TIMESTAMP COMMENT 'Timestamp when this billing schedule record was last modified. Supports change tracking, audit trail, and Silver Layer incremental processing in the Databricks Lakehouse.',
    CONSTRAINT pk_billing_schedule PRIMARY KEY(`billing_schedule_id`)
) COMMENT 'Defines recurring or milestone-based billing schedules for long-term agricultural contracts including grain storage agreements, crop input supply contracts, and livestock management service agreements. Captures schedule code, billing frequency (weekly/monthly/quarterly/seasonal/milestone), next billing date, billing amount or formula, contract reference, commodity reference, billing start date, billing end date, auto-invoice flag, and schedule status. Supports seasonal billing cycles aligned with crop harvest and livestock production calendars.';

CREATE OR REPLACE TABLE `agriculture_ecm`.`invoice`.`dunning_notice` (
    `dunning_notice_id` BIGINT COMMENT 'Unique system-generated identifier for each dunning notice record. Primary key for the dunning_notice data product.',
    `account_id` BIGINT COMMENT 'Reference to the agricultural customer (buyer, distributor, food manufacturer) who is the subject of this dunning notice.',
    `invoice_id` BIGINT COMMENT 'Reference to the originating invoice record that triggered this dunning notice. Links the dunning action to the specific overdue billing document.',
    `billing_account_id` BIGINT COMMENT 'Reference to the customer AR billing account against which this dunning notice is issued. Supports dunning at the account level, which may span multiple invoices.',
    `employee_id` BIGINT COMMENT 'Foreign key linking to workforce.employee. Business justification: Collections portfolio management in agriculture AR requires linking dunning notices to the responsible collections employee for workload reporting, performance reviews, and overdue account ownership. ',
    `company_code_id` BIGINT COMMENT 'Foreign key linking to finance.company_code. Business justification: Dunning notices are issued by a specific legal entity (grain elevator, cooperative). In multi-entity agriculture operations, collections management by legal entity, credit risk reporting, and dunning ',
    `created_timestamp` TIMESTAMP COMMENT 'The date and time when this dunning notice record was first created in the system. Audit trail field for data governance and compliance.',
    `credit_exposure` DECIMAL(18,2) COMMENT 'Total outstanding credit exposure for the customer at the time of dunning notice issuance, including all open invoices, not just the overdue amount. Used for credit risk management.',
    `credit_limit` DECIMAL(18,2) COMMENT 'The approved credit limit for the customer at the time of dunning notice issuance. Provides context for collections decisions and credit risk assessment.',
    `currency_code` STRING COMMENT 'ISO 4217 three-letter currency code for the overdue amount (e.g., USD, EUR, CAD). Supports multi-currency agricultural trade transactions.. Valid values are `^[A-Z]{3}$`',
    `customer_response` STRING COMMENT 'The customers response to the dunning notice. Captures the outcome of the collections contact: No Response, Payment Promised, Partial Payment, Disputed, Payment Made, Arrangement Agreed, or Referred to Legal. [ENUM-REF-CANDIDATE: No Response|Payment Promised|Partial Payment|Disputed|Payment Made|Arrangement Agreed|Referred to Legal — promote to reference product]',
    `customer_response_date` DATE COMMENT 'The date on which the customer responded to the dunning notice. Used to measure response time and assess collections effectiveness.',
    `days_overdue` STRING COMMENT 'Number of calendar days the oldest invoice included in this dunning notice has been past its due date at the time of notice issuance. Used for AR aging analysis and credit risk assessment.',
    `dispute_reference` STRING COMMENT 'Reference number of any active invoice dispute associated with this dunning notice. If a dispute is raised, dunning may be blocked pending resolution. Links to the dispute management process.',
    `dunning_area` STRING COMMENT 'SAP dunning area code used to segment dunning processing by business unit, region, or company code. Enables separate dunning runs for different agricultural divisions (e.g., crop inputs vs. livestock feed).',
    `dunning_block_reason` STRING COMMENT 'Reason code indicating why dunning has been blocked for this customer account (e.g., payment arrangement in place, dispute under review, seasonal deferral granted, legal hold). Null if no block is active.',
    `dunning_charge_amount` DECIMAL(18,2) COMMENT 'Administrative fee or dunning charge levied on the customer for the issuance of this dunning notice, as permitted by the sales contract or applicable law.',
    `dunning_level` STRING COMMENT 'Numeric escalation level of the dunning notice indicating severity of the collections action. Level 1 = first reminder, Level 2 = second reminder, Level 3 = final notice, Level 4 = legal action referral. Aligns with SAP dunning levels 1–4.',
    `dunning_level_description` STRING COMMENT 'Human-readable label corresponding to the dunning level: First Reminder, Second Reminder, Final Notice, or Legal Action. Used in customer-facing correspondence and collections reporting.. Valid values are `First Reminder|Second Reminder|Final Notice|Legal Action`',
    `dunning_method` STRING COMMENT 'The communication channel used to deliver the dunning notice to the customer. Email = electronic delivery; Mail = postal letter; Phone = verbal notice; Legal = formal legal correspondence; Fax = facsimile; Portal = customer self-service portal notification.. Valid values are `Email|Mail|Phone|Legal|Fax|Portal`',
    `escalation_date` DATE COMMENT 'The date on which the dunning notice was escalated to legal action or a third-party collections agency. Null if not yet escalated.',
    `escalation_status` STRING COMMENT 'Current escalation state of the dunning notice. Tracks whether the overdue account has been escalated beyond standard collections to legal counsel or a third-party collections agency. [ENUM-REF-CANDIDATE: Not Escalated|Pending Escalation|Escalated to Legal|Referred to Agency|Write-Off Initiated — promote to reference product]. Valid values are `Not Escalated|Pending Escalation|Escalated to Legal|Referred to Agency|Write-Off Initiated`',
    `exchange_rate` DECIMAL(18,2) COMMENT 'Foreign currency exchange rate applied to convert the overdue amount to functional currency at the time of dunning notice issuance.',
    `interest_amount` DECIMAL(18,2) COMMENT 'Calculated interest or late payment charges levied on the overdue balance and included in this dunning notice, per the contractual payment terms. Applicable where agricultural supply contracts include late payment penalty clauses.',
    `is_dunning_blocked` BOOLEAN COMMENT 'Indicates whether further dunning actions are currently blocked for this customer account. True = dunning is blocked (e.g., due to dispute, payment plan, or seasonal deferral); False = dunning proceeds normally.',
    `notes` STRING COMMENT 'Free-text field for collections officers to record additional context, customer communications, special circumstances (e.g., crop failure, weather event impacting payment), or follow-up actions related to this dunning notice.',
    `notice_date` DATE COMMENT 'The calendar date on which the dunning notice was formally issued and sent to the customer. Used as the reference date for response deadline calculation.',
    `notice_number` STRING COMMENT 'Externally visible, human-readable identifier for the dunning notice, used in customer correspondence and collections tracking. Format: DN-{YYYY}-{sequence}.. Valid values are `^DN-[0-9]{4}-[0-9]{8}$`',
    `notice_status` STRING COMMENT 'Current lifecycle status of the dunning notice. Draft = prepared but not sent; Issued = sent to customer; Responded = customer acknowledged or paid; Escalated = forwarded to legal/collections agency; Closed = resolved; Cancelled = voided.. Valid values are `Draft|Issued|Responded|Escalated|Closed|Cancelled`',
    `oldest_invoice_date` DATE COMMENT 'The invoice date of the oldest unpaid invoice included in this dunning notice. Used to determine the age of the oldest outstanding receivable and assess credit risk.',
    `overdue_amount` DECIMAL(18,2) COMMENT 'Total outstanding overdue balance included in this dunning notice, expressed in the transaction currency. Represents the sum of all past-due invoice amounts for the customer account at the time of notice issuance.',
    `overdue_amount_functional` DECIMAL(18,2) COMMENT 'Total overdue balance converted to the companys functional currency (typically USD) using the exchange rate at the time of notice issuance. Required for consolidated AR reporting under GAAP/IFRS.',
    `payment_arrangement_date` DATE COMMENT 'The date on which a payment arrangement was formally agreed with the customer. Null if no arrangement has been established.',
    `payment_arrangement_flag` BOOLEAN COMMENT 'Indicates whether a formal payment arrangement or installment plan has been agreed with the customer as a result of this dunning notice. True = arrangement in place; False = no arrangement. Supports seasonal agricultural buyer cash flow management.',
    `promised_payment_amount` DECIMAL(18,2) COMMENT 'The amount the customer has committed to paying by the promised payment date. May be less than the full overdue amount if a partial payment arrangement has been agreed.',
    `promised_payment_date` DATE COMMENT 'The date by which the customer has committed to making payment as part of a payment promise or arrangement. Used to monitor promise-to-pay compliance for agricultural buyers with seasonal cash flow constraints.',
    `response_deadline_date` DATE COMMENT 'The date by which the customer must respond or remit payment before the dunning notice escalates to the next level. Critical for seasonal agricultural buyers managing post-harvest cash flow.',
    `source_system` STRING COMMENT 'The operational system of record from which this dunning notice originated. Supports data lineage and reconciliation across the agricultural enterprise.. Valid values are `SAP S/4HANA|Oracle NetSuite|Granular|Manual`',
    `updated_timestamp` TIMESTAMP COMMENT 'The date and time when this dunning notice record was last modified. Audit trail field for tracking status changes, escalations, and customer response updates.',
    CONSTRAINT pk_dunning_notice PRIMARY KEY(`dunning_notice_id`)
) COMMENT 'Tracks dunning (collections) notices issued to agricultural customers with overdue AR balances. Captures dunning notice number, customer AR account reference, dunning level (1st reminder/2nd reminder/final notice/legal action), notice date, overdue amount, oldest invoice date, dunning method (email/mail/phone/legal), response deadline, customer response, and escalation status. Supports collections management for seasonal agricultural buyers who may experience cash flow constraints post-harvest.';

CREATE OR REPLACE TABLE `agriculture_ecm`.`invoice`.`price_basis` (
    `price_basis_id` BIGINT COMMENT 'Primary key for price_basis',
    `commodity_id` BIGINT COMMENT 'Foreign key linking to product.commodity. Business justification: Price basis records (futures exchange, basis amount, delivery specs) are inherently commodity-specific in ag trading. Linking to commodity_id enables basis-by-commodity reporting, forward contract pri',
    `grading_standard_id` BIGINT COMMENT 'Foreign key linking to product.grading_standard. Business justification: Price basis in ag commodity trading is grade-specific — No. 2 Yellow Corn commands a different basis than No. 3. A grading_standard_id FK normalizes the denormalized grade_standard field and enables g',
    `market_price_id` BIGINT COMMENT 'Foreign key linking to sales.market_price. Business justification: A price basis record in grain trading references a specific market price source (exchange settlement, WASDE reference). Linking price_basis to market_price enables automated basis calculation, price f',
    `material_master_id` BIGINT COMMENT 'Foreign key linking to inventory.material_master. Business justification: Commodity pricing configuration: price basis records define futures-based pricing for specific commodities; material_master is the authoritative commodity specification record (grade standards, moistu',
    `sustainability_certification_id` BIGINT COMMENT 'Foreign key linking to sustainability.sustainability_certification. Business justification: Price basis definitions for certified organic/sustainable premiums must reference the specific certification scheme (e.g., USDA Organic, ISCC) that governs the premium. price_basis has organic_certifi',
    `zone_id` BIGINT COMMENT 'Foreign key linking to weather.weather_zone. Business justification: Commodity price basis amounts vary by weather zone — drought risk, frost-free days, and climate classification directly influence basis levels at delivery locations. Grain merchandisers set zone-speci',
    `applicable_contract_types` STRING COMMENT 'Comma-separated list of contract types for which this price basis is valid (e.g., basis_contract,hedge_to_arrive,forward_contract,spot_purchase). Restricts the use of this basis record to appropriate contract contexts in invoice generation. [ENUM-REF-CANDIDATE: basis_contract|hedge_to_arrive|forward_contract|spot_purchase|deferred_payment|minimum_price — promote to reference product]',
    `approved_by` STRING COMMENT 'Name or employee identifier of the authorized person who approved this price basis record for use in invoice calculations. Required for SOX internal controls over financial reporting and GAAP revenue recognition governance.',
    `approved_date` DATE COMMENT 'The date on which this price basis record was formally approved for use. Required for SOX audit trail and financial reporting controls. Null if the record is in pending or draft status.',
    `basis_amount` DECIMAL(18,2) COMMENT 'The premium or discount applied over or under the futures contract price to arrive at the cash price, expressed in the currency unit per unit of measure (e.g., -0.15 USD/bushel represents a 15-cent under basis for corn). Negative values indicate a discount below futures; positive values indicate a premium above futures.',
    `basis_code` STRING COMMENT 'Externally-known alphanumeric code uniquely identifying this price basis configuration (e.g., CORN-CBOT-DEC, SOY-CME-MAR). Used in contract references, invoice line items, and grain elevator systems to reference the applicable pricing basis.. Valid values are `^[A-Z0-9_-]{2,20}$`',
    `basis_currency_code` STRING COMMENT 'ISO 4217 three-letter currency code in which the basis amount is denominated (e.g., USD for US domestic grain markets, CAD for Canadian operations). Ensures correct currency handling in multi-currency agricultural operations.. Valid values are `^[A-Z]{3}$`',
    `basis_name` STRING COMMENT 'Human-readable descriptive name for the price basis (e.g., December Corn CBOT Basis - Central Illinois). Used in reports, invoices, and contract documents for clear identification of the pricing basis applied.',
    `basis_status` STRING COMMENT 'Current lifecycle status of the price basis record. Active records are eligible for invoice pricing; inactive/expired records are retained for historical reference and audit; superseded records have been replaced by a newer basis version.. Valid values are `active|inactive|pending|expired|superseded`',
    `created_timestamp` TIMESTAMP COMMENT 'The date and time when this price basis record was first created in the system, in ISO 8601 format with timezone offset (yyyy-MM-ddTHH:mm:ss.SSSXXX). Provides audit trail for record creation per SOX and GAAP financial reporting controls.',
    `delivery_country_code` STRING COMMENT 'ISO 3166-1 alpha-3 country code for the delivery location (e.g., USA, CAN, BRA). Required for international commodity contracts, COOL compliance, and cross-border agricultural trade reporting.. Valid values are `^[A-Z]{3}$`',
    `delivery_state_province` STRING COMMENT 'Two-letter US state or Canadian province code for the delivery location (e.g., IL, IA, KS, NE). Used for regional basis analysis, USDA reporting, and state-level agricultural compliance.. Valid values are `^[A-Z]{2}$`',
    `effective_date` DATE COMMENT 'The calendar date from which this price basis record becomes active and eligible for use in invoice calculations. Basis records are date-sensitive as commodity basis levels change with market conditions and seasonal patterns.',
    `expiry_date` DATE COMMENT 'The calendar date after which this price basis record is no longer valid for new invoice calculations. Null indicates an open-ended basis with no defined expiration. Aligns with futures contract expiration cycles and seasonal marketing periods.',
    `formula_expression` STRING COMMENT 'For formula-based pricing methods, the mathematical expression or rule used to calculate the final price (e.g., CBOT_CLOSE + BASIS + FREIGHT_ALLOWANCE - MOISTURE_DISCOUNT). Null for non-formula pricing methods. Stored as a string expression interpreted by the pricing engine.',
    `freight_allowance` DECIMAL(18,2) COMMENT 'The freight cost component embedded in or deducted from the basis amount, expressed per unit of measure. Represents the transportation cost from the delivery location to the terminal market or export elevator. Used in FOB vs. CIF pricing reconciliation.',
    `futures_contract_month` STRING COMMENT 'The specific futures contract delivery month and year used as the pricing reference (e.g., DEC-2025, MAR-2026). Critical for grain and livestock invoice pricing to identify which futures contract price is applied in basis calculations.. Valid values are `^(JAN|FEB|MAR|APR|MAY|JUN|JUL|AUG|SEP|OCT|NOV|DEC)-[0-9]{4}$`',
    `futures_exchange` STRING COMMENT 'The futures exchange whose contract price is used as the reference price for this basis (e.g., CBOT for corn/soybeans/wheat, CME for cattle/hogs, ICE for cotton). Null for spot_market or flat_price methods.. Valid values are `CBOT|CME|ICE|KCBT|MGE|NYMEX`',
    `gmo_applicable` BOOLEAN COMMENT 'Indicates whether this price basis applies to GMO commodity (True) or non-GMO/identity-preserved commodity (False). Non-GMO commodities typically command a premium basis over standard GMO commodity prices, requiring separate basis records.',
    `handling_charge` DECIMAL(18,2) COMMENT 'The per-unit elevator or handling fee included in or deducted from the basis calculation (e.g., 0.02 USD/BU for grain elevator handling). Represents the cost of receiving, storing, and loading grain at the delivery location.',
    `max_quantity` DECIMAL(18,2) COMMENT 'The maximum commodity quantity (in the specified unit of measure) for which this basis applies. Basis records may be quantity-banded for volume pricing tiers. Null indicates no maximum quantity restriction.',
    `min_quantity` DECIMAL(18,2) COMMENT 'The minimum commodity quantity (in the specified unit of measure) required for this basis to apply. Basis levels may differ for small lots vs. full truckload or barge quantities. Null indicates no minimum quantity restriction.',
    `moisture_adjustment_rate` DECIMAL(18,2) COMMENT 'The per-unit price adjustment applied per percentage point of moisture above or below the standard moisture level (e.g., -0.0035 USD/BU per 1% moisture above 15.5% for corn). Used in weight-ticket reconciliation and invoice adjustments for grain quality discounts.',
    `notes` STRING COMMENT 'Free-text field for additional context, special conditions, or exceptions associated with this price basis record (e.g., Applies only to identity-preserved white corn, Subject to CBOT limit move provisions). Supports operational transparency and audit documentation.',
    `organic_certified` BOOLEAN COMMENT 'Indicates whether this price basis applies to USDA-certified organic commodity (True) or conventional commodity (False). Organic commodities command significant basis premiums and require separate pricing basis records for accurate invoice generation.',
    `price_ceiling` DECIMAL(18,2) COMMENT 'The maximum cash price per unit of measure above which this basis will not result in an invoice price, regardless of futures movement. Null if no ceiling applies. Used in capped-price contract billing scenarios common in livestock and specialty crop markets.',
    `price_floor` DECIMAL(18,2) COMMENT 'The minimum cash price per unit of measure below which this basis will not result in an invoice price, regardless of futures movement (e.g., minimum price guarantee in minimum-price contracts). Null if no floor applies. Used in minimum-price contract billing scenarios.',
    `pricing_method` STRING COMMENT 'The method used to determine the commodity price for invoice calculations. Options include: futures_basis (price = futures + basis), spot_market (current cash price), formula (custom formula-driven), flat_price (fixed agreed price), basis_contract (basis locked, futures open), hedge_to_arrive (futures locked, basis open).. Valid values are `futures_basis|spot_market|formula|flat_price|basis_contract|hedge_to_arrive`',
    `seasonal_flag` BOOLEAN COMMENT 'Indicates whether this price basis is seasonal in nature (True) or applies year-round (False). Seasonal bases are common in grain marketing where harvest-time basis levels differ significantly from pre-harvest or post-harvest periods.',
    `source_system` STRING COMMENT 'The originating operational system from which this price basis record was sourced (e.g., SAP_SD for SAP S/4HANA Sales & Distribution pricing conditions, GRANULAR for Granular Farm Management, DTN for DTN market data feed). Supports data lineage and reconciliation in the Databricks Silver layer.. Valid values are `SAP_SD|GRANULAR|DTN|MANUAL|ORACLE_NETSUITE|CLIMATE_FIELDVIEW`',
    `standard_moisture_pct` DECIMAL(18,2) COMMENT 'The reference moisture percentage at which no moisture adjustment is applied (e.g., 15.5% for corn, 13.0% for soybeans). Moisture readings from weight tickets above this level trigger discounts; below may trigger premiums per the moisture_adjustment_rate.',
    `standard_test_weight_lbs` DECIMAL(18,2) COMMENT 'The reference test weight in pounds per bushel at which no test weight adjustment is applied (e.g., 56 lbs/BU for corn, 60 lbs/BU for soybeans, 60 lbs/BU for wheat). Deviations from this standard trigger price adjustments per test_weight_adjustment_rate.',
    `test_weight_adjustment_rate` DECIMAL(18,2) COMMENT 'The per-unit price adjustment applied per pound below the standard test weight (e.g., -0.01 USD/BU per pound below 56 lbs/BU for corn). Test weight is a key quality factor in grain pricing that affects invoice amounts.',
    `unit_of_measure` STRING COMMENT 'The unit of measure against which the basis amount is applied (e.g., BU for bushel in grain, CWT for hundredweight in livestock, MT for metric ton in export contracts). Aligns with USDA and exchange standard units for the commodity type. [ENUM-REF-CANDIDATE: BU|CWT|MT|LB|TON|KG|OZ — 7 candidates stripped; promote to reference product]',
    `updated_timestamp` TIMESTAMP COMMENT 'The date and time when this price basis record was last modified, in ISO 8601 format with timezone offset (yyyy-MM-ddTHH:mm:ss.SSSXXX). Supports change tracking, data lineage, and incremental load processing in the Databricks Silver layer.',
    CONSTRAINT pk_price_basis PRIMARY KEY(`price_basis_id`)
) COMMENT 'Reference table defining commodity pricing bases used in agricultural invoice calculations including futures-based pricing, basis contracts, spot pricing, and formula pricing. Captures basis code, commodity type (corn, soybeans, wheat, cotton, cattle, hogs), pricing method (CBOT futures, CME futures, spot market, DTN market data, WASDE-referenced), basis amount (premium/discount over futures), effective date, expiry date, delivery location, and applicable contract types. Essential for accurate commodity invoice pricing in grain and livestock billing.';

CREATE OR REPLACE TABLE `agriculture_ecm`.`invoice`.`advance_payment` (
    `advance_payment_id` BIGINT COMMENT 'Unique system-generated identifier for the advance payment record. Primary key for the advance_payment data product in the invoice domain.',
    `account_id` BIGINT COMMENT 'Reference to the agricultural buyer or customer who made the advance payment. Links to the customer master record for AR management.',
    `bank_account_id` BIGINT COMMENT 'Foreign key linking to finance.bank_account. Business justification: Pre-harvest advances and input financing advances in agriculture are disbursed from specific bank accounts. Treasury management, bank reconciliation, and cash flow forecasting require linking advance ',
    `billing_account_id` BIGINT COMMENT 'Foreign key linking to invoice.billing_account. Business justification: Advance payments are received from agricultural buyers and must be tracked against the AR billing account master. Adding billing_account_id links advance_payment to the billing_account within the invo',
    `commodity_id` BIGINT COMMENT 'Foreign key linking to product.commodity. Business justification: Advance payments in ag (pre-harvest financing, forward delivery advances) are commodity-specific financial instruments. Lenders and ag lenders require commodity_id for crop-year/commodity exposure rep',
    `commodity_lot_id` BIGINT COMMENT 'Foreign key linking to inventory.commodity_lot. Business justification: Crop advance and pre-harvest financing: advance payments in grain agriculture are collateralized against or applied to specific commodity lots upon delivery. Direct FK replaces denormalized commodity_',
    `conservation_enrollment_id` BIGINT COMMENT 'Foreign key linking to sustainability.conservation_enrollment. Business justification: USDA conservation program advance payments (EQIP, CSP, CRP) are disbursed to enrolled producers. advance_payment has seasonal_program_code as plain text but no FK to conservation_enrollment. This link',
    `contract_id` BIGINT COMMENT 'Reference to the underlying agricultural commodity contract, supply agreement, or purchase contract that this advance payment is securing. Common in forward commodity contracts and crop pre-purchase agreements.',
    `drought_index_id` BIGINT COMMENT 'Foreign key linking to weather.drought_index. Business justification: Drought conditions trigger emergency advance payment programs for producers — ag lenders and cooperatives issue advances based on drought severity classifications. Linking drought_index to advance_pay',
    `farm_unit_id` BIGINT COMMENT 'Foreign key linking to land.farm_unit. Business justification: Pre-harvest operating advances and input financing in agriculture are extended against a farm units expected production. Linking advance_payment to farm_unit supports crop-year advance tracking, cred',
    `journal_entry_id` BIGINT COMMENT 'Foreign key linking to finance.journal_entry. Business justification: Advance payments (pre-harvest financing, input advances) generate GL postings (debit advance receivable, credit cash). In agriculture, linking advance_payment to its journal entry supports reconciliat',
    `growing_season_id` BIGINT COMMENT 'Foreign key linking to crop.growing_season. Business justification: Seasonal operating credit: advance payments (pre-season input financing, marketing advances) are extended against a specific growing seasons expected production. This FK links the financial advance t',
    `loan_id` BIGINT COMMENT 'Foreign key linking to finance.loan. Business justification: In agriculture, pre-harvest advances and operating advances to producers are often funded by FSA operating loans or revolving credit facilities. Linking advance_payment to the funding loan supports lo',
    `payment_term_id` BIGINT COMMENT 'Foreign key linking to invoice.payment_term. Business justification: advance_payment.payment_terms_code is a denormalized string reference to the payment_term reference table. Replacing with payment_term_id FK normalizes this to the authoritative payment_term master, e',
    `planting_window_id` BIGINT COMMENT 'Foreign key linking to weather.planting_window. Business justification: Planting window assessments drive advance payment timing for seed and input purchases — producers and cooperatives request operating advances when planting windows open. Linking planting_window to adv',
    `advance_amount` DECIMAL(18,2) COMMENT 'Gross amount of the advance payment received from the agricultural buyer in the transaction currency. Represents the total prepayment before any application to invoices or deductions.',
    `advance_payment_number` STRING COMMENT 'Externally-visible, human-readable business identifier for the advance payment. Used in customer communications, remittance advice matching, and AR reconciliation. Follows the format ADV-YYYY-NNNNNN.. Valid values are `^ADV-[0-9]{4}-[0-9]{6}$`',
    `advance_purpose` STRING COMMENT 'Business purpose classification for the advance payment describing the agricultural transaction it secures. Drives accounting treatment, revenue recognition timing, and reporting segmentation. [ENUM-REF-CANDIDATE: crop_pre_purchase|seed_advance|input_supply_advance|storage_deposit|livestock_pre_purchase|freight_deposit|processing_advance — promote to reference product]',
    `application_status` STRING COMMENT 'Current lifecycle status of the advance payment indicating how much of the advance has been applied against invoices. Drives AR aging, cash application workflows, and revenue recognition schedules. Valid values: unapplied (no invoices applied yet), partially_applied (some amount applied), fully_applied (entire advance consumed), cancelled (advance voided), refunded (advance returned to buyer).. Valid values are `unapplied|partially_applied|fully_applied|cancelled|refunded`',
    `applied_amount` DECIMAL(18,2) COMMENT 'Cumulative amount of the advance payment that has been applied against one or more invoices to date. Derived from application events but stored for AR reporting and aging analysis.',
    `bank_reference_number` STRING COMMENT 'Bank-assigned transaction reference number for the advance payment wire transfer or ACH transaction. Used for bank statement reconciliation, payment tracing, and audit trail in treasury operations.',
    `cost_center_code` STRING COMMENT 'SAP Controlling (CO) cost center code for internal cost allocation of advance payment processing activities. Used in overhead allocation and operational cost reporting.',
    `created_timestamp` TIMESTAMP COMMENT 'Timestamp when the advance payment record was first created in the system. Provides audit trail for record creation and supports SOX financial controls and data lineage tracking.',
    `crop_year` STRING COMMENT 'The agricultural crop year (e.g., 2024) to which this advance payment is attributed. Crop year is the standard period for agricultural commodity accounting, contract settlement, and USDA reporting. Enables crop-year-based financial analysis and advance program reconciliation.',
    `currency_code` STRING COMMENT 'ISO 4217 three-letter currency code for the advance payment transaction currency (e.g., USD, EUR, BRL, CAD). Required for multi-currency agricultural commodity trading and international buyer settlements.. Valid values are `^[A-Z]{3}$`',
    `customer_reference_number` STRING COMMENT 'Buyer-provided reference number included with the advance payment remittance, such as the buyers internal purchase order number or contract reference. Enables matching of incoming payments to buyer records and facilitates dispute resolution.',
    `exchange_rate` DECIMAL(18,2) COMMENT 'Foreign currency exchange rate applied at the time of advance payment receipt, expressed as units of transaction currency per one unit of functional currency. Used for functional currency conversion and FX gain/loss reporting per IFRS 21.',
    `expected_delivery_date` DATE COMMENT 'Anticipated date on which the commodity, seed, input supply, or agricultural service secured by this advance payment is expected to be delivered or completed. Drives revenue recognition scheduling, advance application planning, and contract performance monitoring.',
    `expiry_date` DATE COMMENT 'Date after which the advance payment is no longer valid for application against invoices if not consumed. Relevant for seasonal agricultural advance programs where prepayments must be applied within a crop season or contract period.',
    `functional_currency_amount` DECIMAL(18,2) COMMENT 'Advance payment amount converted to the entitys functional currency (typically USD) using the exchange rate at receipt date. Required for consolidated financial reporting, GL posting, and GAAP/IFRS compliance.',
    `gl_account_code` STRING COMMENT 'General Ledger (GL) account code to which the advance payment liability is posted (typically a customer advance/deferred revenue account). Required for GAAP/IFRS financial reporting and balance sheet classification of advance receipts.',
    `interest_accrued_amount` DECIMAL(18,2) COMMENT 'Total interest amount accrued on the advance payment from receipt date to current date or application date. Applicable when advance payment programs carry interest obligations per contract terms.',
    `interest_rate` DECIMAL(18,2) COMMENT 'Annual interest rate (percentage) applicable to the advance payment if the agricultural buyer earns interest on prepaid funds or if the seller charges a financing fee on the advance. Common in large commodity pre-purchase programs and input supply financing arrangements.',
    `is_intercompany` BOOLEAN COMMENT 'Indicates whether this advance payment is between two entities within the same agricultural enterprise group (intercompany transaction). Drives intercompany elimination in consolidated financial statements per IFRS 10 and GAAP ASC 810.',
    `issuing_entity_code` STRING COMMENT 'Code identifying the legal entity or company code within the agricultural enterprise that received the advance payment. Required for intercompany reconciliation, consolidated financial reporting, and multi-entity AR management.',
    `notes` STRING COMMENT 'Free-text field for additional business context, special instructions, or remarks related to the advance payment. May include buyer-specific terms, crop delivery conditions, or exception handling notes from the AR team.',
    `payment_method` STRING COMMENT 'Financial instrument or mechanism used by the agricultural buyer to remit the advance payment. Drives bank reconciliation workflows and treasury management. Common in commodity markets: wire transfers for large advance purchases, letters of credit for international grain contracts.. Valid values are `wire_transfer|ach|check|letter_of_credit|cash|electronic_funds_transfer`',
    `profit_center_code` STRING COMMENT 'SAP Controlling (CO) profit center code associated with the advance payment for internal management reporting and profitability analysis by business unit, crop type, or geographic region.',
    `receipt_date` DATE COMMENT 'The actual calendar date on which the advance payment funds were received and confirmed in the bank account. Used for cash flow reporting, interest calculations on advances, and GAAP/IFRS revenue recognition timing.',
    `refund_amount` DECIMAL(18,2) COMMENT 'Amount of the advance payment refunded to the agricultural buyer when the advance cannot be fully applied due to contract cancellation, crop failure, or delivery shortfall. Triggers AR credit memo and cash disbursement workflows.',
    `refund_date` DATE COMMENT 'Date on which the advance payment refund was issued to the agricultural buyer. Required for cash flow reporting, AR clearing, and buyer dispute resolution tracking.',
    `sales_order_reference` STRING COMMENT 'Sales Order (SO) number associated with the advance payment, linking the prepayment to a specific commodity sales order in SAP S/4HANA SD. Enables order-level advance tracking and delivery-based application scheduling.',
    `seasonal_program_code` STRING COMMENT 'Code identifying the specific seasonal advance payment program under which this prepayment was received (e.g., spring planting advance, fall harvest pre-purchase program). Agricultural commodity markets commonly operate structured seasonal advance programs tied to crop calendars.',
    `source_system` STRING COMMENT 'Operational system of record from which this advance payment record originated. Supports data lineage, reconciliation between systems, and audit trail requirements. Valid values: SAP_S4HANA (primary ERP), ORACLE_NETSUITE (secondary ERP), GRANULAR (farm management), MANUAL (manual entry).. Valid values are `SAP_S4HANA|ORACLE_NETSUITE|GRANULAR|MANUAL`',
    `unapplied_amount` DECIMAL(18,2) COMMENT 'Remaining balance of the advance payment not yet applied to any invoice. Calculated as advance_amount minus applied_amount. Represents the outstanding liability to the buyer until delivery or service completion.',
    `updated_timestamp` TIMESTAMP COMMENT 'Timestamp of the most recent update to the advance payment record. Supports change data capture (CDC) for the Databricks Silver Layer pipeline, audit trail requirements, and SOX financial controls.',
    `weight_ticket_reference` STRING COMMENT 'Reference to the weight ticket number associated with the commodity delivery that this advance payment will be applied against. Weight tickets are the primary measurement document in grain and commodity trading for quantity verification and invoice reconciliation.',
    CONSTRAINT pk_advance_payment PRIMARY KEY(`advance_payment_id`)
) COMMENT 'Records advance payments and prepayments received from agricultural buyers prior to commodity delivery or service completion. Captures advance payment number, customer reference, advance amount, currency, receipt date, purpose (crop pre-purchase, seed advance, input supply advance, storage deposit), linked contract reference, expected delivery date, application status (unapplied/partially_applied/fully_applied), and applied invoice references. Common in agricultural commodity markets where buyers secure supply through advance payment programs.';

CREATE OR REPLACE TABLE `agriculture_ecm`.`invoice`.`write_off` (
    `write_off_id` BIGINT COMMENT 'Unique system-generated identifier for the bad debt write-off transaction record in the accounts receivable (AR) ledger.',
    `account_id` BIGINT COMMENT 'Reference to the agricultural customer (e.g., food manufacturer, distributor, cooperative) whose AR balance is being written off. Primary party reference for the write-off transaction.',
    `invoice_id` BIGINT COMMENT 'Reference to the originating invoice record being written off. Links to the invoice.invoice product for full invoice detail and reconciliation.',
    `billing_account_id` BIGINT COMMENT 'Reference to the customer billing account against which the write-off is applied. Identifies the AR customer account in the general ledger.',
    `company_code_id` BIGINT COMMENT 'Foreign key linking to finance.company_code. Business justification: Write-offs are processed by a specific legal entity. In multi-entity agriculture operations, bad debt reporting by legal entity is required for statutory financial statements, tax deductibility analys',
    `journal_entry_id` BIGINT COMMENT 'Foreign key linking to finance.journal_entry. Business justification: Bad debt write-offs require GL postings (debit allowance for doubtful accounts, credit AR). In agriculture, write-offs for grain buyer defaults or input customer non-payment require specific GL entrie',
    `dispute_id` BIGINT COMMENT 'Foreign key linking to invoice.dispute. Business justification: write_off.dispute_case_reference is a denormalized string reference to the dispute record. Bad debt write-offs in agricultural AR frequently follow failed dispute resolution. Normalizing to invoice_di',
    `allowance_account_code` STRING COMMENT 'GL account code for the Allowance for Doubtful Accounts contra-asset account offset entry. Under the allowance method, the write-off reduces this account rather than directly expensing. Required for GAAP ASC 310-10 indirect write-off method.',
    `amount` DECIMAL(18,2) COMMENT 'Gross monetary amount of the accounts receivable balance being written off in the transaction currency. Represents the uncollectable AR balance removed from the books.',
    `amount_functional` DECIMAL(18,2) COMMENT 'Write-off amount converted to the companys functional (reporting) currency using the exchange rate at the time of write-off. Required for GAAP/IFRS financial statement reporting and GL posting.',
    `approval_authority` STRING COMMENT 'Name or role identifier of the individual or committee that authorized the write-off per the SOX-compliant delegation of authority matrix. Required for audit trail and internal controls documentation.',
    `approval_date` DATE COMMENT 'Date on which the write-off was formally approved by the designated approval authority. Distinct from the write-off posting date; required for SOX segregation of duties and approval workflow audit trail.',
    `approval_level` STRING COMMENT 'Hierarchical approval tier required and obtained for this write-off based on the amount threshold in the delegation of authority policy. Higher write-off amounts require escalation to senior financial officers per SOX controls.. Valid values are `manager|director|vp|cfo|board`',
    `collection_agency_reference` STRING COMMENT 'External collection agency case or account reference number when the debt was referred to a third-party collection agency prior to write-off. Supports recovery tracking and agency fee reconciliation.',
    `cost_center_code` STRING COMMENT 'SAP cost center code to which the bad debt expense is allocated for management accounting and OPEX reporting. Enables attribution of write-off costs to specific agricultural business units or regions.',
    `created_timestamp` TIMESTAMP COMMENT 'Timestamp when the write-off record was first created in the system. Provides the audit trail creation marker required for SOX-compliant financial record keeping.',
    `currency_code` STRING COMMENT 'ISO 4217 three-letter currency code for the transaction currency in which the write-off amount is denominated (e.g., USD, EUR, CAD). Supports multi-currency agricultural commodity trading operations.. Valid values are `^[A-Z]{3}$`',
    `customer_name` STRING COMMENT 'Legal name of the agricultural customer at the time of write-off. Captured as a denormalized field for audit trail integrity and historical reporting, as the customer record may change post-write-off.',
    `exchange_rate` DECIMAL(18,2) COMMENT 'Foreign currency exchange rate applied to convert the write-off transaction amount to the functional currency at the time of write-off posting. Required for multi-currency AR reconciliation.',
    `fiscal_period` STRING COMMENT 'Accounting fiscal period (YYYY-PP format) in which the write-off is recognized for financial reporting. Aligns with the agricultural companys fiscal calendar for period-end close and GAAP/IFRS reporting.. Valid values are `^[0-9]{4}-[0-9]{2}$`',
    `gl_account_code` STRING COMMENT 'GL account code to which the bad debt expense is posted (typically the Bad Debt Expense or Allowance for Doubtful Accounts account). Required for GAAP revenue accounting and financial statement preparation.',
    `gl_posting_date` DATE COMMENT 'Date on which the write-off journal entry was posted to the general ledger. Determines the accounting period for bad debt expense recognition per GAAP/IFRS period-end close requirements.',
    `invoice_reference_list` STRING COMMENT 'Comma-separated list of invoice numbers included in this write-off transaction when multiple invoices are consolidated into a single write-off event. Supports AR aging reconciliation and audit trail. For single-invoice write-offs, contains the single invoice number.',
    `is_tax_deductible` BOOLEAN COMMENT 'Indicates whether the write-off qualifies as a tax-deductible bad debt expense under applicable tax law. Drives tax provision calculations and deferred tax asset recognition.',
    `notes` STRING COMMENT 'Free-text field for additional operational notes, legal counsel comments, or credit committee observations related to the write-off decision. Supports comprehensive audit documentation for SOX compliance.',
    `original_invoice_amount` DECIMAL(18,2) COMMENT 'Total face value of the original invoice(s) at the time of issuance before any partial payments or credits. Enables calculation of partial write-off percentage and supports credit risk analytics.',
    `partial_payment_applied` DECIMAL(18,2) COMMENT 'Total payments previously received and applied against the invoice(s) prior to the write-off. The net uncollectable balance equals original_invoice_amount minus partial_payment_applied.',
    `profit_center_code` STRING COMMENT 'SAP profit center code for segment-level P&L reporting of bad debt expense. Supports EBITDA analysis by agricultural business segment (e.g., crop inputs, livestock, grain trading).',
    `reason` STRING COMMENT 'Categorized business reason for the bad debt write-off. Agriculture-specific reasons include crop_failure_hardship (customer unable to pay due to crop loss event) and dispute_settlement (negotiated resolution). Required for GAAP bad debt expense classification and management reporting. [ENUM-REF-CANDIDATE: bankruptcy|insolvency|crop_failure_hardship|dispute_settlement|statute_of_limitations|customer_deceased|other — promote to reference product]. Valid values are `bankruptcy|insolvency|crop_failure_hardship|dispute_settlement|statute_of_limitations|customer_deceased`',
    `reason_detail` STRING COMMENT 'Free-text narrative providing additional context for the write-off reason. For crop failure hardship cases, may include crop type, affected season, and loss event reference. Supports audit documentation and SOX compliance.',
    `recovered_amount` DECIMAL(18,2) COMMENT 'Total amount subsequently recovered from the customer after the write-off was posted. Populated when recovery_flag is True. Used to record bad debt recovery income and adjust net bad debt expense reporting.',
    `recovery_date` DATE COMMENT 'Date on which the recovered amount was received from the customer. Used for period-accurate bad debt recovery income recognition and cash flow reporting.',
    `recovery_flag` BOOLEAN COMMENT 'Indicates whether any subsequent recovery of the written-off amount has been initiated or received. When True, triggers monitoring of recovery transactions and potential reversal of bad debt expense per GAAP.',
    `reversal_date` DATE COMMENT 'Date on which the write-off was reversed in the general ledger. Populated only when reversal_flag is True. Determines the accounting period for the reversal entry.',
    `reversal_flag` BOOLEAN COMMENT 'Indicates whether this write-off has been reversed (e.g., due to subsequent full payment or erroneous posting). When True, the write-off_status should reflect reversed and a reversal document reference should be present.',
    `source_system` STRING COMMENT 'Operational system of record from which the write-off transaction originated. Supports data lineage tracking and reconciliation between ERP systems in multi-system agricultural enterprise environments.. Valid values are `SAP_S4HANA|ORACLE_NETSUITE|GRANULAR|MANUAL`',
    `tax_impact_amount` DECIMAL(18,2) COMMENT 'Estimated tax deduction or tax benefit amount associated with the bad debt write-off. Relevant for income tax reporting where bad debt deductions are allowable under applicable tax regulations.',
    `updated_timestamp` TIMESTAMP COMMENT 'Timestamp of the most recent modification to the write-off record. Tracks changes through the approval workflow and any post-posting amendments for SOX audit trail completeness.',
    `weight_ticket_reference` STRING COMMENT 'Weight ticket number associated with the commodity delivery underlying the written-off invoice. Supports weight-ticket-based AR reconciliation specific to grain elevator and commodity trading operations.',
    `write_off_date` DATE COMMENT 'The business event date on which the bad debt write-off was formally executed and recognized. Used for GAAP bad debt expense recognition in the correct accounting period.',
    `write_off_number` STRING COMMENT 'Externally visible, human-readable business identifier for the write-off transaction. Used in audit trails, SOX compliance documentation, and GL posting references. Format: WO-YYYY-NNNNNN.. Valid values are `^WO-[0-9]{4}-[0-9]{6}$`',
    `write_off_status` STRING COMMENT 'Current lifecycle state of the write-off transaction within the SOX-compliant approval and GL posting workflow. Tracks progression from initial submission through approval, GL posting, and any subsequent reversal.. Valid values are `pending_approval|approved|posted|reversed|cancelled`',
    CONSTRAINT pk_write_off PRIMARY KEY(`write_off_id`)
) COMMENT 'Records bad debt write-off transactions for uncollectable AR balances from agricultural customers. Captures write-off number, customer AR account reference, written-off invoice references, write-off amount, write-off date, write-off reason (bankruptcy, insolvency, crop failure hardship, dispute settlement, statute of limitations), approval authority, GL account reference, tax impact, and recovery tracking flag. Supports GAAP bad debt expense recognition and SOX-compliant write-off approval workflows.';

CREATE OR REPLACE TABLE `agriculture_ecm`.`invoice`.`settlement_statement` (
    `settlement_statement_id` BIGINT COMMENT 'Unique system-generated surrogate key identifying each settlement statement record in the lakehouse silver layer. Primary key for the settlement_statement data product.',
    `bank_account_id` BIGINT COMMENT 'Foreign key linking to finance.bank_account. Business justification: Producer settlement payments in agriculture are disbursed from specific company bank accounts. Cash management, bank reconciliation, and daily cash position reporting require linking each settlement d',
    `billing_account_id` BIGINT COMMENT 'Reference to the accounts receivable (AR) billing account associated with this settlement statement, linking to the financial account master.',
    `commodity_id` BIGINT COMMENT 'Foreign key linking to product.commodity. Business justification: Producer settlement statements in grain/ag are always commodity-specific — deductions for drying, storage, and handling are calculated per commodity. A commodity_id FK normalizes the denormalized comm',
    `commodity_lot_id` BIGINT COMMENT 'Foreign key linking to inventory.commodity_lot. Business justification: Producer settlement reconciliation: grain elevator settlement statements summarize payments for specific commodity lots delivered by a producer. Direct FK enables lot-level settlement audit, patronage',
    `company_code_id` BIGINT COMMENT 'Foreign key linking to finance.company_code. Business justification: Settlement statements are issued by a specific legal entity (grain elevator, cooperative). In multi-entity agriculture operations, producer settlement reporting by legal entity supports statutory repo',
    `contract_id` BIGINT COMMENT 'Reference to the underlying commodity purchase, marketing, or grain elevator contract governing the transactions summarized in this settlement statement.',
    `drought_index_id` BIGINT COMMENT 'Foreign key linking to weather.drought_index. Business justification: Drought index values drive storage, drying, and handling deduction calculations in producer settlement statements. Grain elevators and cooperatives reference drought conditions when computing net sett',
    `farm_unit_id` BIGINT COMMENT 'Foreign key linking to land.farm_unit. Business justification: Producer settlement statements in grain/commodity agriculture are issued per farm operation. Linking settlement_statement to farm_unit enables producer-level payment reconciliation, FSA farm number cr',
    `frost_alert_id` BIGINT COMMENT 'Foreign key linking to weather.frost_alert. Business justification: Frost events affecting crop quality and quantity directly impact producer settlement amounts — drying deductions, quality deductions, and quantity adjustments in settlement statements are driven by fr',
    `journal_entry_id` BIGINT COMMENT 'Foreign key linking to finance.journal_entry. Business justification: Producer settlement statements in agriculture (grain elevator paying farmers) generate GL postings for payables, deductions, and net settlement. Linking settlement_statement to its journal entry is es',
    `growing_season_id` BIGINT COMMENT 'Foreign key linking to crop.growing_season. Business justification: Producer settlement reconciliation: grain elevator settlement statements are issued per crop year/season, reconciling all deliveries, deductions, and payments for a producers season. This FK links th',
    `lease_id` BIGINT COMMENT 'Foreign key linking to land.lease. Business justification: Crop-share and flex-rent lease settlements require linking settlement statements to the underlying lease to calculate landlord/tenant payment splits, verify flex-rent trigger prices, and produce lease',
    `organic_compliance_record_id` BIGINT COMMENT 'Foreign key linking to compliance.organic_compliance_record. Business justification: Organic premium settlement validation: producer settlement statements in agriculture include organic price premiums that are only payable when organic compliance is verified. Linking to organic_compli',
    `payment_term_id` BIGINT COMMENT 'Foreign key linking to invoice.payment_term. Business justification: settlement_statement.payment_terms_code is a denormalized string reference to the payment_term reference table. Settlement statements issued to agricultural producers must reference the authoritative ',
    `practice_adoption_id` BIGINT COMMENT 'Foreign key linking to sustainability.practice_adoption. Business justification: Regenerative agriculture programs (Indigo Ag, Bayer Carbon, USDA RCPP) pay producers based on verified practice adoption. Settlement statements for these programs must reference the practice_adoption ',
    `precipitation_event_id` BIGINT COMMENT 'Foreign key linking to weather.precipitation_event. Business justification: Hail and storm events causing crop damage affect settlement statement deductions — damage_pct and dockage_pct adjustments in grain elevator settlements are justified by documented precipitation events',
    `storage_location_id` BIGINT COMMENT 'Foreign key linking to inventory.storage_location. Business justification: Grain elevator settlement: settlement statements are facility-specific documents; storage deductions (drying, handling, shrinkage) are calculated per storage location. Direct FK enables facility-level',
    `sustainability_certification_id` BIGINT COMMENT 'Foreign key linking to sustainability.sustainability_certification. Business justification: Producer settlement statements apply certification premiums (organic, Rainforest Alliance, ISCC) to commodity prices. Linking to the governing certification enables premium audit trails and supports c',
    `yield_record_id` BIGINT COMMENT 'Foreign key linking to crop.yield_record. Business justification: Grain settlement traceability: producer settlement statements settle payment for specific harvested loads. This FK links the settlement document to the yield record (production data including moisture',
    `created_timestamp` TIMESTAMP COMMENT 'The date and time when this settlement statement record was first created in the system, in ISO 8601 format with timezone offset. Supports audit trail and SOX financial reporting controls.',
    `credits_issued_amount` DECIMAL(18,2) COMMENT 'Total value of credit memos, price adjustments, quality deductions reversals, and other credits applied to the producers account during the settlement period.',
    `crop_year` STRING COMMENT 'The agricultural crop year (e.g., 2024-2025) to which this settlement statement applies. Critical for grain elevator settlements, cooperative patronage distributions, and crop-year-based commodity contracts. Follows USDA crop year conventions.. Valid values are `^[0-9]{4}-[0-9]{4}$`',
    `currency_code` STRING COMMENT 'ISO 4217 three-letter currency code for all monetary amounts on this settlement statement (e.g., USD for US Dollar). Required for multi-currency operations and IFRS compliance.. Valid values are `^[A-Z]{3}$`',
    `delivery_date` DATE COMMENT 'The date on which the settlement statement was actually delivered or transmitted to the producer. Used for compliance tracking with state grain dealer licensing requirements that mandate timely statement delivery.',
    `delivery_method` STRING COMMENT 'The channel through which the settlement statement was delivered to the producer. Email: electronic delivery; Postal Mail: physical mailing; EDI: electronic data interchange for cooperative/elevator systems; Portal: producer self-service web portal; Fax: facsimile transmission.. Valid values are `email|postal_mail|edi|portal|fax`',
    `dispute_flag` BOOLEAN COMMENT 'Indicates whether the producer has formally disputed any portion of this settlement statement. True: active dispute exists; False: no dispute. Triggers dispute resolution workflow in SAP S/4HANA FI-AR.',
    `dispute_reason` STRING COMMENT 'Free-text description of the reason provided by the producer for disputing the settlement statement, such as weight ticket discrepancy, incorrect grade, or unauthorized deduction. Populated only when dispute_flag is True.',
    `drying_deduction_amount` DECIMAL(18,2) COMMENT 'Total grain drying fees deducted from the producers settlement for moisture reduction services applied to delivered grain during the settlement period.',
    `due_date` DATE COMMENT 'The date by which the net settlement amount must be paid or remitted, calculated from the statement date and applicable payment terms. Critical for AR aging and dunning management.',
    `gl_posting_date` DATE COMMENT 'The date on which the settlement statement transactions were posted to the General Ledger (GL) for revenue recognition and financial reporting purposes. May differ from statement_date for period-end accruals.',
    `handling_deduction_amount` DECIMAL(18,2) COMMENT 'Total grain handling and elevation fees deducted from the producers settlement for receiving, conditioning, and loading-out services at the elevator during the settlement period.',
    `invoiced_amount` DECIMAL(18,2) COMMENT 'Total gross amount of all invoices and charges billed to the producer during the settlement period, before credits, deductions, or payments. Represents the sum of commodity purchases, services, and other charges.',
    `net_settlement_amount` DECIMAL(18,2) COMMENT 'The definitive net amount due to or from the producer after applying opening balance, invoiced amounts, credits, payments, and all deductions. Positive value indicates amount owed by producer; negative value indicates amount payable to producer.',
    `notes` STRING COMMENT 'Free-text field for additional remarks, special instructions, or explanatory comments related to this settlement statement, such as price adjustment rationale or seasonal payment arrangement details.',
    `opening_balance` DECIMAL(18,2) COMMENT 'The accounts receivable (AR) balance carried forward from the prior settlement period for this producer or account. Represents the starting point for the current period reconciliation.',
    `other_deductions_amount` DECIMAL(18,2) COMMENT 'Total of all other miscellaneous deductions applied during the settlement period not captured in storage, drying, or handling categories, such as checkoff assessments, inspection fees, or loan repayments.',
    `patronage_dividend_amount` DECIMAL(18,2) COMMENT 'The cooperative patronage dividend or equity distribution allocated to the producer-member for the settlement period, based on their proportional volume of business with the cooperative. Applicable only for cooperative settlement types.',
    `payments_received_amount` DECIMAL(18,2) COMMENT 'Total cash payments, ACH transfers, wire transfers, and check payments received from or applied to the producers account during the settlement period.',
    `period_end_date` DATE COMMENT 'The last calendar date of the billing/settlement period covered by this statement. Together with period_start_date, defines the date range of all transactions summarized herein.',
    `period_start_date` DATE COMMENT 'The first calendar date of the billing/settlement period covered by this statement. Together with period_end_date, defines the date range of all transactions summarized herein.',
    `period_type` STRING COMMENT 'Classification of the settlement cycle frequency. Daily: grain elevator daily settlements; Weekly: livestock auction settlements; Monthly: standard AR billing; Seasonal: harvest-season settlements; Crop Year: annual cooperative patronage distributions.. Valid values are `daily|weekly|monthly|seasonal|crop_year`',
    `producer_account_number` STRING COMMENT 'The externally-known account or member number assigned to the producer or cooperative member, as printed on the settlement statement. Used for producer self-service reconciliation and grain elevator licensing compliance.',
    `producer_name` STRING COMMENT 'Legal name of the agricultural producer, cooperative, grain elevator, or commodity buyer as it appears on the settlement statement. Retained on the statement for document integrity and regulatory compliance.',
    `quantity_uom` STRING COMMENT 'Unit of measure for the total_quantity field. BU: Bushel; CWT: Hundredweight; MT: Metric Ton; LB: Pound; TON: Short Ton; HEAD: individual livestock count. Aligns with USDA commodity reporting standards.. Valid values are `BU|CWT|MT|LB|TON|HEAD`',
    `revenue_recognition_date` DATE COMMENT 'The date on which revenue associated with this settlement statement is recognized per GAAP ASC 606 or IFRS 15 five-step model. May differ from statement_date for multi-period commodity contracts.',
    `settlement_type` STRING COMMENT 'Classification of the agricultural settlement scenario. Grain Elevator: grain storage and marketing settlements per state grain dealer licensing; Livestock Auction: proceeds from livestock sales; Cooperative Patronage: annual patronage dividend distributions; Commodity Purchase: direct commodity buyer settlements; Custom Farming: contract farming service settlements. [ENUM-REF-CANDIDATE: grain_elevator|livestock_auction|cooperative_patronage|commodity_purchase|custom_farming — promote to reference product]. Valid values are `grain_elevator|livestock_auction|cooperative_patronage|commodity_purchase|custom_farming`',
    `source_system` STRING COMMENT 'Identifier of the operational system of record from which this settlement statement originated. SAP_S4HANA: SAP S/4HANA FI-AR module; GRANULAR: Granular Farm Management; ORACLE_NETSUITE: Oracle NetSuite AR; FMIS: Farm Management Information System; MANUAL: manually created.. Valid values are `SAP_S4HANA|GRANULAR|ORACLE_NETSUITE|FMIS|MANUAL`',
    `statement_date` DATE COMMENT 'The official business date on which the settlement statement was generated and issued to the producer or counterparty. This is the principal real-world event date for the settlement document.',
    `statement_number` STRING COMMENT 'Externally visible, human-readable unique identifier for the settlement statement as printed on the document and referenced in producer communications. Follows the format SS-YYYY-NNNNNN.. Valid values are `^SS-[0-9]{4}-[0-9]{6}$`',
    `statement_status` STRING COMMENT 'Current lifecycle state of the settlement statement. Draft: in preparation; Issued: sent to producer; Disputed: producer has raised a discrepancy; Settled: fully paid and reconciled; Cancelled/Void: reversed or invalidated.. Valid values are `draft|issued|disputed|settled|cancelled|void`',
    `storage_deduction_amount` DECIMAL(18,2) COMMENT 'Total grain storage fees deducted from the producers settlement for commodity storage at the elevator or warehouse facility during the settlement period. A key deduction category in grain elevator settlements.',
    `total_quantity` DECIMAL(18,2) COMMENT 'Total quantity of commodity or product covered by this settlement statement, expressed in the unit of measure specified in quantity_uom. Supports weight-ticket reconciliation and bushel/metric ton settlement calculations.',
    `updated_timestamp` TIMESTAMP COMMENT 'The date and time when this settlement statement record was last modified in the system, in ISO 8601 format with timezone offset. Tracks revisions, dispute updates, and status changes for audit compliance.',
    CONSTRAINT pk_settlement_statement PRIMARY KEY(`settlement_statement_id`)
) COMMENT 'Periodic settlement statements issued to agricultural producers, cooperatives, grain elevators, and commodity buyers summarizing all billing transactions within a settlement period. Captures statement number, period type (daily/weekly/monthly/seasonal/crop-year), customer/producer reference, opening balance, invoiced amount, credits issued, payments received, deductions (storage, drying, handling fees), net settlement amount, statement date, and delivery method. Serves as the definitive reconciliation document for grain elevator settlements (per state grain dealer licensing requirements), livestock auction settlements, and cooperative patronage distributions.';

CREATE OR REPLACE TABLE `agriculture_ecm`.`invoice`.`price_adjustment` (
    `price_adjustment_id` BIGINT COMMENT 'Unique system-generated identifier for each price adjustment record in the invoice domain. Serves as the primary key for the price_adjustment data product.',
    `account_id` BIGINT COMMENT 'Identifier of the customer (grain elevator, food manufacturer, commodity buyer) to whom the price adjustment applies. Used for AR aging, customer account reconciliation, and credit management.',
    `animal_transaction_id` BIGINT COMMENT 'Foreign key linking to livestock.animal_transaction. Business justification: Livestock price adjustments (grade discounts, weight shrink corrections, quality premiums) are issued against specific sale transactions. Linking price_adjustment to animal_transaction enables traceab',
    `invoice_id` BIGINT COMMENT 'Reference to the originating accounts receivable invoice against which this price adjustment is applied. Links the adjustment to the provisional invoice issued pending final commodity pricing.',
    `billing_account_id` BIGINT COMMENT 'Foreign key linking to invoice.billing_account. Business justification: Price adjustments affect AR balances for agricultural customers and must be linked to the billing_account AR master for account-level adjustment tracking and AR balance reconciliation. price_adjustmen',
    `certificate_of_analysis_id` BIGINT COMMENT 'Foreign key linking to quality.certificate_of_analysis. Business justification: Price adjustments in commodity grain trading are directly driven by COA test results (moisture, protein, dockage, mycotoxin). A FK from price_adjustment to coa_id enables direct quality-test-to-price-',
    `cold_chain_reading_id` BIGINT COMMENT 'Foreign key linking to supply.cold_chain_reading. Business justification: In ag cold chain (produce, dairy, frozen), temperature excursions documented in cold_chain_reading directly trigger contractual price adjustments or deductions. Linking price_adjustment to cold_chain_',
    `commodity_id` BIGINT COMMENT 'Foreign key linking to product.commodity. Business justification: Price adjustments for moisture, dockage, and grade are commodity-specific operations in ag settlement. A commodity_id FK normalizes the denormalized commodity_code and commodity_description, supportin',
    `commodity_lot_id` BIGINT COMMENT 'Foreign key linking to inventory.commodity_lot. Business justification: Quality-based price adjustment traceability: grain price adjustments for moisture, dockage, grade, and MRL factors are tied to specific commodity lots. Direct FK enables audit trail from financial adj',
    `price_basis_id` BIGINT COMMENT 'Foreign key linking to invoice.price_basis. Business justification: price_adjustment.pricing_basis is a denormalized string reference to the price_basis reference table. Price adjustments in commodity billing are driven by specific pricing bases (futures + basis). Nor',
    `contract_id` BIGINT COMMENT 'Reference to the underlying commodity purchase or sales contract that governs the pricing terms being adjusted. Supports basis adjustment, futures price settlement, and contract price true-up scenarios.',
    `frost_alert_id` BIGINT COMMENT 'Foreign key linking to weather.frost_alert. Business justification: Frost events directly trigger contractual price adjustments for damaged commodity in ag sales contracts. Traceability from price_adjustment to the triggering frost_alert is required for dispute resolu',
    `journal_entry_id` BIGINT COMMENT 'Foreign key linking to finance.journal_entry. Business justification: Price adjustments for basis changes, moisture dockage, and grade adjustments in agriculture generate GL postings. Linking price_adjustment to its journal entry supports audit trail for commodity price',
    `grading_standard_id` BIGINT COMMENT 'Foreign key linking to product.grading_standard. Business justification: Price adjustments in ag are frequently triggered by grade reclassification — linking to grading_standard_id provides a formal audit trail for grade-based price corrections, supports dispute resolution',
    `inventory_goods_receipt_id` BIGINT COMMENT 'Foreign key linking to inventory.goods_receipt. Business justification: Quality determination at receipt triggers price adjustment: moisture, test weight, and grade are determined at goods receipt and drive price adjustments. Direct FK enables traceability from financial ',
    `line_id` BIGINT COMMENT 'Foreign key linking to invoice.invoice_line. Business justification: Price adjustments in agricultural billing are applied at the commodity line level (e.g., moisture adjustment, grade reclassification). price_adjustment already has ar_invoice_id -> invoice (header lev',
    `lot_trace_id` BIGINT COMMENT 'Foreign key linking to supply.lot_trace. Business justification: Ag price adjustments for moisture, dockage, grade, and quality factors are applied at the lot level. Linking price_adjustment to lot_trace enables lot-level quality deduction tracking, supports FSMA-c',
    `nonconformance_id` BIGINT COMMENT 'Foreign key linking to quality.nonconformance. Business justification: Price adjustments triggered by nonconformances (MRL exceedance, pesticide residue, grade failure) are a standard agriculture billing process. A FK from price_adjustment to nonconformance_id enables qu',
    `precipitation_event_id` BIGINT COMMENT 'Foreign key linking to weather.precipitation_event. Business justification: Hail and storm events cause commodity quality degradation (elevated moisture, dockage, damage pct), triggering price adjustments on delivery invoices. Linking precipitation_event to price_adjustment e',
    `regulatory_finding_id` BIGINT COMMENT 'Foreign key linking to compliance.regulatory_finding. Business justification: Regulatory-finding-driven price adjustment: MRL exceedances, grade downgrades from inspection findings, and pesticide violations directly trigger price adjustments in agriculture commodity trading. pr',
    `variety_id` BIGINT COMMENT 'Foreign key linking to research.variety. Business justification: Variety-based price adjustments are standard in agriculture: IP-protected or certified varieties trigger specific premium/discount adjustments when trait expression or quality deviates from specs. Lin',
    `sustainability_certification_id` BIGINT COMMENT 'Foreign key linking to sustainability.sustainability_certification. Business justification: Price adjustments triggered by certification status changes (organic decertification, suspended certification) require direct reference to the certification record for audit compliance and price rollb',
    `test_result_id` BIGINT COMMENT 'Foreign key linking to quality.test_result. Business justification: Individual test results (moisture %, protein %, mycotoxin ppb) directly calculate price adjustments in commodity grain settlement. price_adjustment.quality_factor_code is a denormalized text reference',
    `weight_ticket_id` BIGINT COMMENT 'Reference to the weight ticket record used for final weight reconciliation adjustments. Applicable when the adjustment is triggered by a moisture dockage correction or net weight discrepancy between provisional and final scale readings.',
    `yield_record_id` BIGINT COMMENT 'Foreign key linking to crop.yield_record. Business justification: Quality-based price adjustment traceability: when grain is re-tested post-delivery and moisture, dockage, or grade differs from invoice, a price adjustment is issued. This FK links the adjustment to t',
    `adjusted_unit_price` DECIMAL(18,2) COMMENT 'The final settled unit price per unit of measure after applying the price adjustment. Reflects final commodity pricing, quality re-grading outcome, or contract true-up result.',
    `adjustment_amount` DECIMAL(18,2) COMMENT 'Net monetary value of the price adjustment (positive for increases, negative for decreases). Calculated as (adjusted_unit_price - original_unit_price) × quantity_affected. Drives AR debit or credit memo issuance and revenue recognition true-up.',
    `adjustment_direction` STRING COMMENT 'Indicates whether the adjustment increases or decreases the original invoice amount. Drives debit memo vs. credit memo issuance and AR balance impact.. Valid values are `increase|decrease`',
    `adjustment_number` STRING COMMENT 'Externally visible, human-readable business identifier for the price adjustment document. Used in customer communications, remittance advice, and audit trails. Format: PA-YYYY-NNNNNN.. Valid values are `^PA-[0-9]{4}-[0-9]{6}$`',
    `adjustment_status` STRING COMMENT 'Current lifecycle state of the price adjustment record. Controls workflow progression from initial creation through approval, GL posting, and potential reversal. [ENUM-REF-CANDIDATE: draft|pending_approval|approved|posted|reversed|cancelled — promote to reference product]. Valid values are `draft|pending_approval|approved|posted|reversed|cancelled`',
    `adjustment_type` STRING COMMENT 'Classification of the business reason driving the price adjustment. Determines the accounting treatment and GL account mapping. [ENUM-REF-CANDIDATE: final_price_true_up|quality_premium|quality_discount|moisture_dockage|futures_settlement|basis_adjustment|freight_differential — promote to reference product]',
    `approval_date` DATE COMMENT 'Date on which the price adjustment was formally approved by the authorized approver. Used for audit trail, SLA monitoring, and period-end close management.',
    `approval_status` STRING COMMENT 'Current state of the price adjustment in the internal approval workflow. Price adjustments above a materiality threshold require multi-level authorization before GL posting per SOX internal controls.. Valid values are `pending|approved|rejected|escalated`',
    `approved_by` STRING COMMENT 'Name or user ID of the authorized approver who approved the price adjustment for GL posting. Required for SOX audit trail and internal control documentation.',
    `basis_amount` DECIMAL(18,2) COMMENT 'The basis differential (in cents per bushel or dollars per metric ton) representing the difference between the local cash price and the relevant futures contract price. Used in basis adjustment and futures settlement price adjustment types.',
    `created_timestamp` TIMESTAMP COMMENT 'System timestamp recording when the price adjustment record was first created in the data platform. Used for audit trail, data lineage, and period-end close monitoring.',
    `currency_code` STRING COMMENT 'ISO 4217 three-letter currency code for all monetary amounts on this adjustment record (e.g., USD for US Dollar). Supports multi-currency operations for international commodity trading.. Valid values are `^[A-Z]{3}$`',
    `dockage_pct` DECIMAL(18,2) COMMENT 'Percentage deduction applied to gross weight for foreign material, weed seeds, or other non-grain matter. Used in moisture dockage correction adjustments to reconcile provisional vs. final net weight and settlement amount.',
    `effective_date` DATE COMMENT 'The business date on which the price adjustment becomes effective for pricing and settlement purposes. For futures price settlements, this aligns with the contract delivery period or pricing date specified in the commodity contract.',
    `exchange_rate` DECIMAL(18,2) COMMENT 'Foreign exchange rate applied to convert the adjustment amount from the transaction currency to the functional (reporting) currency at the time of posting. Relevant for cross-border commodity sales.',
    `functional_currency_amount` DECIMAL(18,2) COMMENT 'Adjustment amount expressed in the entitys functional (reporting) currency after applying the exchange rate. Used for consolidated financial reporting under GAAP/IFRS.',
    `futures_contract_month` STRING COMMENT 'The CBOT/CME futures contract delivery month code used as the pricing reference for basis or futures-plus-basis adjustments (e.g., Z24 for December 2024 corn). Applicable when pricing_basis is futures_plus_basis or basis.. Valid values are `^[A-Z]{1}[0-9]{2}$`',
    `gl_account_code` STRING COMMENT 'GL account to which the price adjustment amount is posted for revenue recognition true-up or contra-revenue recording. Mapped based on adjustment_type and commodity classification per the chart of accounts.',
    `gl_posting_date` DATE COMMENT 'The accounting date on which the price adjustment is posted to the General Ledger. Determines the fiscal period for revenue recognition true-up and AR balance adjustment. May differ from effective_date for period-end accruals.',
    `moisture_pct` DECIMAL(18,2) COMMENT 'Final measured moisture content (%) of the commodity used to calculate moisture dockage corrections. Deviations from standard moisture (e.g., 15.5% for corn) trigger dockage adjustments that reduce the net settlement weight and price.',
    `notes` STRING COMMENT 'Free-text field for additional context, business justification, or operational notes related to the price adjustment. May include market conditions, counterparty communications, or inspector remarks supporting the adjustment.',
    `original_unit_price` DECIMAL(18,2) COMMENT 'The provisional unit price per unit of measure (e.g., per bushel, per metric ton, per hundredweight) stated on the originating invoice before any adjustment. Basis for calculating the adjustment delta.',
    `price_unit_of_measure` STRING COMMENT 'Unit of measure against which the original and adjusted unit prices are expressed. Common agricultural units include BU (Bushel), CWT (Hundredweight), MT (Metric Ton), LB (Pound), KG (Kilogram), TON (Short Ton).. Valid values are `BU|CWT|MT|LB|KG|TON`',
    `profit_center_code` STRING COMMENT 'SAP profit center to which the price adjustment is attributed for internal management reporting and profitability analysis by business unit or commodity trading desk.',
    `purchase_order_number` STRING COMMENT 'Customer or counterparty purchase order number associated with the original commodity transaction. Included on adjustment documents for customer reconciliation and three-way matching in accounts payable.',
    `quality_factor_code` STRING COMMENT 'Specific quality attribute code (e.g., test weight, heat damage, total damage, broken kernels, foreign material) that triggered a quality premium or discount adjustment. Aligns with USDA GIPSA grading factor codes.',
    `quantity_affected` DECIMAL(18,2) COMMENT 'The quantity of commodity (expressed in price_unit_of_measure) subject to the price adjustment. Used to calculate the total adjustment amount as (adjusted_unit_price - original_unit_price) × quantity_affected.',
    `reversal_reference` STRING COMMENT 'Adjustment number of the reversing price adjustment document if this record has been reversed. Populated when adjustment_status is reversed. Supports audit trail and double-entry accounting integrity.',
    `source_system_code` STRING COMMENT 'Identifier of the operational system of record from which this price adjustment record originated. Supports data lineage, reconciliation, and audit traceability across integrated systems.. Valid values are `SAP_SD|SAP_FI|NETSUITE|GRANULAR|FIELDVIEW|MANUAL`',
    `updated_timestamp` TIMESTAMP COMMENT 'System timestamp recording the most recent modification to the price adjustment record. Supports change data capture (CDC) in the Databricks Silver Layer and audit trail requirements.',
    CONSTRAINT pk_price_adjustment PRIMARY KEY(`price_adjustment_id`)
) COMMENT 'Records post-invoice price adjustments applied to commodity billing due to market price changes, quality re-grading, final weight reconciliation, or contract price true-up events. Captures adjustment number, originating invoice reference, adjustment type (final price true-up, quality premium/discount, moisture dockage correction, futures price settlement, basis adjustment, freight differential), original unit price, adjusted unit price, quantity affected, adjustment amount, effective date, and approval status. Common in grain and oilseed billing where provisional invoices are issued pending final commodity pricing.';

CREATE OR REPLACE TABLE `agriculture_ecm`.`invoice`.`receivable_financing` (
    `receivable_financing_id` BIGINT COMMENT 'Unique system-generated identifier for each receivable financing transaction record. Primary key for the receivable_financing data product.',
    `account_id` BIGINT COMMENT 'Identifier of the customer (obligor) whose invoices are being financed. The customer is the party obligated to pay the underlying receivables being sold or pledged to the financing institution.',
    `financing_arrangement_id` BIGINT COMMENT 'Reference to the master financing facility or framework agreement under which this individual transaction is executed. Multiple financing transactions may be grouped under a single arrangement (e.g., a revolving factoring facility).',
    `bank_account_id` BIGINT COMMENT 'Foreign key linking to finance.bank_account. Business justification: Factoring proceeds from AR financing in agriculture are deposited into specific bank accounts. Treasury management and bank reconciliation require linking each factoring disbursement to the receiving ',
    `billing_account_id` BIGINT COMMENT 'Reference to the accounts receivable (AR) billing account whose invoices are being financed. Links to the billing_account product in the invoice domain.',
    `commodity_id` BIGINT COMMENT 'Foreign key linking to product.commodity. Business justification: Receivable financing (factoring) in ag is commodity-specific — financing institutions assess credit risk by commodity type, crop year, and market volatility. A commodity_id FK normalizes the denormali',
    `company_code_id` BIGINT COMMENT 'Foreign key linking to finance.company_code. Business justification: Receivable financing arrangements are entered into by a specific legal entity. In multi-entity agriculture operations, AR derecognition accounting, financial statement disclosure of transferred receiv',
    `contract_id` BIGINT COMMENT 'Reference to the underlying sales or commodity purchase contract whose invoices are being financed. Links the financing transaction to the originating commercial agreement for traceability and audit purposes.',
    `journal_entry_id` BIGINT COMMENT 'Foreign key linking to finance.journal_entry. Business justification: AR factoring and receivable financing in agriculture generate GL entries for derecognition of receivables (ASC 860). Linking receivable_financing to its journal entry supports audit trail for derecogn',
    `growing_season_id` BIGINT COMMENT 'Foreign key linking to crop.growing_season. Business justification: Crop receivable factoring: grain receivable financing arrangements are structured around a specific crop years production and deliveries. This FK links the financing facility to the growing season, e',
    `parent_receivable_financing_id` BIGINT COMMENT 'Self-referencing FK on receivable_financing (parent_receivable_financing_id)',
    `advance_amount` DECIMAL(18,2) COMMENT 'Actual cash amount disbursed by the financing institution to the agricultural enterprise at the time of financing. Calculated as total_invoice_face_amount multiplied by advance_rate_pct, net of any upfront fees. Critical for cash flow management during harvest-to-payment seasonal gaps.',
    `advance_rate_pct` DECIMAL(18,2) COMMENT 'The percentage of the total invoice face amount that the financing institution advances to the agricultural enterprise at disbursement. Expressed as a decimal (e.g., 0.8500 = 85%). The remaining percentage is held as a reserve until customer payment is received.',
    `cost_center_code` STRING COMMENT 'Cost center to which the factoring fee and financing costs are allocated for internal management accounting. Enables tracking of receivable financing costs by business unit or agricultural division in SAP CO.',
    `created_timestamp` TIMESTAMP COMMENT 'Timestamp when this receivable financing record was first created in the system. Supports audit trail requirements under SOX Section 404 and GAAP financial reporting controls.',
    `crop_year` STRING COMMENT 'Agricultural crop year associated with the underlying invoices being financed (e.g., 2024 or 2024-2025 for split-year crops). Enables seasonal cash flow analysis and correlation of financing activity with harvest cycles. Particularly relevant for grain and oilseed commodity trading.. Valid values are `^[0-9]{4}(-[0-9]{4})?$`',
    `currency_code` STRING COMMENT 'ISO 4217 three-letter currency code for all monetary amounts in this financing transaction (e.g., USD, EUR, CAD). Agricultural commodity transactions are predominantly USD-denominated but may involve other currencies for international grain trade.. Valid values are `^[A-Z]{3}$`',
    `dilution_amount` DECIMAL(18,2) COMMENT 'Total value of credits, returns, disputes, or adjustments that reduce the collectible value of the financed receivables pool below the original face amount. Dilution is a key risk metric monitored by financing institutions and affects reserve calculations. Common in agricultural trade due to quality disputes and weight-ticket adjustments.',
    `disbursement_date` DATE COMMENT 'Date on which the financing institution transferred the advance amount to the agricultural enterprise. Represents the principal business event date for this financing transaction. Critical for cash flow reporting and seasonal liquidity management during post-harvest periods.',
    `exchange_rate` DECIMAL(18,2) COMMENT 'Foreign exchange rate used to convert transaction amounts to the functional currency at the time of disbursement. Applicable when the financing currency differs from the enterprise functional currency. Sourced from SAP FI or Oracle NetSuite exchange rate tables.',
    `factored_invoice_count` STRING COMMENT 'Number of individual AR invoices included in this financing transaction. Supports reconciliation between the financing batch and the underlying invoice pool, particularly relevant for agricultural commodity trading where multiple weight-ticket-backed invoices may be bundled.',
    `factoring_fee_amount` DECIMAL(18,2) COMMENT 'Total fee charged by the financing institution for the receivable financing service. Includes service fees, discount charges, and any other financing costs. Recognized as a financing cost in the income statement per GAAP ASC 860 and IFRS 9.',
    `factoring_fee_rate_pct` DECIMAL(18,2) COMMENT 'The fee rate applied to the total invoice face amount to calculate the factoring fee. Expressed as a decimal (e.g., 0.015000 = 1.5%). May be a flat rate or tiered based on invoice age, customer credit quality, or commodity type.',
    `financing_institution_code` STRING COMMENT 'Internal or industry-standard code identifying the financing institution. Used for system integration, GL posting, and counterparty reporting. May correspond to a bank identifier code (BIC/SWIFT) or internal vendor code in SAP FI.',
    `financing_institution_name` STRING COMMENT 'Legal name of the financial institution (bank, factor, or special purpose vehicle) to which the receivables are sold or pledged. Critical for counterparty risk management and financial statement disclosure under GAAP ASC 860 derecognition assessment.',
    `financing_reference_number` STRING COMMENT 'Externally-known unique reference number assigned to the receivable financing arrangement, used for communication with the financing institution and internal tracking. Corresponds to the facility or transaction reference in SAP FI or Oracle NetSuite AR modules.',
    `financing_status` STRING COMMENT 'Current lifecycle status of the receivable financing transaction, tracking progression from initiation through settlement. Values: draft (being prepared), submitted (sent to institution), approved (institution confirmed), active (funds disbursed), settled (fully reconciled), cancelled (voided).. Valid values are `draft|submitted|approved|active|settled|cancelled`',
    `financing_type` STRING COMMENT 'Classification of the receivable financing arrangement. Factoring involves outright sale of AR; invoice discounting retains collection responsibility; supply chain finance is buyer-led; asset-backed lending pledges AR as collateral; forfaiting is used for medium-term trade receivables. Common in agricultural commodity trading for seasonal cash flow management.. Valid values are `factoring|invoice_discounting|supply_chain_finance|asset_backed_lending|forfaiting`',
    `gl_account_code` STRING COMMENT 'General ledger account code used to post the receivable financing transaction in the enterprise accounting system. Typically maps to a factored receivables or short-term financing liability account per the chart of accounts in SAP S/4HANA FI or Oracle NetSuite GL.',
    `gl_posting_date` DATE COMMENT 'Date on which the receivable financing transaction is posted to the general ledger. May differ from disbursement_date due to period-end cut-off requirements. Critical for accurate period-end financial reporting and SOX compliance.',
    `is_derecognized` BOOLEAN COMMENT 'Indicates whether the financed receivables have been removed from the agricultural enterprise balance sheet per GAAP ASC 860 or IFRS 9 derecognition criteria. True = receivables derecognized (off-balance-sheet); False = receivables remain on balance sheet (secured borrowing treatment).',
    `maturity_date` DATE COMMENT 'Date by which the underlying customer invoices are expected to be paid and the financing arrangement is expected to be fully settled. Used for aging analysis, liquidity forecasting, and monitoring of overdue financing positions.',
    `notes` STRING COMMENT 'Free-text field for additional context, special conditions, or operational notes related to the receivable financing transaction. May include details about seasonal payment terms, commodity-specific conditions, or financing institution special requirements.',
    `notification_sent_flag` BOOLEAN COMMENT 'Indicates whether the customer (invoice obligor) has been formally notified of the assignment or sale of their receivable to the financing institution. Notification is legally required in many jurisdictions for the assignment to be enforceable against the debtor. True = notification sent; False = not yet notified.',
    `profit_center_code` STRING COMMENT 'Profit center associated with the receivable financing transaction for segment reporting and profitability analysis. Enables attribution of financing costs to specific commodity trading or agricultural business segments.',
    `recourse_limit_amount` DECIMAL(18,2) COMMENT 'Maximum monetary exposure retained by the agricultural enterprise under a partial recourse arrangement. Null for full recourse or without recourse transactions. Used for contingent liability disclosure in financial statements per GAAP ASC 460.',
    `recourse_type` STRING COMMENT 'Defines the credit risk allocation between the agricultural enterprise and the financing institution. Full recourse: enterprise bears all credit risk; partial recourse: shared risk up to a defined limit; without recourse: financing institution assumes all credit risk. Determines whether the receivable qualifies for derecognition under GAAP ASC 860 and IFRS 9.. Valid values are `full_recourse|partial_recourse|without_recourse`',
    `reserve_amount` DECIMAL(18,2) COMMENT 'Amount withheld by the financing institution as a reserve against potential dilution, disputes, or credit losses. Released to the agricultural enterprise upon confirmed customer payment. Equals total_invoice_face_amount minus advance_amount minus factoring_fee_amount.',
    `reserve_released_amount` DECIMAL(18,2) COMMENT 'Amount of the withheld reserve that has been remitted back to the agricultural enterprise following confirmed customer payment collection by the financing institution. Supports reconciliation of the total financing cycle.',
    `settlement_date` DATE COMMENT 'Actual date on which the financing arrangement was fully settled, including remittance of reserve amounts and reconciliation of all fees. May differ from maturity_date if customers pay early or late. Null if not yet settled.',
    `settlement_status` STRING COMMENT 'Current status of the settlement process for this financing transaction. Tracks whether the financing institution has remitted reserve amounts back to the enterprise following customer payment collection. Overdue indicates maturity_date has passed without full settlement.. Valid values are `pending|partial|complete|overdue|disputed`',
    `source_system` STRING COMMENT 'Operational system of record from which this receivable financing record originated. Supports data lineage, reconciliation, and audit trail requirements. SAP S/4HANA FI and Oracle NetSuite are the primary source systems for AR financing transactions.. Valid values are `SAP_S4HANA|ORACLE_NETSUITE|GRANULAR|MANUAL`',
    `total_invoice_face_amount` DECIMAL(18,2) COMMENT 'Aggregate face value of all AR invoices included in this financing transaction before any advance rate, fees, or deductions. Represents the gross receivables pool being financed. Used for GAAP ASC 860 derecognition and IFRS 9 impairment calculations.',
    `updated_timestamp` TIMESTAMP COMMENT 'Timestamp of the most recent update to this receivable financing record. Supports change tracking, audit trail, and data lineage requirements for financial reporting controls.',
    CONSTRAINT pk_receivable_financing PRIMARY KEY(`receivable_financing_id`)
) COMMENT 'Tracks receivables financing, factoring, and assignment transactions where the agricultural enterprise sells or pledges AR invoices to financial institutions for early cash conversion. Captures financing arrangement reference, factored invoice references, advance rate, factoring fee, recourse type (with/without recourse), financing institution, disbursement date, maturity date, and settlement status. Common in agricultural commodity trading where seasonal cash flow gaps require receivables monetization between harvest delivery and customer payment.';

